-- Poems batch 466
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-121','送僧','賈島','唐','御定全唐诗','yuding','','[]','此生披衲過，在世得身閑。日午遊都市，天寒往華山。',48,'御定全唐詩/json/573.json','["此生披衲過，在世得身閑。日午遊都市，天寒往華山。", "言歸文字外，意出有無間。仙掌雲邊樹，巢禽時出關。"]'),
('yuding-122','寄魏少府','賈島','唐','御定全唐诗','yuding','','[]','來時乖面別，終日使人慚。易記卷中句，難忘燈下談。',48,'御定全唐詩/json/573.json','["來時乖面別，終日使人慚。易記卷中句，難忘燈下談。", "濕苔粘樹癭，瀑布濺房庵。音信如相惠，移居古井南。"]'),
('yuding-123','原居即事言懷贈孫員外','賈島','唐','御定全唐诗','yuding','','[]','出入土門偏，秋深石色泉。徑通原上草，地接水中蓮。',72,'御定全唐詩/json/573.json','["出入土門偏，秋深石色泉。徑通原上草，地接水中蓮。", "采菌依餘枿，拾薪逢刈田。鑷撏白髮斷，兵阻尺書傳。", "避路來華省，抄詩上彩箋。高齋久不到，猶喜未經年。"]'),
('yuding-124','登樓','賈島','唐','御定全唐诗','yuding','','[]','秋日登高望，涼風吹海初。山川明已久，河漢沒無餘。',48,'御定全唐詩/json/573.json','["秋日登高望，涼風吹海初。山川明已久，河漢沒無餘。", "遠近涯寥夐，高低中太虛。賦因王閣筆，思比謝遊疏。"]'),
('yuding-125','上樂使君救康成公','賈島','唐','御定全唐诗','yuding','','[]','曾夢諸侯笑，康囚議脫枷。千根池裏藕，一朵火中花。',24,'御定全唐詩/json/573.json','["曾夢諸侯笑，康囚議脫枷。千根池裏藕，一朵火中花。"]'),
('yuding-126','昆明池泛舟','賈島','唐','御定全唐诗','yuding','','[]','一枝青竹榜，泛泛綠萍裏。不見釣魚人，漸入秋塘水。',24,'御定全唐詩/json/573.json','["一枝青竹榜，泛泛綠萍裏。不見釣魚人，漸入秋塘水。"]'),
('yuding-127','送僧','賈島','唐','御定全唐诗','yuding','','[]','大內曾持論，天南化俗行。舊房山雪在，春草岳陽生。',48,'御定全唐詩/json/573.json','["大內曾持論，天南化俗行。舊房山雪在，春草岳陽生。", "曉了蓮經義，堪任寶蓋迎。王侯皆護法，何寺講鐘鳴。"]'),
('yuding-128','送劉知新往襄陽','賈島','唐','御定全唐诗','yuding','','[]','此別誠堪恨，荊襄是舊遊。眼光懸欲落，心緒亂難收。',48,'御定全唐詩/json/573.json','["此別誠堪恨，荊襄是舊遊。眼光懸欲落，心緒亂難收。", "花木三層寺，煙波五相樓。因君兩地去，長使夢悠悠。"]'),
('yuding-129','寄慈恩寺郁上人','賈島','唐','御定全唐诗','yuding','','[]','中秋期夕望，虛室省相容。北斗生清漏，南山出碧重。',48,'御定全唐詩/json/573.json','["中秋期夕望，虛室省相容。北斗生清漏，南山出碧重。", "露寒鳩宿竹，鴻過月圓鐘。此夜情應切，衡陽舊住峰。"]'),
('yuding-0','送饒州張使君','賈島','唐','御定全唐诗','yuding','','[]','終南雲雨連城闕，去路西江白浪頭。滁上郡齋離昨日，',40,'御定全唐詩/json/574.json','["終南雲雨連城闕，去路西江白浪頭。滁上郡齋離昨日，", "借問泊帆幹謁者，誰人曾聽峽猿愁。"]'),
('yuding-1','觀冬設上東川楊尚書','賈島','唐','御定全唐诗','yuding','','[]','匏革奏冬非獨樂，軍城未曉啟重門。何時卻入三台貴，',40,'御定全唐詩/json/574.json','["匏革奏冬非獨樂，軍城未曉啟重門。何時卻入三台貴，", "逐遷屬吏隨賓列，撥棹扁舟不忘恩。"]'),
('yuding-2','巴興作','賈島','唐','御定全唐诗','yuding','','[]','三年未省聞鴻叫，九月何曾見草枯。寒暑氣均思白社，',40,'御定全唐詩/json/574.json','["三年未省聞鴻叫，九月何曾見草枯。寒暑氣均思白社，", "鄉味朔山林果別，北歸期掛海帆孤。"]'),
('yuding-3','早蟬','賈島','唐','御定全唐诗','yuding','','[]','早蟬孤抱芳槐葉，噪向殘陽意度秋。也任一聲催我老，',40,'御定全唐詩/json/574.json','["早蟬孤抱芳槐葉，噪向殘陽意度秋。也任一聲催我老，", "若問此心嗟歎否，天人不可怨而尤。"]'),
('yuding-4','投元郎中','賈島','唐','御定全唐诗','yuding','','[]','心在瀟湘歸未期，卷中多是得名詩。高臺聊望清秋色，',40,'御定全唐詩/json/574.json','["心在瀟湘歸未期，卷中多是得名詩。高臺聊望清秋色，", "舊文去歲曾將獻，蒙與人來說始知。"]'),
('yuding-5','阮籍嘯台','賈島','唐','御定全唐诗','yuding','','[]','如聞長嘯春風裏，荊棘叢邊訪舊蹤。',32,'御定全唐詩/json/574.json','["如聞長嘯春風裏，荊棘叢邊訪舊蹤。", "地接蘇門山近遠，荒台突兀抵高峰。"]'),
('yuding-6','滕校書使院小池','賈島','唐','御定全唐诗','yuding','','[]','小池誰見鑿時初，走水南來十裏餘。',32,'御定全唐詩/json/574.json','["小池誰見鑿時初，走水南來十裏餘。", "樓上日斜吹暮角，院中人出鎖游魚。"]'),
('yuding-7','送陝府王建司馬','賈島','唐','御定全唐诗','yuding','','[]','司馬雖然聽曉鐘，尚猶高枕恣疏慵。請詩僧過三門水，',40,'御定全唐詩/json/574.json','["司馬雖然聽曉鐘，尚猶高枕恣疏慵。請詩僧過三門水，", "杜陵惆悵臨相餞，未寢月前多屐蹤。"]'),
('yuding-8','上穀旅夜','賈島','唐','御定全唐诗','yuding','','[]','世難那堪恨旅遊，龍鍾更是對窮秋。故園千里數行淚，',40,'御定全唐詩/json/574.json','["世難那堪恨旅遊，龍鍾更是對窮秋。故園千里數行淚，", "此心不向常人說，倚識平津萬戶侯。"]'),
('yuding-9','寄無得頭陀','賈島','唐','御定全唐诗','yuding','','[]','夏臘今應三十餘，不離樹下塚間居。貌堪良匠抽毫寫，',40,'御定全唐詩/json/574.json','["夏臘今應三十餘，不離樹下塚間居。貌堪良匠抽毫寫，", "白衣只在青門裏，心每相親跡且疏。"]'),
('yuding-10','崔卿池上雙白鷺','賈島','唐','御定全唐诗','yuding','','[]','鷺雛相逐出深籠，頂各有絲莖數同。灑石多霜移足冷，',40,'御定全唐詩/json/574.json','["鷺雛相逐出深籠，頂各有絲莖數同。灑石多霜移足冷，", "見此池潭卿自鑿，清泠太液底潛通。"]'),
('yuding-11','送胡道士','賈島','唐','御定全唐诗','yuding','','[]','短褐身披滿漬苔，靈溪深處觀門開。卻從城裏移琴去，',40,'御定全唐詩/json/574.json','["短褐身披滿漬苔，靈溪深處觀門開。卻從城裏移琴去，", "丹梯願逐真人上，日夕歸心白髮催。"]'),
('yuding-12','寄韓潮州愈','賈島','唐','御定全唐诗','yuding','','[]','此心曾與木蘭舟，直到天南潮水頭。隔嶺篇章來華嶽，',40,'御定全唐詩/json/574.json','["此心曾與木蘭舟，直到天南潮水頭。隔嶺篇章來華嶽，", "一夕瘴煙風卷盡，月明初上浪西樓。"]'),
('yuding-13','酬張籍王建','賈島','唐','御定全唐诗','yuding','','[]','疏林荒宅古坡前，久住還因太守憐。漸老更思深處隱，',40,'御定全唐詩/json/574.json','["疏林荒宅古坡前，久住還因太守憐。漸老更思深處隱，", "身是龍鍾應是分，水曹芸閣枉來篇。"]'),
('yuding-14','逢博陵故人彭兵曹','賈島','唐','御定全唐诗','yuding','','[]','曲陽分散會京華，見說三年住海涯。別後解餐蓬虆子，',40,'御定全唐詩/json/574.json','["曲陽分散會京華，見說三年住海涯。別後解餐蓬虆子，", "蹋雪攜琴相就宿，夜深開戶鬥牛斜。"]'),
('yuding-15','贈牛山人','賈島','唐','御定全唐诗','yuding','','[]','二十年中餌茯苓，致書半是老君經。東都舊住商人宅，',40,'御定全唐詩/json/574.json','["二十年中餌茯苓，致書半是老君經。東都舊住商人宅，", "古來隱者多能蔔，欲就先生問丙丁。"]'),
('yuding-16','送於中丞使回紇冊立','賈島','唐','御定全唐诗','yuding','','[]','君立天驕發使車，冊文字字著金書。漸通青塚鄉山盡，',40,'御定全唐詩/json/574.json','["君立天驕發使車，冊文字字著金書。漸通青塚鄉山盡，", "旌旗來往幾多日，應向途中見歲除。"]'),
('yuding-17','送劉侍禦重使江西','賈島','唐','御定全唐诗','yuding','','[]','時當苦熱遠行人，石壁飛泉濺馬身。又到鐘陵知務大，',40,'御定全唐詩/json/574.json','["時當苦熱遠行人，石壁飛泉濺馬身。又到鐘陵知務大，", "前者已聞廉使薦，兼言有畫靜邊塵。"]'),
('yuding-18','贈圓上人','賈島','唐','御定全唐诗','yuding','','[]','誦經千紙得為僧，麈尾持行不拂蠅。古塔月高聞咒水，',40,'御定全唐詩/json/574.json','["誦經千紙得為僧，麈尾持行不拂蠅。古塔月高聞咒水，", "且說近來心裏事，仇讎相對似親朋。"]'),
('yuding-19','處州李使君改任遂州因寄贈','賈島','唐','御定全唐诗','yuding','','[]','庭樹幾株陰入戶，主人何在客聞蟬。鑰開原上高樓鎖，',40,'御定全唐詩/json/574.json','["庭樹幾株陰入戶，主人何在客聞蟬。鑰開原上高樓鎖，", "仙都山水誰能憶，西去風濤書滿船。"]'),
('yuding-20','酬慈恩寺文郁上人','賈島','唐','御定全唐诗','yuding','','[]','袈裟影入禁池清，猶憶鄉山近赤城。籬落罅間寒蟹過，',40,'御定全唐詩/json/574.json','["袈裟影入禁池清，猶憶鄉山近赤城。籬落罅間寒蟹過，", "聞說又尋南嶽去，無端詩思忽然生。"]'),
('yuding-21','訪鑒玄師侄','賈島','唐','御定全唐诗','yuding','','[]','維摩青石講初休，緣訪親宗到普州。',32,'御定全唐詩/json/574.json','["維摩青石講初休，緣訪親宗到普州。", "我有軍持憑弟子，岳陽溪裏汲寒流。"]'),
('yuding-22','夜坐','賈島','唐','御定全唐诗','yuding','','[]','蟋蟀漸多秋不淺，蟾蜍已沒夜應深。',32,'御定全唐詩/json/574.json','["蟋蟀漸多秋不淺，蟾蜍已沒夜應深。", "三更兩鬢幾枝雪，一念雙峰四祖心。"]'),
('yuding-23','送別','賈島','唐','御定全唐诗','yuding','','[]','門外便伸千里別，無車不得到河梁。',32,'御定全唐詩/json/574.json','["門外便伸千里別，無車不得到河梁。", "高樓直上百餘尺，今日為君南望長。"]'),
('yuding-24','聞蟬感懷','賈島','唐','御定全唐诗','yuding','','[]','新蟬忽發最高枝，不覺立聽無限時。',32,'御定全唐詩/json/574.json','["新蟬忽發最高枝，不覺立聽無限時。", "正遇友人來告別，一心分作兩般悲。"]'),
('yuding-25','夏夜上穀宿開元寺','賈島','唐','御定全唐诗','yuding','','[]','詩成一夜月中題，便臥松風到曙雞。',32,'御定全唐詩/json/574.json','["詩成一夜月中題，便臥松風到曙雞。", "帶月時聞山鳥語，郡城知近武陵溪。"]'),
('yuding-26','送於總持歸京','賈島','唐','御定全唐诗','yuding','','[]','出家初隸何方寺，上國西明禦水東。',32,'御定全唐詩/json/574.json','["出家初隸何方寺，上國西明禦水東。", "卻見舊房階下樹，別來二十一春風。"]'),
('yuding-27','崔卿池上鶴','賈島','唐','御定全唐诗','yuding','','[]','月中時叫葉紛紛，不異洞庭霜夜聞。',32,'御定全唐詩/json/574.json','["月中時叫葉紛紛，不異洞庭霜夜聞。", "翎羽如今從放長，猶能飛起向孤雲。"]'),
('yuding-28','登田中丞高亭','賈島','唐','御定全唐诗','yuding','','[]','高亭林表迥嵯峨，獨坐秋宵不寢多。',32,'御定全唐詩/json/574.json','["高亭林表迥嵯峨，獨坐秋宵不寢多。", "玉兔玉人歌裏出，白雲難似莫相和。"]'),
('yuding-29','友人婚楊氏催妝','賈島','唐','御定全唐诗','yuding','','[]','不知今夕是何夕，催促陽臺近鏡臺。',32,'御定全唐詩/json/574.json','["不知今夕是何夕，催促陽臺近鏡臺。", "誰道芙蓉水中種，青銅鏡裏一枝開。"]'),
('yuding-30','酬朱侍禦望月見寄','賈島','唐','御定全唐诗','yuding','','[]','他寢此時吾不寢，近秋三五日逢晴。',32,'御定全唐詩/json/574.json','["他寢此時吾不寢，近秋三五日逢晴。", "相思唯有霜台月，望盡孤光見卻生。"]'),
('yuding-31','題韋雲叟草堂','賈島','唐','御定全唐诗','yuding','','[]','新起此堂開北窗，當窗山隔一重江。',32,'御定全唐詩/json/574.json','["新起此堂開北窗，當窗山隔一重江。", "白茅草苫重重密，愛此秋天夜雨淙。"]'),
('yuding-32','和韓吏部泛南溪','賈島','唐','御定全唐诗','yuding','','[]','溪裏晚從池岸出，石泉秋急夜深聞。',32,'御定全唐詩/json/574.json','["溪裏晚從池岸出，石泉秋急夜深聞。", "木蘭船共山人上，月映渡頭零落雲。"]'),
('yuding-33','方鏡','賈島','唐','御定全唐诗','yuding','','[]','背如刀截機頭錦，面似升量澗底泉。',32,'御定全唐詩/json/574.json','["背如刀截機頭錦，面似升量澗底泉。", "銅雀台南秋日後，照來照去已三年。"]'),
('yuding-34','酬姚合','賈島','唐','御定全唐诗','yuding','','[]','黍穗豆苗侵古道，晴原午後早秋時。',32,'御定全唐詩/json/574.json','["黍穗豆苗侵古道，晴原午後早秋時。", "故人相憶僧來說，楊柳無風蟬滿枝。"]'),
('yuding-35','送靈應上人','賈島','唐','御定全唐诗','yuding','','[]','遍參尊宿游方久，名岳奇峰問此公。',32,'御定全唐詩/json/574.json','["遍參尊宿游方久，名岳奇峰問此公。", "五月半間看瀑布，青城山裏白雲中。"]'),
('yuding-36','贈丘先生','賈島','唐','御定全唐诗','yuding','','[]','常言吃藥全勝飯，華岳松邊采茯神。',32,'御定全唐詩/json/574.json','["常言吃藥全勝飯，華岳松邊采茯神。", "不遣髭須一莖白，擬為白日上升人。"]'),
('yuding-37','渡桑幹','賈島','唐','御定全唐诗','yuding','','[]','客舍並州已十霜，歸心日夜憶咸陽。',32,'御定全唐詩/json/574.json','["客舍並州已十霜，歸心日夜憶咸陽。", "無端更渡桑幹水，卻望並州是故鄉。"]'),
('yuding-38','夜期嘯客呂逸人不至','賈島','唐','御定全唐诗','yuding','','[]','逸人期宿石床中，遣我開扉對晚空。',32,'御定全唐詩/json/574.json','["逸人期宿石床中，遣我開扉對晚空。", "不知何處嘯秋月，閑著松門一夜風。"]'),
('yuding-39','夜集烏行中所居','賈島','唐','御定全唐诗','yuding','','[]','環爐促席複持杯，松院雙扉向月開。',32,'御定全唐詩/json/574.json','["環爐促席複持杯，松院雙扉向月開。", "座上同聲半先達，名山獨入此心來。"]'),
('yuding-40','贈梁浦秀才斑竹拄杖','賈島','唐','御定全唐诗','yuding','','[]','揀得林中最細枝，結根石上長身遲。',32,'御定全唐詩/json/574.json','["揀得林中最細枝，結根石上長身遲。", "莫嫌滴瀝紅斑少，恰似湘妃淚盡時。"]'),
('yuding-41','尋石甕寺上方','賈島','唐','御定全唐诗','yuding','','[]','野寺入時春雪後，崎嶇得到此房前。',32,'御定全唐詩/json/574.json','["野寺入時春雪後，崎嶇得到此房前。", "老僧不出迎朝客，已住上方三十年。"]'),
('yuding-42','早秋寄題天竺靈隱寺','賈島','唐','御定全唐诗','yuding','','[]','峰前峰後寺新秋，絕頂高窗見沃洲。人在定中聞蟋蟀，',40,'御定全唐詩/json/574.json','["峰前峰後寺新秋，絕頂高窗見沃洲。人在定中聞蟋蟀，", "心憶懸帆身未遂，謝公此地昔年遊。"]'),
('yuding-43','黎陽寄姚合','賈島','唐','御定全唐诗','yuding','','[]','魏都城裏曾游熟，才子齋中止泊多。去日綠楊垂紫陌，',40,'御定全唐詩/json/574.json','["魏都城裏曾游熟，才子齋中止泊多。去日綠楊垂紫陌，", "惆悵心思滑臺北，滿杯濃酒與愁和。"]'),
('yuding-44','送崔約秀才','賈島','唐','御定全唐诗','yuding','','[]','歸寧仿佛三千里，月向船窗見幾宵。野鼠獨偷高樹果，',40,'御定全唐詩/json/574.json','["歸寧仿佛三千里，月向船窗見幾宵。野鼠獨偷高樹果，", "重入石頭城下寺，南朝杉老未幹燋。"]'),
('yuding-45','詠懷','賈島','唐','御定全唐诗','yuding','','[]','縱把書看未省勤，一生生計只長貧。可能在世無成事，',40,'御定全唐詩/json/574.json','["縱把書看未省勤，一生生計只長貧。可能在世無成事，", "經年抱疾誰來問，野鳥相過啄木頻。"]'),
('yuding-46','夏日寄高洗馬','賈島','唐','御定全唐诗','yuding','','[]','三十年來長在客，兩三行淚忽然垂。白衣蒼鬢經過懶，',40,'御定全唐詩/json/574.json','["三十年來長在客，兩三行淚忽然垂。白衣蒼鬢經過懶，", "不緣馬死西州去，畫角堪聽是曉吹。"]'),
('yuding-47','送周判官元范赴越','賈島','唐','御定全唐诗','yuding','','[]','原下相逢便別離，蟬鳴關路使回時。過淮漸有懸帆興，',40,'御定全唐詩/json/574.json','["原下相逢便別離，蟬鳴關路使回時。過淮漸有懸帆興，", "已曾幾遍隨旌旆，去謁荒郊大禹祠。"]'),
('yuding-48','送羅少府歸牛渚','賈島','唐','御定全唐诗','yuding','','[]','作尉長安始三日，忽思牛渚夢天臺。楚山遠色獨歸去，',40,'御定全唐詩/json/574.json','["作尉長安始三日，忽思牛渚夢天臺。楚山遠色獨歸去，", "白雲多處應頻到，寒澗泠泠漱古苔。"]'),
('yuding-49','題童真上人','賈島','唐','御定全唐诗','yuding','','[]','江上修持積歲年，灘聲未擬住潺湲。誓從五十身披衲，',40,'御定全唐詩/json/574.json','["江上修持積歲年，灘聲未擬住潺湲。誓從五十身披衲，", "昨宵忽夢遊滄海，萬里波濤在目前。"]'),
('yuding-50','贈溫觀主','賈島','唐','御定全唐诗','yuding','','[]','一別羅浮竟未還，觀深廊古院多關。君來幾日行虛洞，',40,'御定全唐詩/json/574.json','["一別羅浮竟未還，觀深廊古院多關。君來幾日行虛洞，", "弊廬道室雖鄰近，自樂冬陽炙背閑。"]'),
('yuding-51','賀龐少尹除太常少卿','賈島','唐','御定全唐诗','yuding','','[]','太白山前終日見，十旬假滿擬秋尋。中峰絕頂非無路，',40,'御定全唐詩/json/574.json','["太白山前終日見，十旬假滿擬秋尋。中峰絕頂非無路，", "省中石鐙陪隨步，唯賞煙霞不厭深。"]'),
('yuding-52','上邠甯刑司徒','賈島','唐','御定全唐诗','yuding','','[]','箭頭破帖渾無敵，杖底敲球遠有聲。馬走千蹄朝萬乘，',40,'御定全唐詩/json/574.json','["箭頭破帖渾無敵，杖底敲球遠有聲。馬走千蹄朝萬乘，", "不是邢公來鎮此，長安西北未能行。"]'),
('yuding-53','欲游嵩岳留別李少尹益','賈島','唐','御定全唐诗','yuding','','[]','孤策遲回洛水湄，孤禽嘹唳幸人知。嵩嶽望中常待我，',40,'御定全唐詩/json/574.json','["孤策遲回洛水湄，孤禽嘹唳幸人知。嵩嶽望中常待我，", "微眇此來將敢問，鳳凰何日定歸池。"]'),
('yuding-54','病鶻吟','賈島','唐','御定全唐诗','yuding','','[]','俊鳥還投高處棲，騰身戛戛下雲梯。有時透霧淩空去，',40,'御定全唐詩/json/574.json','["俊鳥還投高處棲，騰身戛戛下雲梯。有時透霧淩空去，", "不緣毛羽遭零落，焉肯雄心向爾低。"]'),
('yuding-55','贈僧','賈島','唐','御定全唐诗','yuding','','[]','從來多是遊山水，省泊禪舟月下濤。初過石橋年尚少，',40,'御定全唐詩/json/574.json','["從來多是遊山水，省泊禪舟月下濤。初過石橋年尚少，", "常恐畫工援筆寫，身長七尺有眉毫。"]'),
('yuding-56','贈翰林','賈島','唐','御定全唐诗','yuding','','[]','清重無過知內制，從前禮絕外庭人。看花在處多隨駕，',40,'御定全唐詩/json/574.json','["清重無過知內制，從前禮絕外庭人。看花在處多隨駕，", "應憐獨向名場苦，曾十餘年浪過春。"]'),
('yuding-57','頌德上賈常侍','賈島','唐','御定全唐诗','yuding','','[]','邊臣說使朝天子，發語轟然激夏雷。高節羽書期獨傳，',40,'御定全唐詩/json/574.json','["邊臣說使朝天子，發語轟然激夏雷。高節羽書期獨傳，", "自顧此身無所立，恭談祖德朵頤開。"]'),
('yuding-58','田將軍書院','賈島','唐','御定全唐诗','yuding','','[]','滿庭花木半新栽，石自平湖遠岸來。筍迸鄰家還長竹，',40,'御定全唐詩/json/574.json','["滿庭花木半新栽，石自平湖遠岸來。筍迸鄰家還長竹，", "行背曲江誰到此，琴書鎖著未朝回。"]'),
('yuding-59','投龐少尹','賈島','唐','御定全唐诗','yuding','','[]','閉戶息機搔白首，中庭一樹有清陰。年年不改風塵趣，',40,'御定全唐詩/json/574.json','["閉戶息機搔白首，中庭一樹有清陰。年年不改風塵趣，", "龐公相識元和歲，眷分依依直至今。"]'),
('yuding-60','夏夜登南樓','賈島','唐','御定全唐诗','yuding','','[]','水岸寒樓帶月躋，夏林初見岳陽溪。',32,'御定全唐詩/json/574.json','["水岸寒樓帶月躋，夏林初見岳陽溪。", "一點新螢報秋信，不知何處是菩提。"]'),
('yuding-61','題青龍寺','賈島','唐','御定全唐诗','yuding','','[]','碣石山人一軸詩，終南山北數人知。',32,'御定全唐詩/json/574.json','["碣石山人一軸詩，終南山北數人知。", "擬看青龍寺裏月，待無一點夜雲時。"]'),
('yuding-62','贈李文通','賈島','唐','御定全唐诗','yuding','','[]','營當萬勝岡頭下，誓立千年不朽功。',32,'御定全唐詩/json/574.json','["營當萬勝岡頭下，誓立千年不朽功。", "天子手擎新鉞斧，諫官請贈李文通。"]'),
('yuding-63','題虢州三堂贈吳郎中','賈島','唐','御定全唐诗','yuding','','[]','無窮草樹昔誰栽，新起臨湖白石台。半岸泥沙孤鶴立，',40,'御定全唐詩/json/574.json','["無窮草樹昔誰栽，新起臨湖白石台。半岸泥沙孤鶴立，", "昨夜北樓堪朗詠，虢城初鎖月裴回。"]'),
('yuding-64','送僧','賈島','唐','御定全唐诗','yuding','','[]','池上時時松雪落，焚香煙起見孤燈。',32,'御定全唐詩/json/574.json','["池上時時松雪落，焚香煙起見孤燈。", "靜夜憶誰來對坐，曲江南岸寺中僧。"]'),
('yuding-65','三月晦日贈劉評事','賈島','唐','御定全唐诗','yuding','','[]','三月正當三十日，風光別我苦吟身。',32,'御定全唐詩/json/574.json','["三月正當三十日，風光別我苦吟身。", "共君今夜不須睡，未到曉鐘猶是春。"]'),
('yuding-66','送張道者','賈島','唐','御定全唐诗','yuding','','[]','新歲抱琴何處去，洛陽三十六峰西。',32,'御定全唐詩/json/574.json','["新歲抱琴何處去，洛陽三十六峰西。", "生來未識山人面，不得一聽烏夜啼。"]'),
('yuding-67','題魚尊師院','賈島','唐','御定全唐诗','yuding','','[]','老子堂前花萬樹，先生曾見幾回春。',32,'御定全唐詩/json/574.json','["老子堂前花萬樹，先生曾見幾回春。", "夜煎白石平明吃，不擬教人哭此身。"]'),
('yuding-68','宿村家亭子','賈島','唐','御定全唐诗','yuding','','[]','床頭枕是溪中石，井底泉通竹下池。',32,'御定全唐詩/json/574.json','["床頭枕是溪中石，井底泉通竹下池。", "宿客未眠過夜半，獨聞山雨到來時。"]'),
('yuding-69','送稱上人','賈島','唐','御定全唐诗','yuding','','[]','歸蜀擬從巫峽過，何時得入舊房禪。',32,'御定全唐詩/json/574.json','["歸蜀擬從巫峽過，何時得入舊房禪。", "寺中來後誰身化，起塔栽松向野田。"]'),
('yuding-70','楊秘書新居','賈島','唐','御定全唐诗','yuding','','[]','城角新居鄰靜寺，時從新閣上經樓。',32,'御定全唐詩/json/574.json','["城角新居鄰靜寺，時從新閣上經樓。", "南山泉入宮中去，先向詩人門外流。"]'),
('yuding-71','聽樂山人彈易水','賈島','唐','御定全唐诗','yuding','','[]','朱絲弦底燕泉急，燕將雲孫白日彈。',32,'御定全唐詩/json/574.json','["朱絲弦底燕泉急，燕將雲孫白日彈。", "嬴氏歸山陵已掘，聲聲猶帶發沖冠。"]'),
('yuding-72','經蘇秦墓','賈島','唐','御定全唐诗','yuding','','[]','沙埋古篆折碑文，六國興亡事系君。',32,'御定全唐詩/json/574.json','["沙埋古篆折碑文，六國興亡事系君。", "今日淒涼無處說，亂山秋盡有寒雲。"]'),
('yuding-73','題戴勝','賈島','唐','御定全唐诗','yuding','','[]','星點花冠道士衣，紫陽宮女化身飛。',32,'御定全唐詩/json/574.json','["星點花冠道士衣，紫陽宮女化身飛。", "能傳上界春消息，若到蓬山莫放歸。"]'),
('yuding-74','題隱者居','賈島','唐','御定全唐诗','yuding','','[]','雖有柴門常不關，片雲孤木伴身閑。',32,'御定全唐詩/json/574.json','["雖有柴門常不關，片雲孤木伴身閑。", "猶嫌住久人知處，見擬移家更上山。"]'),
('yuding-75','哭孟東野','賈島','唐','御定全唐诗','yuding','','[]','蘭無香氣鶴無聲，哭盡秋天月不明。',32,'御定全唐詩/json/574.json','["蘭無香氣鶴無聲，哭盡秋天月不明。", "自從東野先生死，側近雲山得散行。"]'),
('yuding-76','過京索先生墳','賈島','唐','御定全唐诗','yuding','','[]','京索先生三尺墳，秋風漠漠吐寒雲。',32,'御定全唐詩/json/574.json','["京索先生三尺墳，秋風漠漠吐寒雲。", "從來有恨君多哭，今日何人更哭君。"]'),
('yuding-77','客思','賈島','唐','御定全唐诗','yuding','','[]','促織聲尖尖似針，更深刺著旅人心。',32,'御定全唐詩/json/574.json','["促織聲尖尖似針，更深刺著旅人心。", "獨言獨語月明裏，驚覺眠童與宿禽。"]'),
('yuding-78','鹽池院觀鹿','賈島','唐','御定全唐诗','yuding','','[]','條峰五老勢相連，此鹿來從若個邊。',32,'御定全唐詩/json/574.json','["條峰五老勢相連，此鹿來從若個邊。", "別有野麋人不見，一生長飲白雲泉。"]'),
('yuding-79','黃鵠下太液池','賈島','唐','御定全唐诗','yuding','','[]','高飛空外鵠，下向禁中池。岸印行蹤淺，波搖立影危。',72,'御定全唐詩/json/574.json','["高飛空外鵠，下向禁中池。岸印行蹤淺，波搖立影危。", "來從千里島，舞拂萬年枝。踉蹌孤風起，裴回水沫移。", "幽音清露滴，野性白雲隨。太液無彈射，靈禽翅不垂。"]'),
('yuding-80','代舊將','賈島','唐','御定全唐诗','yuding','','[]','舊事說如夢，誰當信老夫。戰場幾處在，部曲一人無。',48,'御定全唐詩/json/574.json','["舊事說如夢，誰當信老夫。戰場幾處在，部曲一人無。", "落日收病馬，晴天曬陣圖。猶希聖朝用，自鑷白髭須。"]'),
('yuding-81','老將','賈島','唐','御定全唐诗','yuding','','[]','膽壯亂須白，金瘡蠹百骸。旌旗猶入夢，歌舞不開懷。',48,'御定全唐詩/json/574.json','["膽壯亂須白，金瘡蠹百骸。旌旗猶入夢，歌舞不開懷。", "燕雀來鷹架，塵埃滿箭靫。自誇勳業重，開府是官階。"]'),
('yuding-82','春行','賈島','唐','御定全唐诗','yuding','','[]','去去行人遠，塵隨馬不窮。旅情斜日後，春色早煙中。',48,'御定全唐詩/json/574.json','["去去行人遠，塵隨馬不窮。旅情斜日後，春色早煙中。", "流水穿空館，閑花發故宮。舊鄉千里思，池上綠楊風。"]'),
('yuding-83','題鄭常侍廳前竹','賈島','唐','御定全唐诗','yuding','','[]','綠竹臨詩酒，嬋娟思不窮。亂枝低積雪，繁葉亞寒風。',120,'御定全唐詩/json/574.json','["綠竹臨詩酒，嬋娟思不窮。亂枝低積雪，繁葉亞寒風。", "蕭颯疑泉過，縈回有徑通。侵庭根出土，隔壁筍成叢。", "疏影紗窗外，清音寶瑟中。捲簾終日看，欹枕幾秋同。", "萬頃歌王子，千竿伴阮公。露光憐片片，雨潤愛濛濛。", "嶰穀蠻湖北，湘川灀水東。何如軒檻側，蒼翠嫋長空。"]'),
('yuding-84','早行','賈島','唐','御定全唐诗','yuding','','[]','早起赴前程，鄰雞尚未鳴。主人燈下別，羸馬暗中行。',48,'御定全唐詩/json/574.json','["早起赴前程，鄰雞尚未鳴。主人燈下別，羸馬暗中行。", "蹋石新霜滑，穿林宿鳥驚。遠山鐘動後，曙色漸分明。"]'),
('yuding-85','送人南歸','賈島','唐','御定全唐诗','yuding','','[]','分手向天涯，迢迢泛海波。雖然南地遠，見說北人多。',48,'御定全唐詩/json/574.json','["分手向天涯，迢迢泛海波。雖然南地遠，見說北人多。", "山暖花常發，秋深雁不過。炎方饒勝事，此去莫蹉跎。"]'),
('yuding-86','送人南游','賈島','唐','御定全唐诗','yuding','','[]','此別天涯遠，孤舟泛海中。夜行常認火，帆去每因風。',48,'御定全唐詩/json/574.json','["此別天涯遠，孤舟泛海中。夜行常認火，帆去每因風。", "蠻國人多富，炎方語不同。雁飛難度嶺，書信若為通。"]'),
('yuding-87','送道者','賈島','唐','御定全唐诗','yuding','','[]','獨向山中見，今朝又別離。一心無掛住，萬里獨何之。',48,'御定全唐詩/json/574.json','["獨向山中見，今朝又別離。一心無掛住，萬里獨何之。", "到處絕煙火，逢人話古時。此行無弟子，白犬自相隨。"]'),
('yuding-88','風蟬','賈島','唐','御定全唐诗','yuding','','[]','風蟬旦夕鳴，伴葉送新聲。故里客歸盡，水邊身獨行。',48,'御定全唐詩/json/574.json','["風蟬旦夕鳴，伴葉送新聲。故里客歸盡，水邊身獨行。", "噪軒高樹合，驚枕暮山橫。聽處無人見，塵埃滿甑生。"]'),
('yuding-89','清明日園林寄友人','賈島','唐','御定全唐诗','yuding','','[]','今日清明節，園林勝事偏。晴風吹柳絮，新火起廚煙。',48,'御定全唐詩/json/574.json','["今日清明節，園林勝事偏。晴風吹柳絮，新火起廚煙。", "杜草開三徑，文章憶二賢。幾時能命駕，對酒落花前。"]'),
('yuding-90','上杜駙馬','賈島','唐','御定全唐诗','yuding','','[]','玉山突兀壓乾坤，出得朱門入戟門。妻是九重天子女，',40,'御定全唐詩/json/574.json','["玉山突兀壓乾坤，出得朱門入戟門。妻是九重天子女，", "今日澧陽非久駐，佇為霖雨拜新恩。"]'),
('yuding-91','蓮峰歌','賈島','唐','御定全唐诗','yuding','','[]','錦礫潺湲玉溪水，曉來微雨藤花紫。冉冉山雞紅尾長，',40,'御定全唐詩/json/574.json','["錦礫潺湲玉溪水，曉來微雨藤花紫。冉冉山雞紅尾長，", "陽崖一夢伴雲根，仙菌靈芝夢魂裏。"]'),
('yuding-92','壯士吟','賈島','唐','御定全唐诗','yuding','','[]','壯士不曾悲，悲即無回期。如何易水上，未歌先淚垂。',24,'御定全唐詩/json/574.json','["壯士不曾悲，悲即無回期。如何易水上，未歌先淚垂。"]'),
('yuding-93','題興化園亭','賈島','唐','御定全唐诗','yuding','','[]','破卻千家作一池，不栽桃李種薔薇。',32,'御定全唐詩/json/574.json','["破卻千家作一池，不栽桃李種薔薇。", "薔薇花落秋風起，荊棘滿庭君始知。"]'),
('yuding-94','竹','賈島','唐','御定全唐诗','yuding','','[]','籬外清陰接藥欄，曉風交戛碧琅玕。子猷沒後知音少，粉節霜筠漫歲寒。',32,'御定全唐詩/json/574.json','["籬外清陰接藥欄，曉風交戛碧琅玕。子猷沒後知音少，粉節霜筠漫歲寒。"]'),
('yuding-95','李斯井','賈島','唐','御定全唐诗','yuding','','[]','井存上蔡南門外，置此井時來相秦。',32,'御定全唐詩/json/574.json','["井存上蔡南門外，置此井時來相秦。", "斷綆數尋垂古甃，取將寒水是何人。"]'),
('yuding-96','題詩後','賈島','唐','御定全唐诗','yuding','','[]','二句三年得，一吟雙淚流。知音如不賞，歸臥故山秋。',24,'御定全唐詩/json/574.json','["二句三年得，一吟雙淚流。知音如不賞，歸臥故山秋。"]'),
('yuding-97','送友人之南陵','賈島','唐','御定全唐诗','yuding','','[]','莫歎徒勞向宦途，不群氣岸有誰如。南陵暫掌仇香印，',40,'御定全唐詩/json/574.json','["莫歎徒勞向宦途，不群氣岸有誰如。南陵暫掌仇香印，", "少年躍馬同心使，免得詩中道跨驢。"]'),
('yuding-98','尋人不遇','賈島','唐','御定全唐诗','yuding','','[]','聞說到揚州，吹簫有舊遊。人來多不見，莫是上迷樓。',24,'御定全唐詩/json/574.json','["聞說到揚州，吹簫有舊遊。人來多不見，莫是上迷樓。"]'),
('yuding-99','尋隱者不遇','賈島','唐','御定全唐诗','yuding','','[]','松下問童子，言師采藥去。只在此山中，雲深不知處。',24,'御定全唐詩/json/574.json','["松下問童子，言師采藥去。只在此山中，雲深不知處。"]'),
('yuding-100','行次漢上','賈島','唐','御定全唐诗','yuding','','[]','習家池沼草萋萋，嵐樹光中信馬蹄。',32,'御定全唐詩/json/574.json','["習家池沼草萋萋，嵐樹光中信馬蹄。", "漢主廟前湘水碧，一聲風角夕陽低。"]'),
('yuding-101','馬嵬','賈島','唐','御定全唐诗','yuding','','[]','長川幾處樹青青，孤驛危樓對翠屏。',32,'御定全唐詩/json/574.json','["長川幾處樹青青，孤驛危樓對翠屏。", "一自上皇惆悵後，至今來往馬蹄腥。"]'),
('yuding-102','冬夜送人','賈島','唐','御定全唐诗','yuding','','[]','平明走馬上村橋，花落梅溪雪未消。',32,'御定全唐詩/json/574.json','["平明走馬上村橋，花落梅溪雪未消。", "日短天寒愁送客，楚山無限路迢迢。"]'),
('yuding-103','句','賈島','唐','御定全唐诗','yuding','','[]','晴風吹柳絮，新火起廚煙。。',52,'御定全唐詩/json/574.json','["晴風吹柳絮，新火起廚煙。。", "長江風送客，孤館雨留人。。", "古岸崩將盡，平沙長未休。。", "不如牛與羊，猶得日暮歸。。"]'),
('yuding-0','雞鳴埭曲','溫庭筠','唐','御定全唐诗','yuding','','[]','南朝天子射雉時，銀河耿耿星參差。銅壺漏斷夢初覺，',88,'御定全唐詩/json/575.json','["南朝天子射雉時，銀河耿耿星參差。銅壺漏斷夢初覺，", "紅妝萬戶鏡中春，碧樹一聲天下曉。盤踞勢窮三百年，", "繡龍畫雉填宮井，野火風驅燒九鼎。殿巢江燕砌生蒿，", "甯知玉樹後庭曲，留待野棠如雪枝。"]'),
('yuding-1','織錦詞','溫庭筠','唐','御定全唐诗','yuding','','[]','丁東細漏侵瓊瑟，影轉高梧月初出。簇簌金梭萬縷紅，',48,'御定全唐詩/json/575.json','["丁東細漏侵瓊瑟，影轉高梧月初出。簇簌金梭萬縷紅，", "此意欲傳傳不得，玫瑰作柱朱弦琴。為君裁破合歡被，"]'),
('yuding-2','夜宴謠','溫庭筠','唐','御定全唐诗','yuding','','[]','長釵墜發雙蜻蜓，碧盡山斜開畫屏。虯須公子五侯客，',72,'御定全唐詩/json/575.json','["長釵墜發雙蜻蜓，碧盡山斜開畫屏。虯須公子五侯客，", "清夜恩情四座同，莫令溝水東西別。亭亭蠟淚香珠殘，", "裂管縈弦共繁曲，芳樽細浪傾春醁。高樓客散杏花多，"]'),
('yuding-3','蓮浦謠','溫庭筠','唐','御定全唐诗','yuding','','[]','鳴橈軋軋溪溶溶，廢綠平煙吳苑東。水清蓮媚兩相向，',40,'御定全唐詩/json/575.json','["鳴橈軋軋溪溶溶，廢綠平煙吳苑東。水清蓮媚兩相向，", "荷心有露似驪珠，不是真圓亦搖盪。"]'),
('yuding-4','郭處士擊甌歌','溫庭筠','唐','御定全唐诗','yuding','','[]','佶栗金虯石潭古，勺陂瀲灩幽修語。湘君寶馬上神雲，',104,'御定全唐詩/json/575.json','["佶栗金虯石潭古，勺陂瀲灩幽修語。湘君寶馬上神雲，", "玉晨冷磬破昏夢，天露未幹香著衣。蘭釵委墜垂雲發，", "太平天子駐雲車，龍爐勃鬱雙蟠拏。宮中近臣抱扇立，", "我亦為君長歎息，緘情遠寄愁無色。莫沾香夢綠楊絲。", "千里春風正無力。"]'),
('yuding-5','遐水謠','溫庭筠','唐','御定全唐诗','yuding','','[]','天兵九月渡遐水，馬踏沙鳴驚雁起。殺氣空高萬里情，',48,'御定全唐詩/json/575.json','["天兵九月渡遐水，馬踏沙鳴驚雁起。殺氣空高萬里情，", "犀帶鼠裘無暖色，清光炯冷黃金鞍。虜塵如霧昏亭障，"]'),
('yuding-6','曉仙謠','溫庭筠','唐','御定全唐诗','yuding','','[]','玉妃喚月歸海宮，月色澹白涵春空。銀河欲轉星靨靨，',72,'御定全唐詩/json/575.json','["玉妃喚月歸海宮，月色澹白涵春空。銀河欲轉星靨靨，", "綺閣空傳唱漏聲，網軒未辨淩雲字。遙遙珠帳連湘煙，", "秦王女騎紅尾鳳，半空回首晨雞弄。霧蓋狂塵億兆家，"]'),
('yuding-7','錦城曲','溫庭筠','唐','御定全唐诗','yuding','','[]','蜀山攢黛留晴雪，簝筍蕨芽縈九折。江風吹巧剪霞綃，',48,'御定全唐詩/json/575.json','["蜀山攢黛留晴雪，簝筍蕨芽縈九折。江風吹巧剪霞綃，", "巴水漾情情不盡，文君織得春機紅。怨魄未歸芳草死，"]'),
('yuding-8','生禖屏風歌','溫庭筠','唐','御定全唐诗','yuding','','[]','玉墀暗接昆侖井，井上無人金索冷。畫壁陰森九子堂，',40,'御定全唐詩/json/575.json','["玉墀暗接昆侖井，井上無人金索冷。畫壁陰森九子堂，", "宜男漫作後庭草，不似櫻桃千子紅。"]'),
('yuding-9','嘲春風','溫庭筠','唐','御定全唐诗','yuding','','[]','春風何處好，別殿饒芳草。苒嫋轉鸞旗，萎蕤吹雉葆。',48,'御定全唐詩/json/575.json','["春風何處好，別殿饒芳草。苒嫋轉鸞旗，萎蕤吹雉葆。", "揚芳曆九門，澹蕩入蘭蓀。爭奈白團扇，時時偷主恩。"]'),
('yuding-10','舞衣曲','溫庭筠','唐','御定全唐诗','yuding','','[]','藕腸纖縷抽輕春，煙機漠漠嬌娥嚬。金梭淅瀝透空薄，',48,'御定全唐詩/json/575.json','["藕腸纖縷抽輕春，煙機漠漠嬌娥嚬。金梭淅瀝透空薄，", "蟬衫麟帶壓愁香，偷得鶯簧鎖金縷。管含蘭氣嬌語悲，"]'),
('yuding-11','張靜婉採蓮歌','溫庭筠','唐','御定全唐诗','yuding','','[]','蘭膏墜發紅玉春，燕釵拖頸拋盤雲。城邊楊柳向嬌晚，',88,'御定全唐詩/json/575.json','["蘭膏墜發紅玉春，燕釵拖頸拋盤雲。城邊楊柳向嬌晚，", "掌中無力舞衣輕，剪斷鮫綃破春碧。抱月飄煙一尺腰，", "鸂鶒交交塘水滿，綠芒如粟蓮莖短。一夜西風送雨來，", "郎心似月月未缺，十五十六清光圓。"]'),
('yuding-12','湘宮人歌','溫庭筠','唐','御定全唐诗','yuding','','[]','池塘芳草濕，夜半東風起。生綠畫羅屏，金壺貯春水。',48,'御定全唐詩/json/575.json','["池塘芳草濕，夜半東風起。生綠畫羅屏，金壺貯春水。", "黃粉楚宮人，芳花玉刻鱗。娟娟照棋燭，不語兩含嚬。"]'),
('yuding-13','黃曇子歌','溫庭筠','唐','御定全唐诗','yuding','','[]','參差綠蒲短，搖豔雲塘滿。紅瀲蕩融融，鶯翁鸂鶒暖。',48,'御定全唐詩/json/575.json','["參差綠蒲短，搖豔雲塘滿。紅瀲蕩融融，鶯翁鸂鶒暖。", "萋芊小成路，馬上修蛾懶。羅衫嫋回風，點粉金鸝卵。"]'),
('yuding-14','觱篥歌','溫庭筠','唐','御定全唐诗','yuding','','[]','蠟煙如纛新蟾滿，門外平沙草芽短。黑頭丞相九天歸。',112,'御定全唐詩/json/575.json','["蠟煙如纛新蟾滿，門外平沙草芽短。黑頭丞相九天歸。", "夜聽飛瓊吹朔管。情遠氣調蘭蕙熏，天香瑞彩含絪縕。", "皓然纖指都揭血，日暖碧霄無片雲。含商咀征雙幽咽，", "鳴梭淅瀝金絲蕊，恨語殷勤隴頭水。漢將營前萬里沙，", "景陽宮女正愁絕，莫使此聲催斷魂。"]'),
('yuding-15','照影曲','溫庭筠','唐','御定全唐诗','yuding','','[]','景陽妝罷瓊窗暖，欲照澄明香步懶。橋上衣多抱彩雲，',40,'御定全唐詩/json/575.json','["景陽妝罷瓊窗暖，欲照澄明香步懶。橋上衣多抱彩雲，", "桃花百媚如欲語，曾為無雙今兩身。"]'),
('yuding-16','拂舞詞','溫庭筠','唐','御定全唐诗','yuding','','[]','黃河怒浪連天來，大響谹谹如殷雷。龍伯驅風不敢上，',88,'御定全唐詩/json/575.json','["黃河怒浪連天來，大響谹谹如殷雷。龍伯驅風不敢上，", "下有狂蛟鋸為尾，裂帆截棹磨霜齒。神椎鑿石塞神潭，", "腥鮮龍氣連清防，花風漾漾吹細光。疊瀾不定照天井，", "夜深銀漢通柏梁，二十八宿朝玉堂。"]'),
('yuding-17','雉場歌','溫庭筠','唐','御定全唐诗','yuding','','[]','茭葉萋萋接煙曙，雞鳴埭上梨花露。彩仗鏘鏘已合圍，',48,'御定全唐詩/json/575.json','["茭葉萋萋接煙曙，雞鳴埭上梨花露。彩仗鏘鏘已合圍，", "綠場紅跡未相接，箭發銅牙傷彩毛。麥隴桑陰小山晚，"]'),
('yuding-18','雍台歌','溫庭筠','唐','御定全唐诗','yuding','','[]','太子池南樓百尺，入窗新樹疏簾隔。黃金鋪首畫鉤陳，',40,'御定全唐詩/json/575.json','["太子池南樓百尺，入窗新樹疏簾隔。黃金鋪首畫鉤陳，", "早雁驚鳴細波起，映花鹵簿龍飛回。"]'),
('yuding-19','吳苑行','溫庭筠','唐','御定全唐诗','yuding','','[]','錦雉雙飛梅結子，平春遠綠窗中起。吳江澹畫水連空，',40,'御定全唐詩/json/575.json','["錦雉雙飛梅結子，平春遠綠窗中起。吳江澹畫水連空，", "綺戶雕楹長若此，韶光歲歲如歸來。"]'),
('yuding-20','常林歡歌','溫庭筠','唐','御定全唐诗','yuding','','[]','宜城酒熟花覆橋，沙晴綠鴨鳴咬咬。穠桑繞舍麥如尾，',40,'御定全唐詩/json/575.json','["宜城酒熟花覆橋，沙晴綠鴨鳴咬咬。穠桑繞舍麥如尾，", "錦薦金爐夢正長，東家咿喔雞鳴早。"]'),
('yuding-21','塞寒行','溫庭筠','唐','御定全唐诗','yuding','','[]','燕弓弦勁霜封瓦，樸簌寒雕睇平野，一點黃塵起雁喧，',48,'御定全唐詩/json/575.json','["燕弓弦勁霜封瓦，樸簌寒雕睇平野，一點黃塵起雁喧，", "晚出榆關逐征北，驚沙飛迸沖貂袍。心許淩煙名不滅，"]'),
('yuding-22','湖陰詞','溫庭筠','唐','御定全唐诗','yuding','','[]','祖龍黃須珊瑚鞭，鐵驄金面青連錢。虎髯拔劍欲成夢，',72,'御定全唐詩/json/575.json','["祖龍黃須珊瑚鞭，鐵驄金面青連錢。虎髯拔劍欲成夢，", "蒼黃追騎塵外歸，森索妖星陣前死。五陵愁碧春萋萋，", "白虯天子金煌鋩，高臨帝座回龍章。吳波不動楚山晚，"]'),
('yuding-23','蔣侯神歌','溫庭筠','唐','御定全唐诗','yuding','','[]','楚神鐵馬金鳴珂，夜動蛟潭生素波。商風刮水報西帝，',48,'御定全唐詩/json/575.json','["楚神鐵馬金鳴珂，夜動蛟潭生素波。商風刮水報西帝，", "巫娥傳意托悲絲，鐸語琅琅理雙鬢。湘煙刷翠湘山斜，"]'),
('yuding-24','漢皇迎春詞','溫庭筠','唐','御定全唐诗','yuding','','[]','春草芊芊晴掃煙，宮城大錦紅殷鮮。海日初融照仙掌，',64,'御定全唐詩/json/575.json','["春草芊芊晴掃煙，宮城大錦紅殷鮮。海日初融照仙掌，", "鉅公步輦迎句芒，複道掃塵燕彗長。豹尾竿前趙飛燕，", "寶馬搖環萬騎歸，恩光暗入簾櫳裏。"]'),
('yuding-0','蘭塘詞','溫庭筠','唐','御定全唐诗','yuding','','[]','塘水汪汪鳧唼喋，憶上江南木蘭楫。繡頸金須蕩倒光，',48,'御定全唐詩/json/576.json','["塘水汪汪鳧唼喋，憶上江南木蘭楫。繡頸金須蕩倒光，", "小姑歸晚紅妝淺，鏡裏芙蓉照水鮮。東溝潏潏勞回首，"]'),
('yuding-1','晚歸曲','溫庭筠','唐','御定全唐诗','yuding','','[]','格格水禽飛帶波，孤光斜起夕陽多。湖西山淺似相笑，',72,'御定全唐詩/json/576.json','["格格水禽飛帶波，孤光斜起夕陽多。湖西山淺似相笑，", "水極晴搖泛灩紅，草平春染煙綿綠。玉鞭騎馬楊叛兒，", "彎堤弱柳遙相矚，雀扇團圓掩香玉。蓮塘艇子歸不歸，"]'),
('yuding-2','故城曲','溫庭筠','唐','御定全唐诗','yuding','','[]','漠漠沙堤煙，堤西雉子斑。雉聲何角角，麥秀桑陰閑。',72,'御定全唐詩/json/576.json','["漠漠沙堤煙，堤西雉子斑。雉聲何角角，麥秀桑陰閑。", "遊絲蕩平綠，明滅時相續。白馬金絡頭，東風故城曲。", "故城殷貴嬪，曾占未來春。自從香骨化，飛作馬蹄塵。"]'),
('yuding-3','昆明池水戰詞','溫庭筠','唐','御定全唐诗','yuding','','[]','汪汪積水光連空，重疊細紋晴漾紅。赤帝龍孫鱗甲怒，',96,'御定全唐詩/json/576.json','["汪汪積水光連空，重疊細紋晴漾紅。赤帝龍孫鱗甲怒，", "雷吼濤驚白石山，石鯨眼裂蟠蛟死。溟池海浦俱喧豗。", "青幟白旌相次來。箭羽槍纓三百萬，踏翻西海生塵埃。", "茂陵仙去菱花老，唼唼遊魚近煙島。渺莽殘陽釣艇歸，"]'),
('yuding-4','謝公墅歌','溫庭筠','唐','御定全唐诗','yuding','','[]','朱雀航南繞香陌，謝郎東墅連春碧。鳩眠高柳日方融，',48,'御定全唐詩/json/576.json','["朱雀航南繞香陌，謝郎東墅連春碧。鳩眠高柳日方融，", "四座無喧梧竹靜，金蟬玉柄俱持頤。對局含情見千里，"]'),
('yuding-5','罩魚歌','溫庭筠','唐','御定全唐诗','yuding','','[]','朝罩罩城南，暮罩罩城西。兩漿鳴幽幽，蓮子相高低。',88,'御定全唐詩/json/576.json','["朝罩罩城南，暮罩罩城西。兩漿鳴幽幽，蓮子相高低。", "持罩入深水，金鱗大如手。魚尾迸圓波，千珠落湘藕。", "風颸颸，雨離離，菱尖茭刺鸂鶒飛。水連網眼白如影，", "悠溶杳若去無窮，五色澄潭鴨頭綠。"]'),
('yuding-6','春洲曲','溫庭筠','唐','御定全唐诗','yuding','','[]','韶光染色如蛾翠，綠濕紅鮮水容媚。蘇小慵多蘭渚閑，',40,'御定全唐詩/json/576.json','["韶光染色如蛾翠，綠濕紅鮮水容媚。蘇小慵多蘭渚閑，", "門外平橋連柳堤，歸來晚樹黃鶯啼。"]'),
('yuding-7','台城曉朝曲','溫庭筠','唐','御定全唐诗','yuding','','[]','司馬門前火千炬，闌幹星斗天將曙。朱網龕鬖丞相車，',40,'御定全唐詩/json/576.json','["司馬門前火千炬，闌幹星斗天將曙。朱網龕鬖丞相車，", "大江斂勢避辰極，兩闕深嚴煙翠濃。"]'),
('yuding-8','走馬樓三更曲','溫庭筠','唐','御定全唐诗','yuding','','[]','春姿暖氣昏神沼，李樹拳枝紫芽小。玉皇夜入未央宮，',40,'御定全唐詩/json/576.json','["春姿暖氣昏神沼，李樹拳枝紫芽小。玉皇夜入未央宮，", "簾間清唱報寒點，丙舍無人遺燼香。"]'),
('yuding-9','達摩支曲','溫庭筠','唐','御定全唐诗','yuding','','[]','搗麝成塵香不滅，拗蓮作寸絲難絕。紅淚文姬洛水春，',48,'御定全唐詩/json/576.json','["搗麝成塵香不滅，拗蓮作寸絲難絕。紅淚文姬洛水春，", "舊臣頭鬢霜華早，可惜雄心醉中老。萬古春歸夢不歸，"]'),
('yuding-10','陽春曲','溫庭筠','唐','御定全唐诗','yuding','','[]','雲母空窗曉煙薄，香昏龍氣凝暉閣。霏霏霧雨杏花天，',40,'御定全唐詩/json/576.json','["雲母空窗曉煙薄，香昏龍氣凝暉閣。霏霏霧雨杏花天，", "廄馬何能齧芳草，路人不敢隨流塵。"]'),
('yuding-11','湘東宴曲','溫庭筠','唐','御定全唐诗','yuding','','[]','湘東夜宴金貂人，楚女含情嬌翠嚬。玉管將吹插鈿帶，',48,'御定全唐詩/json/576.json','["湘東夜宴金貂人，楚女含情嬌翠嚬。玉管將吹插鈿帶，", "萬戶沉沉碧樹圓，雲飛雨散知何處。欲上香車俱脈脈，"]'),
('yuding-12','東郊行','溫庭筠','唐','御定全唐诗','yuding','','[]','鬥雞台下東西道，柳覆班騅蝶縈草。坱靄韶容鎖澹愁，',48,'御定全唐詩/json/576.json','["鬥雞台下東西道，柳覆班騅蝶縈草。坱靄韶容鎖澹愁，", "王孫騎馬有歸意，林彩著空如細塵。安得人生各相守，"]'),
('yuding-13','水仙謠','溫庭筠','唐','御定全唐诗','yuding','','[]','水客夜騎紅鯉魚，赤鸞雙鶴蓬瀛書。輕塵不起雨新霽，',40,'御定全唐詩/json/576.json','["水客夜騎紅鯉魚，赤鸞雙鶴蓬瀛書。輕塵不起雨新霽，", "夜深天碧亂山姿，光碎平波滿船月。"]'),
('yuding-14','東峰歌','溫庭筠','唐','御定全唐诗','yuding','','[]','錦礫潺湲玉溪水，曉來微雨藤花紫。冉冉山雞紅尾長，',40,'御定全唐詩/json/576.json','["錦礫潺湲玉溪水，曉來微雨藤花紫。冉冉山雞紅尾長，", "陽崖一夢伴雲根，仙菌靈芝夢魂裏。"]'),
('yuding-15','會昌丙寅豐歲歌','溫庭筠','唐','御定全唐诗','yuding','','[]','丙寅歲，休牛馬，風如吹煙，日如渥赭。九重天子調天下，',51,'御定全唐詩/json/576.json','["丙寅歲，休牛馬，風如吹煙，日如渥赭。九重天子調天下，", "zv茸單衣麥田路，村南娶婦桃花紅。新姑車右及門柱，"]'),
('yuding-16','碌碌古詞','溫庭筠','唐','御定全唐诗','yuding','','[]','左亦不碌碌，右亦不碌碌。野草自根肥，羸牛生健犢。',72,'御定全唐詩/json/576.json','["左亦不碌碌，右亦不碌碌。野草自根肥，羸牛生健犢。", "融蠟作杏蒂，男兒不戀家。春風破紅意，女頰如桃花。", "忠言未見信，巧語翻咨嗟。一鞘無兩刃，徒勞油壁車。"]'),
('yuding-17','春野行','溫庭筠','唐','御定全唐诗','yuding','','[]','草淺淺，春如剪。花壓李娘愁，饑蠶欲成繭。',44,'御定全唐詩/json/576.json','["草淺淺，春如剪。花壓李娘愁，饑蠶欲成繭。", "東城年少氣堂堂，金丸驚起雙鴛鴦。含羞更問衛公子，"]'),
('yuding-18','醉歌','溫庭筠','唐','御定全唐诗','yuding','','[]','簷柳初黃燕新乳，曉碧芊綿過微雨。樹色深含台榭情，',120,'御定全唐詩/json/576.json','["簷柳初黃燕新乳，曉碧芊綿過微雨。樹色深含台榭情，", "入門下馬問誰在，降階握手登華堂。臨邛美人連山眉，", "勸君莫惜金樽酒，年少須臾如覆手。辛勤到老慕簞瓢，", "阿耋光顏不識字，指麾豪俊如驅羊。天犀壓斷朱鼴鼠，", "駑馬垂頭搶暝塵，驊騮一日行千里。但有沉冥醉客家，"]'),
('yuding-19','江南曲','溫庭筠','唐','御定全唐诗','yuding','','[]','妾家白蘋浦，日上芙蓉楫。軋軋搖槳聲，移舟入茭葉。',240,'御定全唐詩/json/576.json','["妾家白蘋浦，日上芙蓉楫。軋軋搖槳聲，移舟入茭葉。", "溪長茭葉深，作底難相尋。避郎郎不見，鸂鶒自浮沉。", "拾萍萍無根，採蓮蓮有子。不作浮萍生，寧為藕花死。", "岸傍騎馬郎，烏帽紫遊韁。含愁複含笑，回首問橫塘。", "妾住金陵浦，門前朱雀航。流蘇持作帳，芙蓉持作梁。", "出入金犢幰，兄弟侍中郎。前年學歌舞，定得郎相許。", "連娟眉繞山，依約腰如杵。鳳管悲若咽，鸞弦嬌欲語。", "扇薄露紅鉛，羅輕壓金縷。明月西南樓，珠簾玳瑁鉤。", "橫波巧能笑，彎蛾不識愁。花開子留樹，草長根依土。", "早聞金溝遠，底事歸郎許。不學楊白花，朝朝淚如雨。"]'),
('yuding-20','堂堂曲','溫庭筠','唐','御定全唐诗','yuding','','[]','錢唐岸上春如織，淼淼寒潮帶晴色。淮南遊客馬連嘶，',40,'御定全唐詩/json/576.json','["錢唐岸上春如織，淼淼寒潮帶晴色。淮南遊客馬連嘶，", "一曲堂堂紅燭筵，長鯨瀉酒如飛泉。"]'),
('yuding-21','惜春詞','溫庭筠','唐','御定全唐诗','yuding','','[]','百舌問花花不語，低回似恨橫塘雨。蜂爭粉蕊蝶分香，',40,'御定全唐詩/json/576.json','["百舌問花花不語，低回似恨橫塘雨。蜂爭粉蕊蝶分香，", "秦女含嚬向煙月，愁紅帶露空迢迢。"]'),
('yuding-22','春愁曲','溫庭筠','唐','御定全唐诗','yuding','','[]','紅絲穿露珠簾冷，百尺啞啞下纖綆。遠翠愁山入臥屏，',48,'御定全唐詩/json/576.json','["紅絲穿露珠簾冷，百尺啞啞下纖綆。遠翠愁山入臥屏，", "錦疊空床委墮紅，颸颸掃尾雙金鳳。蜂喧蝶駐俱悠揚，"]'),
('yuding-23','蘇小小歌','溫庭筠','唐','御定全唐诗','yuding','','[]','買蓮莫破券，買酒莫解金。酒裏春容抱離恨，',36,'御定全唐詩/json/576.json','["買蓮莫破券，買酒莫解金。酒裏春容抱離恨，", "一自檀郎逐便風，門前春水年年綠。"]'),
('yuding-24','春江花月夜詞','溫庭筠','唐','御定全唐诗','yuding','','[]','玉樹歌闌海雲黑，花庭忽作青蕪國。秦淮有水水無情，',88,'御定全唐詩/json/576.json','["玉樹歌闌海雲黑，花庭忽作青蕪國。秦淮有水水無情，", "百幅錦帆風力滿，連天展盡金芙蓉。珠翠丁星複明滅，", "漏轉霞高滄海西，頗黎枕上聞天雞。蠻弦代寫曲如語，", "後主荒宮有曉鶯，飛來只隔西江水。"]'),
('yuding-25','懊惱曲','溫庭筠','唐','御定全唐诗','yuding','','[]','藕絲作線難勝針，蕊粉染黃那得深。玉白蘭芳不相顧，',72,'御定全唐詩/json/576.json','["藕絲作線難勝針，蕊粉染黃那得深。玉白蘭芳不相顧，", "三秋庭綠盡迎霜，惟有荷花守紅死。廬江小吏朱斑輪，", "悠悠楚水流如馬，恨紫愁紅滿平野。野土千年怨不平，"]'),
('yuding-26','三洲詞','溫庭筠','唐','御定全唐诗','yuding','','[]','團圓莫作波中月，潔白莫為枝上雪。月隨波動碎潾潾，',40,'御定全唐詩/json/576.json','["團圓莫作波中月，潔白莫為枝上雪。月隨波動碎潾潾，", "門前有路輕別離，唯恐歸來舊香滅。"]'),
('yuding-0','春曉曲','溫庭筠','唐','御定全唐诗','yuding','','[]','家臨長信往來道，乳燕雙雙拂煙草。油壁車輕金犢肥，',40,'御定全唐詩/json/577.json','["家臨長信往來道，乳燕雙雙拂煙草。油壁車輕金犢肥，", "衰桃一樹近前池，似惜紅顏鏡中老。"]'),
('yuding-1','獵騎辭','溫庭筠','唐','御定全唐诗','yuding','','[]','早辭平扆殿，夕奉湘南宴。香兔抱微煙，重鱗疊輕扇。',84,'御定全唐詩/json/577.json','["早辭平扆殿，夕奉湘南宴。香兔抱微煙，重鱗疊輕扇。", "蠶饑使君馬，雁避將軍箭。寶柱惜離弦，流黃悲赤縣。", "理釵低舞鬢，換袖回歌面。晚柳未如絲，春花已如霰。", "所嗟故里曲，不及青樓宴。"]'),
('yuding-2','西州詞','溫庭筠','唐','御定全唐诗','yuding','','[]','悠悠複悠悠，昨日下西州。西州風色好，遙見武昌樓。',168,'御定全唐詩/json/577.json','["悠悠複悠悠，昨日下西州。西州風色好，遙見武昌樓。", "武昌何鬱鬱，儂家定無匹。小婦被流黃，登樓撫瑤瑟。", "朱弦繁複輕，素手直淒清。一彈三四解，掩抑似含情。", "南樓登且望，西江廣複平。艇子搖兩槳，催過石頭城。", "門前烏臼樹，慘澹天將曙。鸂鶒飛複還，郎隨早帆去。", "回頭語同伴，定複負情儂。去帆不安幅，作抵使西風。", "他日相尋索，莫作西州客。西州人不歸，春草年年碧。"]'),
('yuding-3','燒歌','溫庭筠','唐','御定全唐诗','yuding','','[]','起來望南山，山火燒山田。微紅夕如滅，短焰複相連。',192,'御定全唐詩/json/577.json','["起來望南山，山火燒山田。微紅夕如滅，短焰複相連。", "差差向岩石，冉冉淩青壁。低隨回風盡，遠照簷茅赤。", "鄰翁能楚言，倚插欲潸然。自言楚越俗，燒畬為早田。", "豆苗蟲促促，籬上花當屋。廢棧豕歸欄，廣場雞啄粟。", "新年春雨晴，處處賽神聲。持錢就人蔔，敲瓦隔林鳴。", "蔔得山上卦，歸來桑棗下。吹火向白茅，腰鐮映赬蔗。", "風驅槲葉煙，槲樹連平山。迸星拂霞外，飛燼落階前。", "仰面呻複嚏，鴉娘咒豐歲。誰知蒼翠容，盡作官家稅。"]'),
('yuding-4','長安寺','溫庭筠','唐','御定全唐诗','yuding','','[]','仁祠寫露宮，長安佳氣濃。煙樹含蔥蒨，金刹映zv茸。',97,'御定全唐詩/json/577.json','["仁祠寫露宮，長安佳氣濃。煙樹含蔥蒨，金刹映zv茸。", "繡戶香焚象，珠網玉盤龍。寶題斜翡翠，天井倒芙蓉。", "幡長回遠吹，窗虛含曉風。遊騎迷青鎖，歸鳥思華鐘。", "雲栱承跗邐，羽葆背花重。所嗟蓮社客，輕蕩不相從。"]'),
('yuding-5','和沈參軍招友生觀芙蓉池','溫庭筠','唐','御定全唐诗','yuding','','[]','桂棟坐清曉，瑤琴商鳳絲。況聞楚澤香，適與秋風期。',120,'御定全唐詩/json/577.json','["桂棟坐清曉，瑤琴商鳳絲。況聞楚澤香，適與秋風期。", "遂從棹萍客，靜嘯煙草湄。倒影回澹蕩，愁紅媚漣漪。", "湘莖久鮮澀，宿雨增離披。而我江海意，楚遊動夢思。", "北渚水雲葉，南塘煙霧枝。豈亡台榭芳，獨與鷗鳥知。", "珠墜魚迸淺，影多鳧泛遲。落英不可攀，返照昏澄陂。"]'),
('yuding-6','寓懷','溫庭筠','唐','御定全唐诗','yuding','','[]','誠足不顧得，妄矜徒有言。語斯諒未盡，隱顯何悠然。',96,'御定全唐詩/json/577.json','["誠足不顧得，妄矜徒有言。語斯諒未盡，隱顯何悠然。", "洵彼都邑盛，眷惟車馬喧。自期尊客卿，非意幹王孫。", "銜知有貞爵，處實非厚顏。苟無海岱氣，奚取壺漿恩。", "唯絲南山楊，適我松菊香。鵬鶤誠未憶，誰謂淩風翔。"]'),
('yuding-7','余昔自西濱得蘭數本，移藝於庭，亦既逾歲，而芃然蕃殖，自余遊者未始以芳草為遇矣。因悲夫物有厭常而反，不若混然者有之焉，遂寄情於此','溫庭筠','唐','御定全唐诗','yuding','','[]','寓賞本殊致，意幽非我情。吾常有流淺，外物無重輕。',120,'御定全唐詩/json/577.json','["寓賞本殊致，意幽非我情。吾常有流淺，外物無重輕。", "各言藝幽深，彼美香素莖。豈為賞者設，自保孤根生。", "易地無赤株，麗土亦同榮。賞際林壑近，泛餘煙露清。", "余懷既郁陶，爾類徒縱橫。妍蚩苟不信，寵辱何為驚。", "貞隱諒無跡，激時猶揀名。幽叢靄綠畹，豈必懷歸耕。"]'),
('yuding-8','秋日','溫庭筠','唐','御定全唐诗','yuding','','[]','爽氣變昏旦，神皋遍原隰。煙華久蕩搖，石澗仍清急。',168,'御定全唐詩/json/577.json','["爽氣變昏旦，神皋遍原隰。煙華久蕩搖，石澗仍清急。", "柳暗山犬吠，蒲荒水禽立。菊花明欲迷，棗葉光如濕。", "天籟思林嶺，車塵倦都邑。譸張夙所違，悔吝何由入。", "芳草秋可藉，幽泉曉堪汲。牧羊燒外鳴，林果雨中拾。", "複此遂閑曠，翛然脫羈縶。田收鳥雀喧，氣肅龍蛇蟄。", "佳節足豐穰，良朋阻遊集。沉機日寂寥，葆素常呼吸。", "投跡倦攸往，放懷志所執。良時有東菑，吾將事蓑笠。"]'),
('yuding-9','七夕','溫庭筠','唐','御定全唐诗','yuding','','[]','鳴機劄劄停金梭，芙蓉澹蕩生池波。神軒紅粉陳香羅，',48,'御定全唐詩/json/577.json','["鳴機劄劄停金梭，芙蓉澹蕩生池波。神軒紅粉陳香羅，", "彎橋銷盡愁奈何，天氣駘蕩雲陂阤。平明花木有秋意，"]'),
('yuding-10','酬友人','溫庭筠','唐','御定全唐诗','yuding','','[]','辭榮亦素尚，倦遊非夙心。甯複思金籍，獨此臥煙林。',72,'御定全唐詩/json/577.json','["辭榮亦素尚，倦遊非夙心。甯複思金籍，獨此臥煙林。", "閑雲無定貌，佳樹有餘陰。坐久芰荷發，釣闌茭葦深。", "遊魚自搖漾，浴鳥故浮沉。唯君清露夕，一為灑煩襟。"]'),
('yuding-11','觀舞妓','溫庭筠','唐','御定全唐诗','yuding','','[]','朔音悲嘒管，瑤踏動芳塵。總袖時增怨，聽破複含嚬。',48,'御定全唐詩/json/577.json','["朔音悲嘒管，瑤踏動芳塵。總袖時增怨，聽破複含嚬。", "凝腰倚風軟，花題照錦春。朱弦固淒緊，瓊樹亦迷人。"]'),
('yuding-12','邊笳曲','溫庭筠','唐','御定全唐诗','yuding','','[]','朔管迎秋動，雕陰雁來早。上郡隱黃雲，天山吹白草。',48,'御定全唐詩/json/577.json','["朔管迎秋動，雕陰雁來早。上郡隱黃雲，天山吹白草。", "嘶馬悲寒磧，朝陽照霜堡。江南戍客心，門外芙蓉老。"]'),
('yuding-13','經西塢偶題','溫庭筠','唐','御定全唐诗','yuding','','[]','搖搖弱柳黃鸝啼，芳草無情人自迷。日影明滅金色鯉，',40,'御定全唐詩/json/577.json','["搖搖弱柳黃鸝啼，芳草無情人自迷。日影明滅金色鯉，", "借問含嚬向何事，昔年曾到武陵溪。"]'),
('yuding-14','金虎台','溫庭筠','唐','御定全唐诗','yuding','','[]','碧草連金虎，青苔蔽石麟。皓齒芳塵起，纖腰玉樹春。',48,'御定全唐詩/json/577.json','["碧草連金虎，青苔蔽石麟。皓齒芳塵起，纖腰玉樹春。", "倚瑟紅鉛濕，分香翠黛嚬。誰言奉陵寢，相顧複沾巾。"]'),
('yuding-15','俠客行','溫庭筠','唐','御定全唐诗','yuding','','[]','欲出鴻都門，陰雲蔽城闕。寶劍黯如水，微紅濕餘血。',36,'御定全唐詩/json/577.json','["欲出鴻都門，陰雲蔽城闕。寶劍黯如水，微紅濕餘血。", "白馬夜頻驚，三更霸陵雪。"]'),
('yuding-16','詠曉','溫庭筠','唐','御定全唐诗','yuding','','[]','蟲歇紗窗靜，鴉散碧梧寒。稍驚朝佩動，猶傳清漏殘。',48,'御定全唐詩/json/577.json','["蟲歇紗窗靜，鴉散碧梧寒。稍驚朝佩動，猶傳清漏殘。", "亂珠凝燭淚，微紅上露盤。褰衣複理鬢，餘潤拂芝蘭。"]'),
('yuding-17','芙蓉','溫庭筠','唐','御定全唐诗','yuding','','[]','剌莖澹蕩碧，花片參差紅。吳歌秋水冷，湘廟夜雲空。',48,'御定全唐詩/json/577.json','["剌莖澹蕩碧，花片參差紅。吳歌秋水冷，湘廟夜雲空。", "濃豔香露裏，美人青鏡中。南樓未歸客，一夕練塘東。"]'),
('yuding-18','敕勒歌塞北','溫庭筠','唐','御定全唐诗','yuding','','[]','敕勒金fj壁，陰山無歲華。帳外風飄雪，營前月照沙。',49,'御定全唐詩/json/577.json','["敕勒金fj壁，陰山無歲華。帳外風飄雪，營前月照沙。", "羌兒吹玉管，胡姬踏錦花。卻笑江南客，梅落不歸家。"]'),
('yuding-19','邯鄲郭公詞','溫庭筠','唐','御定全唐诗','yuding','','[]','金笳悲故曲，玉座積深塵。言是邯鄲伎，不見鄴城人。',48,'御定全唐詩/json/577.json','["金笳悲故曲，玉座積深塵。言是邯鄲伎，不見鄴城人。", "青苔竟埋骨，紅粉自傷神。唯有漳河柳，還向舊營春。"]'),
('yuding-20','古意','溫庭筠','唐','御定全唐诗','yuding','','[]','莫莫複莫莫，絲蘿緣澗壑。散木無斧斤，纖莖得依託。',48,'御定全唐詩/json/577.json','["莫莫複莫莫，絲蘿緣澗壑。散木無斧斤，纖莖得依託。", "枝低浴鳥歇，根靜懸泉落。不慮見春遲，空傷致身錯。"]'),
('yuding-21','齊宮','溫庭筠','唐','御定全唐诗','yuding','','[]','白馬雜金飾，言從雕輦回。粉香隨笑度，鬢態伴愁來。',48,'御定全唐詩/json/577.json','["白馬雜金飾，言從雕輦回。粉香隨笑度，鬢態伴愁來。", "遠水斜如剪，青莎綠似裁。所恨章華日，冉冉下層台。"]'),
('yuding-22','春日','溫庭筠','唐','御定全唐诗','yuding','','[]','柳岸杏花稀，梅梁乳燕飛。美人鸞鏡笑，嘶馬雁門歸。',48,'御定全唐詩/json/577.json','["柳岸杏花稀，梅梁乳燕飛。美人鸞鏡笑，嘶馬雁門歸。", "楚宮雲影薄，台城心賞違。從來千里恨，邊色滿戎衣。"]'),
('yuding-23','詠春幡','溫庭筠','唐','御定全唐诗','yuding','','[]','閒庭見早梅，花影為誰栽。碧煙隨刃落，蟬鬢覺春來。',48,'御定全唐詩/json/577.json','["閒庭見早梅，花影為誰栽。碧煙隨刃落，蟬鬢覺春來。", "代郡嘶金勒，梵聲悲鏡臺。玉釵風不定，香步獨徘徊。"]'),
('yuding-24','陳宮詞','溫庭筠','唐','御定全唐诗','yuding','','[]','雞鳴人草草，香輦出宮花。妓語細腰轉，馬嘶金面斜。',48,'御定全唐詩/json/577.json','["雞鳴人草草，香輦出宮花。妓語細腰轉，馬嘶金面斜。", "早鶯隨彩仗，驚雉避凝笳。淅瀝湘風外，紅輪映曙霞。"]'),
('yuding-25','春日野行','溫庭筠','唐','御定全唐诗','yuding','','[]','騎馬踏煙莎，青春奈怨何。蝶翎朝粉盡，鴉背夕陽多。',48,'御定全唐詩/json/577.json','["騎馬踏煙莎，青春奈怨何。蝶翎朝粉盡，鴉背夕陽多。", "柳豔欺芳帶，山愁縈翠蛾。別情無處說，方寸是星河。"]'),
('yuding-26','詠嚬','溫庭筠','唐','御定全唐诗','yuding','','[]','毛羽斂愁翠，黛嬌攢豔春。恨容偏落淚，低態定思人。',48,'御定全唐詩/json/577.json','["毛羽斂愁翠，黛嬌攢豔春。恨容偏落淚，低態定思人。", "枕上夢隨月，扇邊歌繞塵。玉鉤鸞不住，波淺石磷磷。"]'),
('yuding-27','中書令裴公挽歌詞二首','溫庭筠','唐','御定全唐诗','yuding','','[]','王儉風華首，蕭何社稷臣。丹陽布衣客，蓮渚白頭人。',96,'御定全唐詩/json/577.json','["王儉風華首，蕭何社稷臣。丹陽布衣客，蓮渚白頭人。", "銘勒燕山暮，碑沉漢水春。從今虛醉飽，無複汙車茵。", "箭下妖星落，風前殺氣回。國香荀令去，樓月庾公來。", "玉璽終無慮，金縢意不開。空嗟薦賢路，芳草滿燕台。"]'),
('yuding-28','唐莊恪太子挽歌詞二首','溫庭筠','唐','御定全唐诗','yuding','','[]','疊鼓辭宮殿，悲笳降杳冥。影離雲外日，光滅火前星。',96,'御定全唐詩/json/577.json','["疊鼓辭宮殿，悲笳降杳冥。影離雲外日，光滅火前星。", "鄴客瞻秦苑，商公下漢庭。依依陵樹色，空繞古原青。", "東府虛容衛，西園寄夢思。鳳懸吹曲夜，雞斷問安時。", "塵陌都人恨，霜郊賵馬悲。唯餘埋璧地，煙草近丹墀。"]'),
('yuding-29','秘書劉尚書挽歌詞二首','溫庭筠','唐','御定全唐诗','yuding','','[]','王筆活鸞鳳，謝詩生芙蓉。學筵開絳帳，談柄發洪鐘。',96,'御定全唐詩/json/577.json','["王筆活鸞鳳，謝詩生芙蓉。學筵開絳帳，談柄發洪鐘。", "粉署見飛鵩，玉山猜臥龍。遺風麗清韻，蕭散九原松。", "麈尾近良玉，鶴裘吹素絲。壞陵殷浩謫，春墅謝安棋。", "京口貴公子，襄陽諸女兒。折花兼踏月，多唱柳郎詞。"]'),
('yuding-30','太子西池二首','溫庭筠','唐','御定全唐诗','yuding','','[]','梨花雪壓枝，鶯囀柳如絲。懶逐妝成曉，春融夢覺遲。',96,'御定全唐詩/json/577.json','["梨花雪壓枝，鶯囀柳如絲。懶逐妝成曉，春融夢覺遲。", "鬢輕全作影，嚬淺未成眉。莫信張公子，窗間斷暗期。", "花紅蘭紫莖，愁草雨新晴。柳占三春色，鶯偷百鳥聲。", "日長嫌輦重，風暖覺衣輕。薄暮香塵起，長楊落照明。"]'),
('yuding-31','西陵道士茶歌','溫庭筠','唐','御定全唐诗','yuding','','[]','乳竇濺濺通石脈，綠塵愁草春江色。澗花入井水味香，',40,'御定全唐詩/json/577.json','["乳竇濺濺通石脈，綠塵愁草春江色。澗花入井水味香，", "疏香皓齒有餘味，更覺鶴心通杳冥。"]'),
('yuding-32','過西堡塞北','溫庭筠','唐','御定全唐诗','yuding','','[]','淺草幹河闊，叢棘廢城高。白馬犀匕首，黑裘金佩刀。',48,'御定全唐詩/json/577.json','["淺草幹河闊，叢棘廢城高。白馬犀匕首，黑裘金佩刀。", "霜清澈兔目，風急吹雕毛。一經何用厄，日暮涕沾袍。"]'),
('yuding-0','送李億東歸','溫庭筠','唐','御定全唐诗','yuding','','[]','黃山遠隔秦樹，紫禁斜通渭城。別路青青柳弱，',35,'御定全唐詩/json/578.json','["黃山遠隔秦樹，紫禁斜通渭城。別路青青柳弱，", "灞上金樽未飲，宴歌已有餘聲。"]'),
('yuding-1','開聖寺','溫庭筠','唐','御定全唐诗','yuding','','[]','路分溪石夾煙叢，十裏蕭蕭古樹風。出寺馬嘶秋色裏，',40,'御定全唐詩/json/578.json','["路分溪石夾煙叢，十裏蕭蕭古樹風。出寺馬嘶秋色裏，", "猶有南朝舊碑在，恥將興廢問休公。"]'),
('yuding-2','贈蜀府將','溫庭筠','唐','御定全唐诗','yuding','','[]','十年分散劍關秋，萬事皆隨錦水流。志氣已曾明漢節，',40,'御定全唐詩/json/578.json','["十年分散劍關秋，萬事皆隨錦水流。志氣已曾明漢節，", "今日逢君倍惆悵，灌嬰韓信盡封侯。"]'),
('yuding-3','西江貽釣叟騫生','溫庭筠','唐','御定全唐诗','yuding','','[]','晴江如鏡月如鉤，泛灩蒼茫送客愁。衣淚潛生竹枝曲，',40,'御定全唐詩/json/578.json','["晴江如鏡月如鉤，泛灩蒼茫送客愁。衣淚潛生竹枝曲，", "昨日歡娛竟何在，一枝梅謝楚江頭。"]'),
('yuding-4','寄清源寺僧','溫庭筠','唐','御定全唐诗','yuding','','[]','石路無塵竹徑開，昔年曾伴戴顒來。窗間半偈聞鐘後，',40,'御定全唐詩/json/578.json','["石路無塵竹徑開，昔年曾伴戴顒來。窗間半偈聞鐘後，", "白蓮社裏如相問，為說遊人是姓雷。"]'),
('yuding-5','重游圭峰宗密禪師精廬','溫庭筠','唐','御定全唐诗','yuding','','[]','百尺青崖三尺墳，微言已絕杳難聞。戴顒今日稱居士，',40,'御定全唐詩/json/578.json','["百尺青崖三尺墳，微言已絕杳難聞。戴顒今日稱居士，", "故山弟子空回首，蔥嶺唯應見宋雲。"]'),
('yuding-6','題李處士幽居','溫庭筠','唐','御定全唐诗','yuding','','[]','水玉簪頭白角巾，瑤琴寂曆拂輕塵。濃陰似帳紅薇晚，',40,'御定全唐詩/json/578.json','["水玉簪頭白角巾，瑤琴寂曆拂輕塵。濃陰似帳紅薇晚，", "南山自是忘年友，谷口徒稱鄭子真。"]'),
('yuding-7','利州南渡','溫庭筠','唐','御定全唐诗','yuding','','[]','澹然空水對斜暉，曲島蒼茫接翠微，波上馬嘶看棹去，',40,'御定全唐詩/json/578.json','["澹然空水對斜暉，曲島蒼茫接翠微，波上馬嘶看棹去，", "誰解乘舟尋範蠡，五湖煙水獨忘機。"]'),
('yuding-8','贈李將軍','溫庭筠','唐','御定全唐诗','yuding','','[]','誰言荀羨愛功勳，年少登壇眾所聞。曾以能書稱內史，',40,'御定全唐詩/json/578.json','["誰言荀羨愛功勳，年少登壇眾所聞。曾以能書稱內史，", "不學龍驤畫山水，醉鄉無跡似閑雲。"]'),
('yuding-9','寒食日作','溫庭筠','唐','御定全唐诗','yuding','','[]','紅深綠暗徑相交，抱暖含芳披紫袍。彩索平時牆婉娩，',40,'御定全唐詩/json/578.json','["紅深綠暗徑相交，抱暖含芳披紫袍。彩索平時牆婉娩，", "自有玉樓春意在，不能騎馬度煙郊。"]'),
('yuding-10','李羽處士寄新醞走筆戲酬','溫庭筠','唐','御定全唐诗','yuding','','[]','高談有伴還成藪，沉醉無期即是鄉。已恨流鶯欺謝客，',40,'御定全唐詩/json/578.json','["高談有伴還成藪，沉醉無期即是鄉。已恨流鶯欺謝客，", "所恨玳筵紅燭夜，草玄寥落近回塘。"]'),
('yuding-11','郊居秋日有懷一二知己','溫庭筠','唐','御定全唐诗','yuding','','[]','稻田鳧雁滿晴沙，釣渚歸來一徑斜。門帶果林招邑吏，',40,'御定全唐詩/json/578.json','["稻田鳧雁滿晴沙，釣渚歸來一徑斜。門帶果林招邑吏，", "自笑謾懷經濟策，不將心事許煙霞。"]'),
('yuding-12','題友人池亭','溫庭筠','唐','御定全唐诗','yuding','','[]','月榭風亭繞曲池，粉垣回互瓦參差。侵簾片白搖翻影，',40,'御定全唐詩/json/578.json','["月榭風亭繞曲池，粉垣回互瓦參差。侵簾片白搖翻影，", "山翁醉後如相憶，羽扇清樽我自知。"]'),
('yuding-13','南湖','溫庭筠','唐','御定全唐诗','yuding','','[]','湖上微風入檻涼，翻翻菱荇滿回塘。野船著岸偎春草，',40,'御定全唐詩/json/578.json','["湖上微風入檻涼，翻翻菱荇滿回塘。野船著岸偎春草，", "飄然篷艇東歸客，盡日相看憶楚鄉。"]'),
('yuding-14','贈袁司錄','溫庭筠','唐','御定全唐诗','yuding','','[]','一朝辭滿有心期，花發楊園雪壓枝。劉尹故人諳往事，',40,'御定全唐詩/json/578.json','["一朝辭滿有心期，花發楊園雪壓枝。劉尹故人諳往事，", "記得襄陽耆舊語，不堪風景峴山碑。"]'),
('yuding-15','題西明寺僧院','溫庭筠','唐','御定全唐诗','yuding','','[]','曾識匡山遠法師，低松片石對前墀。為尋名畫來過院，',40,'御定全唐詩/json/578.json','["曾識匡山遠法師，低松片石對前墀。為尋名畫來過院，", "自知終有張華識，不向滄洲理釣絲。"]'),
('yuding-16','偶題','溫庭筠','唐','御定全唐诗','yuding','','[]','微風和暖日鮮明，草色迷人向渭城。吳客捲簾閑不語，',40,'御定全唐詩/json/578.json','["微風和暖日鮮明，草色迷人向渭城。吳客捲簾閑不語，", "自恨青樓無近信，不將心事許卿卿。"]'),
('yuding-17','寄湘陰閻少府乞釣輪子','溫庭筠','唐','御定全唐诗','yuding','','[]','釣輪形與月輪同，獨繭和煙影似空。若向三湘逢雁信，',40,'御定全唐詩/json/578.json','["釣輪形與月輪同，獨繭和煙影似空。若向三湘逢雁信，", "終日垂鉤還有意，尺書多在錦鱗中。"]'),
('yuding-18','哭王元裕','溫庭筠','唐','御定全唐诗','yuding','','[]','聞說蕭郎逐逝川，伯牙因此絕清弦。柳邊猶憶青驄影，',40,'御定全唐詩/json/578.json','["聞說蕭郎逐逝川，伯牙因此絕清弦。柳邊猶憶青驄影，", "他時若到相尋處，碧樹紅樓自宛然。"]'),
('yuding-19','法雲寺雙檜','溫庭筠','唐','御定全唐诗','yuding','','[]','晉朝名輩此離群，想對濃陰去住分。題處尚尋王內史，',40,'御定全唐詩/json/578.json','["晉朝名輩此離群，想對濃陰去住分。題處尚尋王內史，", "一下南台到人世，曉泉清籟更難聞。"]'),
('yuding-20','送陳嘏之侯官兼簡李常侍','溫庭筠','唐','御定全唐诗','yuding','','[]','縱得步兵無綠蟻，不緣句漏有丹砂。殷勤為報同袍友，',40,'御定全唐詩/json/578.json','["縱得步兵無綠蟻，不緣句漏有丹砂。殷勤為報同袍友，", "梅仙自是青雲客，莫羨相如卻到家。"]'),
('yuding-21','春日野行','溫庭筠','唐','御定全唐诗','yuding','','[]','雨漲西塘金堤斜，碧草芊芊晴吐芽。野岸明媚山芍藥，',40,'御定全唐詩/json/578.json','["雨漲西塘金堤斜，碧草芊芊晴吐芽。野岸明媚山芍藥，", "何事輕橈句溪客，綠萍方好不歸家。"]'),
('yuding-22','溪上行','溫庭筠','唐','御定全唐诗','yuding','','[]','綠塘漾漾煙濛濛，張翰此來情不窮。雪羽褵褷立倒影，',40,'御定全唐詩/json/578.json','["綠塘漾漾煙濛濛，張翰此來情不窮。雪羽褵褷立倒影，", "心羨夕陽波上客，片時歸夢釣船中。"]'),
('yuding-23','投翰林蕭舍人','溫庭筠','唐','御定全唐诗','yuding','','[]','人間鵷鷺杳難從，獨恨金扉直九重。萬象晚歸仁壽鏡，',40,'御定全唐詩/json/578.json','["人間鵷鷺杳難從，獨恨金扉直九重。萬象晚歸仁壽鏡，", "每過朱門愛庭樹，一枝何日許相容。"]'),
('yuding-24','春日偶作','溫庭筠','唐','御定全唐诗','yuding','','[]','西園一曲豔陽歌，擾擾車塵負薜蘿。自欲放懷猶未得，',40,'御定全唐詩/json/578.json','["西園一曲豔陽歌，擾擾車塵負薜蘿。自欲放懷猶未得，", "釣渚別來應更好，春風還為起微波。"]'),
('yuding-25','春暮宴罷寄宋壽先輩','溫庭筠','唐','御定全唐诗','yuding','','[]','斜掩朱門花外鐘，曉鶯時節好相逢。窗間桃蕊宿妝在，',40,'御定全唐詩/json/578.json','["斜掩朱門花外鐘，曉鶯時節好相逢。窗間桃蕊宿妝在，", "誰憐芳草生三徑，參佐橋西陸士龍。"]'),
('yuding-26','馬嵬驛','溫庭筠','唐','御定全唐诗','yuding','','[]','穆滿曾為物外游，六龍經此暫淹留。返魂無驗青煙滅，',40,'御定全唐詩/json/578.json','["穆滿曾為物外游，六龍經此暫淹留。返魂無驗青煙滅，", "甘泉不復重相見，誰道文成是故侯。"]'),
('yuding-27','和道溪君別業','溫庭筠','唐','御定全唐诗','yuding','','[]','積潤初銷碧草新，鳳陽晴日帶雕輪。風飄弱柳平橋晚，',40,'御定全唐詩/json/578.json','["積潤初銷碧草新，鳳陽晴日帶雕輪。風飄弱柳平橋晚，", "花房透露紅珠落，蛺蝶雙飛護粉塵。"]'),
('yuding-28','奉天西佛寺','溫庭筠','唐','御定全唐诗','yuding','','[]','憶昔狂童犯順年，玉虯閒暇出甘泉。宗臣欲舞千鈞劍，',40,'御定全唐詩/json/578.json','["憶昔狂童犯順年，玉虯閒暇出甘泉。宗臣欲舞千鈞劍，", "至今南頓諸耆舊，猶指榛蕪作弄田。"]'),
('yuding-29','題望苑驛','溫庭筠','唐','御定全唐诗','yuding','','[]','弱柳千條杏一枝，半含春雨半垂絲。景陽寒井人難到，',40,'御定全唐詩/json/578.json','["弱柳千條杏一枝，半含春雨半垂絲。景陽寒井人難到，", "分明十二樓前月，不向西陵照盛姬。"]'),
('yuding-30','寄分司元庶子兼呈元處士','溫庭筠','唐','御定全唐诗','yuding','','[]','閉門高臥莫長嗟，水木凝暉屬謝家。緱嶺參差殘曉雪，',40,'御定全唐詩/json/578.json','["閉門高臥莫長嗟，水木凝暉屬謝家。緱嶺參差殘曉雪，", "月榭知君還悵望，碧霄煙闊雁行斜。"]'),
('yuding-31','題柳','溫庭筠','唐','御定全唐诗','yuding','','[]','楊柳千條拂面絲，綠煙金穗不勝吹。香隨靜婉歌塵起，',40,'御定全唐詩/json/578.json','["楊柳千條拂面絲，綠煙金穗不勝吹。香隨靜婉歌塵起，", "千門九陌花如雪，飛過宮牆兩自知。"]'),
('yuding-32','和友人悼亡','溫庭筠','唐','御定全唐诗','yuding','','[]','玉貌潘郎淚滿衣，畫羅輕鬢雨霏微。紅蘭委露愁難盡，',40,'御定全唐詩/json/578.json','["玉貌潘郎淚滿衣，畫羅輕鬢雨霏微。紅蘭委露愁難盡，", "春來多少傷心事，碧草侵階粉蝶飛。"]'),
('yuding-33','李羽處士故里','溫庭筠','唐','御定全唐诗','yuding','','[]','柳不成絲草帶煙，海槎東去鶴歸天。愁腸斷處春何限，',40,'御定全唐詩/json/578.json','["柳不成絲草帶煙，海槎東去鶴歸天。愁腸斷處春何限，", "終知此恨銷難盡，辜負南華第一篇。"]'),
('yuding-34','卻經商山寄昔同行人','溫庭筠','唐','御定全唐诗','yuding','','[]','曾道逍遙第一篇，爾來無處不恬然。便同南郭能忘象，',24,'御定全唐詩/json/578.json','["曾道逍遙第一篇，爾來無處不恬然。便同南郭能忘象，"]'),
('yuding-35','池塘七夕','溫庭筠','唐','御定全唐诗','yuding','','[]','月出西南露氣秋，綺羅河漢在斜溝。楊家繡作鴛鴦幔，',40,'御定全唐詩/json/578.json','["月出西南露氣秋，綺羅河漢在斜溝。楊家繡作鴛鴦幔，", "萬家砧杵三篙水，一夕橫塘似舊遊。"]'),
('yuding-36','偶游','溫庭筠','唐','御定全唐诗','yuding','','[]','曲巷斜臨一水間，小門終日不開關。紅珠鬥帳櫻桃熟，',40,'御定全唐詩/json/578.json','["曲巷斜臨一水間，小門終日不開關。紅珠鬥帳櫻桃熟，", "與君便是鴛鴦侶，休向人間覓往還。"]'),
('yuding-37','寄河南杜少尹','溫庭筠','唐','御定全唐诗','yuding','','[]','十載歸來鬢未凋，玳簪珠履見常僚。豈關名利分榮路，',40,'御定全唐詩/json/578.json','["十載歸來鬢未凋，玳簪珠履見常僚。豈關名利分榮路，", "夕陽亭畔山如畫，應念田歌正寂寥。"]'),
('yuding-38','贈知音','溫庭筠','唐','御定全唐诗','yuding','','[]','翠羽花冠碧樹雞，未明先向短牆啼。窗間謝女青蛾斂，',40,'御定全唐詩/json/578.json','["翠羽花冠碧樹雞，未明先向短牆啼。窗間謝女青蛾斂，", "景陽宮裏鐘初動，不語垂鞭上柳堤。"]'),
('yuding-39','過陳琳墓','溫庭筠','唐','御定全唐诗','yuding','','[]','曾於青史見遺文，今日飄蓬過古墳。詞客有靈應識我，',40,'御定全唐詩/json/578.json','["曾於青史見遺文，今日飄蓬過古墳。詞客有靈應識我，", "莫怪臨風倍惆悵，欲將書劍學從軍。"]'),
('yuding-40','題崔公池亭舊遊','溫庭筠','唐','御定全唐诗','yuding','','[]','皎鏡方塘菡萏秋，此來重見採蓮舟。誰能不逐當年樂，',40,'御定全唐詩/json/578.json','["皎鏡方塘菡萏秋，此來重見採蓮舟。誰能不逐當年樂，", "簷前依舊青山色，盡日無人獨上樓。"]'),
('yuding-41','回中作','溫庭筠','唐','御定全唐诗','yuding','','[]','蒼莽寒空遠色愁，嗚嗚戍角上高樓。吳姬怨思吹雙管，',40,'御定全唐詩/json/578.json','["蒼莽寒空遠色愁，嗚嗚戍角上高樓。吳姬怨思吹雙管，", "夜來霜重西風起，隴水無聲凍不流。"]'),
('yuding-42','西江上送漁父','溫庭筠','唐','御定全唐诗','yuding','','[]','卻逐嚴光向若耶，釣輪菱棹寄年華。三秋梅雨愁楓葉，',40,'御定全唐詩/json/578.json','["卻逐嚴光向若耶，釣輪菱棹寄年華。三秋梅雨愁楓葉，", "白蘋風起樓船暮，江燕雙雙五兩斜。"]'),
('yuding-43','經故秘書崔監揚州南塘舊居','溫庭筠','唐','御定全唐诗','yuding','','[]','昔年曾識范安成，松竹風姿鶴性情。西掖曙河橫漏響，',40,'御定全唐詩/json/578.json','["昔年曾識范安成，松竹風姿鶴性情。西掖曙河橫漏響，", "千頃水流通故墅，至今留得謝公名。"]'),
('yuding-44','七夕','溫庭筠','唐','御定全唐诗','yuding','','[]','鵲歸燕去兩悠悠，青瑣西南月似鉤。天上歲時星右轉，',40,'御定全唐詩/json/578.json','["鵲歸燕去兩悠悠，青瑣西南月似鉤。天上歲時星右轉，", "蘇小橫塘通桂楫，未應清淺隔牽牛。"]'),
('yuding-45','題韋籌博士草堂','溫庭筠','唐','御定全唐诗','yuding','','[]','玄晏先生已白頭，不隨鵷鷺狎群鷗。元卿謝免開三徑，',40,'御定全唐詩/json/578.json','["玄晏先生已白頭，不隨鵷鷺狎群鷗。元卿謝免開三徑，", "滄浪未濯塵纓在，野水無情處處流。"]'),
('yuding-46','和友人題壁','溫庭筠','唐','御定全唐诗','yuding','','[]','沖尚猶來出範圍，肯將經世作風徽。三台位缺嚴陵臥，',40,'御定全唐詩/json/578.json','["沖尚猶來出範圍，肯將經世作風徽。三台位缺嚴陵臥，", "西州未有看棋暇，澗戶何由得掩扉。"]'),
('yuding-47','春日將欲東歸寄新及第苗紳先輩','溫庭筠','唐','御定全唐诗','yuding','','[]','幾年辛苦與君同，得喪悲歡儘是空。猶喜故人先折桂，',40,'御定全唐詩/json/578.json','["幾年辛苦與君同，得喪悲歡儘是空。猶喜故人先折桂，", "知有杏園無路入，馬前惆悵滿枝紅。"]'),
('yuding-48','經李征君故居','溫庭筠','唐','御定全唐诗','yuding','','[]','露濃煙重草萋萋，樹映闌幹柳拂堤。一院落花無客醉，',40,'御定全唐詩/json/578.json','["露濃煙重草萋萋，樹映闌幹柳拂堤。一院落花無客醉，", "惆悵羸驂往來慣，每經門巷亦長嘶。"]'),
('yuding-49','送崔郎中赴幕','溫庭筠','唐','御定全唐诗','yuding','','[]','一別黔巫似斷弦，故交東去更淒然。心遊目送三千里，',40,'御定全唐詩/json/578.json','["一別黔巫似斷弦，故交東去更淒然。心遊目送三千里，", "相思休話長安遠，江月隨人處處圓。"]'),
('yuding-50','經舊遊','溫庭筠','唐','御定全唐诗','yuding','','[]','珠箔金鉤對彩橋，昔年於此見嬌嬈。香燈悵望飛瓊鬢，',40,'御定全唐詩/json/578.json','["珠箔金鉤對彩橋，昔年於此見嬌嬈。香燈悵望飛瓊鬢，", "壞牆經雨蒼苔遍，拾得當時舊翠翹。"]'),
('yuding-51','老君廟','溫庭筠','唐','御定全唐诗','yuding','','[]','紫氣氤氳捧半岩，蓮峰仙掌共巉巉。廟前晚色連寒水，',40,'御定全唐詩/json/578.json','["紫氣氤氳捧半岩，蓮峰仙掌共巉巉。廟前晚色連寒水，", "自憐金骨無人識，知有飛龜在石函。"]'),
('yuding-52','過五丈原','溫庭筠','唐','御定全唐诗','yuding','','[]','鐵馬雲雕久絕塵，柳陰高壓漢營春。天晴殺氣屯關右，',40,'御定全唐詩/json/578.json','["鐵馬雲雕久絕塵，柳陰高壓漢營春。天晴殺氣屯關右，", "象床錦帳無言語，從此譙周是老臣。"]'),
('yuding-53','和友人傷歌姬','溫庭筠','唐','御定全唐诗','yuding','','[]','月缺花殘莫愴然，花須終發月終圓。更能何事銷芳念，',40,'御定全唐詩/json/578.json','["月缺花殘莫愴然，花須終發月終圓。更能何事銷芳念，", "王孫莫學多情客，自古多情損少年。"]'),
('yuding-54','山中與諸道友夜坐聞邊防不甯因示同志','溫庭筠','唐','御定全唐诗','yuding','','[]','龍砂鐵馬犯煙塵，跡近群鷗意倍親。風卷蓬根屯戊己，',40,'御定全唐詩/json/578.json','["龍砂鐵馬犯煙塵，跡近群鷗意倍親。風卷蓬根屯戊己，", "心許故人知此意，古來知者竟誰人。"]'),
('yuding-55','祕書省有賀監知章草題詩筆力遒健風尚高遠拂塵尋玩因有此作','溫庭筠','唐','御定全唐诗','yuding','','[]','越溪漁客賀知章，任達憐才愛酒狂。鸂鶒葦花隨釣艇，',48,'御定全唐詩/json/578.json','["越溪漁客賀知章，任達憐才愛酒狂。鸂鶒葦花隨釣艇，", "榮路脫身終自得，福庭回首莫相忘。出籠鸞鶴歸遼海，"]'),
('yuding-56','題裴晉公林亭','溫庭筠','唐','御定全唐诗','yuding','','[]','謝傅林亭暑氣微，山丘零落閟音徽。東山終為蒼生起，',40,'御定全唐詩/json/578.json','["謝傅林亭暑氣微，山丘零落閟音徽。東山終為蒼生起，", "悠然到此忘情處，一日何妨有萬幾。"]'),
('yuding-0','車駕西遊因而有作','溫庭筠','唐','御定全唐诗','yuding','','[]','宣曲長楊瑞氣凝，上林狐兔待秋鷹。',32,'御定全唐詩/json/579.json','["宣曲長楊瑞氣凝，上林狐兔待秋鷹。", "誰將詞賦陪雕輦，寂寞相如臥茂林。"]'),
('yuding-1','傷溫德彝','溫庭筠','唐','御定全唐诗','yuding','','[]','昔年戎虜犯榆關，一敗龍城匹馬還。',32,'御定全唐詩/json/579.json','["昔年戎虜犯榆關，一敗龍城匹馬還。", "侯印不聞封李廣，他人丘壟似天山。"]'),
('yuding-2','贈少年','溫庭筠','唐','御定全唐诗','yuding','','[]','江海相逢客恨多，秋風葉下洞庭波。',32,'御定全唐詩/json/579.json','["江海相逢客恨多，秋風葉下洞庭波。", "酒酣夜別淮陰市，月照高樓一曲歌。"]'),
('yuding-3','贈鄭征君家匡山首春與丞相贊皇公游止','溫庭筠','唐','御定全唐诗','yuding','','[]','一拋蘭棹逐燕鴻，曾向江湖識謝公。',32,'御定全唐詩/json/579.json','["一拋蘭棹逐燕鴻，曾向江湖識謝公。", "每到朱門還悵望，故山多在畫屏中。"]'),
('yuding-4','夏中病痁作','溫庭筠','唐','御定全唐诗','yuding','','[]','山鬼揚威正氣愁，便辭珍簟襲狐裘。',32,'御定全唐詩/json/579.json','["山鬼揚威正氣愁，便辭珍簟襲狐裘。", "西窗一夕悲人事，團扇無情不待秋。"]'),
('yuding-5','題友人居','溫庭筠','唐','御定全唐诗','yuding','','[]','盡日松堂看畫圖，綺疏岑寂似清都。',32,'御定全唐詩/json/579.json','["盡日松堂看畫圖，綺疏岑寂似清都。", "若教煙水無鷗鳥，張翰何由到五湖。"]'),
('yuding-6','題李相公敕賜錦屏風','溫庭筠','唐','御定全唐诗','yuding','','[]','豐沛曾為社稷臣，賜書名畫墨猶新。',32,'御定全唐詩/json/579.json','["豐沛曾為社稷臣，賜書名畫墨猶新。", "幾人同保山河誓，猶自棲棲九陌塵。"]'),
('yuding-7','蔡中郎墳','溫庭筠','唐','御定全唐诗','yuding','','[]','古墳零落野花春，聞說中郎有後身。',32,'御定全唐詩/json/579.json','["古墳零落野花春，聞說中郎有後身。", "今日愛才非昔日，莫拋心力作詞人。"]'),
('yuding-8','元處士池上','溫庭筠','唐','御定全唐诗','yuding','','[]','蓼穗菱叢思蟪蛄，水螢江鳥滿煙蒲。',32,'御定全唐詩/json/579.json','["蓼穗菱叢思蟪蛄，水螢江鳥滿煙蒲。", "愁紅一片風前落，池上秋波似五湖。"]'),
('yuding-9','華陰韋氏林亭','溫庭筠','唐','御定全唐诗','yuding','','[]','自有林亭不得閒，陌塵宮樹是非間。',32,'御定全唐詩/json/579.json','["自有林亭不得閒，陌塵宮樹是非間。", "終南長在茅簷外，別向人間看華山。"]'),
('yuding-10','寄裴生乞釣鉤','溫庭筠','唐','御定全唐诗','yuding','','[]','一隨菱棹謁王侯，深愧移文負釣舟。',32,'御定全唐詩/json/579.json','["一隨菱棹謁王侯，深愧移文負釣舟。", "今日太湖風色好，卻將詩句乞魚鉤。"]'),
('yuding-11','長安春晚二首','溫庭筠','唐','御定全唐诗','yuding','','[]','曲江春半日遲遲，正是王孫悵望時。',64,'御定全唐詩/json/579.json','["曲江春半日遲遲，正是王孫悵望時。", "杏花落盡不歸去，江上東風吹柳絲。", "四方無事太平年，萬象鮮明禁火前。", "九重細雨惹春色，輕染龍池楊柳煙。"]'),
('yuding-12','三月十八日雪中作','溫庭筠','唐','御定全唐诗','yuding','','[]','芍藥薔薇語早梅，不知誰是豔陽才。',32,'御定全唐詩/json/579.json','["芍藥薔薇語早梅，不知誰是豔陽才。", "今朝領得春風意，不復饒君雪裏開。"]'),
('yuding-13','咸陽值雨','溫庭筠','唐','御定全唐诗','yuding','','[]','咸陽橋上雨如懸，萬點空蒙隔釣船。',32,'御定全唐詩/json/579.json','["咸陽橋上雨如懸，萬點空蒙隔釣船。", "還似洞庭春水色，曉雲將入岳陽天。"]'),
('yuding-14','彈箏人','溫庭筠','唐','御定全唐诗','yuding','','[]','天寶年中事玉皇，曾將新曲教甯王。',32,'御定全唐詩/json/579.json','["天寶年中事玉皇，曾將新曲教甯王。", "鈿蟬金雁今零落，一曲伊州淚萬行。"]'),
('yuding-15','瑤瑟怨','溫庭筠','唐','御定全唐诗','yuding','','[]','冰簟銀床夢不成，碧天如水夜雲輕。',32,'御定全唐詩/json/579.json','["冰簟銀床夢不成，碧天如水夜雲輕。", "雁聲遠過瀟湘去，十二樓中月自明。"]'),
('yuding-16','題端正樹','溫庭筠','唐','御定全唐诗','yuding','','[]','路傍佳樹碧雲愁，曾侍金輿幸驛樓。',32,'御定全唐詩/json/579.json','["路傍佳樹碧雲愁，曾侍金輿幸驛樓。", "草木榮枯似人事，綠陰寂寞漢陵秋。"]'),
('yuding-17','渭上題三首','溫庭筠','唐','御定全唐诗','yuding','','[]','呂公榮達子陵歸，萬古煙波繞釣磯。',96,'御定全唐詩/json/579.json','["呂公榮達子陵歸，萬古煙波繞釣磯。", "橋上一通名利跡，至今江鳥背人飛。", "目極雲霄思浩然，風帆一片水連天。", "輕橈便是東歸路，不肯忘機作釣船。", "煙水何曾息世機，暫時相向亦依依。", "所嗟白首磻溪叟，一下漁舟更不歸。"]'),
('yuding-18','經故翰林袁學士居','溫庭筠','唐','御定全唐诗','yuding','','[]','劍逐驚波玉委塵，謝安門下更何人。',32,'御定全唐詩/json/579.json','["劍逐驚波玉委塵，謝安門下更何人。", "西州城外花千樹，儘是羊曇醉後春。"]'),
('yuding-19','題城南杜邠公林亭','溫庭筠','唐','御定全唐诗','yuding','','[]','卓氏壚前金線柳，隋家堤畔錦帆風。',32,'御定全唐詩/json/579.json','["卓氏壚前金線柳，隋家堤畔錦帆風。", "貪為兩地分霖雨，不見池蓮照水紅。"]'),
('yuding-20','夜看牡丹','溫庭筠','唐','御定全唐诗','yuding','','[]','高低深淺一闌紅，把火殷勤繞露叢。',32,'御定全唐詩/json/579.json','["高低深淺一闌紅，把火殷勤繞露叢。", "希逸近來成懶病，不能容易向春風。"]'),
('yuding-21','宿城南亡友別墅','溫庭筠','唐','御定全唐诗','yuding','','[]','水流花落歎浮生，又伴遊人宿杜城。',32,'御定全唐詩/json/579.json','["水流花落歎浮生，又伴遊人宿杜城。", "還似昔年殘夢裏，透簾斜月獨聞鶯。"]'),
('yuding-22','過分水嶺','溫庭筠','唐','御定全唐诗','yuding','','[]','溪水無情似有情，入山三日得同行。',32,'御定全唐詩/json/579.json','["溪水無情似有情，入山三日得同行。", "嶺頭便是分頭處，惜別潺湲一夜聲。"]'),
('yuding-23','鄠杜郊居','溫庭筠','唐','御定全唐诗','yuding','','[]','槿籬芳援近樵家，壟麥青青一徑斜。',32,'御定全唐詩/json/579.json','["槿籬芳援近樵家，壟麥青青一徑斜。", "寂寞遊人寒食後，夜來風雨送梨花。"]'),
('yuding-24','題河中紫極宮','溫庭筠','唐','御定全唐诗','yuding','','[]','昔年曾伴玉真遊，每到仙宮即是秋。',32,'御定全唐詩/json/579.json','["昔年曾伴玉真遊，每到仙宮即是秋。", "曼倩不歸花落盡，滿叢煙露月當樓。"]'),
('yuding-25','四皓','溫庭筠','唐','御定全唐诗','yuding','','[]','商於甪裏便成功，一寸沉機萬古同。',32,'御定全唐詩/json/579.json','["商於甪裏便成功，一寸沉機萬古同。", "但得戚姬甘定分，不應真有紫芝翁。"]'),
('yuding-26','贈張煉師','溫庭筠','唐','御定全唐诗','yuding','','[]','丹溪藥盡變金骨，清洛月寒吹玉笙。',32,'御定全唐詩/json/579.json','["丹溪藥盡變金骨，清洛月寒吹玉笙。", "他日隱居無訪處，碧桃花發水縱橫。"]'),
('yuding-0','病中書懷呈友人','溫庭筠','唐','御定全唐诗','yuding','','[]','逸足皆先路，窮郊獨向隅。頑童逃廣柳，羸馬臥平蕪。',576,'御定全唐詩/json/580.json','["逸足皆先路，窮郊獨向隅。頑童逃廣柳，羸馬臥平蕪。", "黃卷嗟誰問，朱弦偶自娛。鹿鳴皆綴士，雌伏竟非夫。", "埰地荒遺野，爰田失故都。亡羊猶博簺，牧馬倦呼盧。", "奕世參周祿，承家學魯儒。功庸留劍舄，銘戒在盤盂。", "經濟懷良畫，行藏識遠圖。未能鳴楚玉，空欲握隋珠。", "定為魚緣木，曾因兔守株。五車堆縹帙，三徑闔繩樞。", "適與群英集，將期善價沽。葉龍圖夭矯，燕鼠笑胡盧。", "賦分知前定，寒心畏厚誣。躡塵追慶忌，操劍學班輸。", "文囿陪多士，神州試大巫。對雖希鼓瑟，名亦濫吹竽。", "正使猜奔競，何嘗計有無。鎦惔虛訪覓，王霸竟揶揄。", "市義虛焚券，關譏謾棄繻。至言今信矣，微尚亦悲夫。", "白雪調歌響，清風樂舞雩。脅肩難黽勉，搔首易嗟籲。", "角勝非能者，推賢見射乎。兕觥增恐竦，杯水失錙銖。", "粉垛收丹采，金髇隱僕姑。垂櫜羞盡爵，揚觶辱彎弧。", "虎拙休言畫，龍希莫學屠。轉蓬隨款段，耘草辟墁壚。", "受業鄉名鄭，藏機穀號愚。質文精等貫，琴築韻相須。", "築室連中野，誅茅接上腴。葦花綸虎落，松癭鬥欒櫨。", "靜語鶯相對，閑眠鶴浪俱。蕊多勞蝶翅，香酷墜蜂須。", "芳草迷三島，澄波似五湖。躍魚翻藻荇，愁鷺睡葭蘆。", "暝渚藏鸂鶒，幽屏臥鷓鴣。苦辛隨藝殖，甘旨仰樵蘇。", "笑語空懷橘，窮愁亦據梧。尚能甘半菽，非敢薄生芻。", "釣石封蒼蘚，芳蹊豔絳跗。樹蘭畦繚繞，穿竹路縈紆。", "機杼非桑女，林園異木奴。橫竿窺赤鯉，持翳望青鸕。", "泮水思芹味，琅琊得稻租。杖輕藜擁腫，衣破芰披敷。"]'),
('yuding-1','感舊陳情五十韻獻淮南李僕射','溫庭筠','唐','御定全唐诗','yuding','','[]','嵇紹垂髫日，山濤筮仕年。琴樽陳席上，紈綺拜床前。',576,'御定全唐詩/json/580.json','["嵇紹垂髫日，山濤筮仕年。琴樽陳席上，紈綺拜床前。", "鄰里才三徙，雲霄已九遷。感深情惝怳，言發淚潺湲。", "憶昔龍圖盛，方今鶴羽全。桂枝香可襲，楊葉舊頻穿。", "玉籍標人瑞，金丹化地仙。賦成攢筆寫，歌出滿城傳。", "既矯排虛翅，將持造物權。萬靈思鼓鑄，群品待陶甄。", "視草絲綸出，持綱雨露懸。法行黃道內，居近翠華邊。", "書跡臨湯鼎，吟聲接舜弦。白麻紅燭夜，清漏紫微天。", "雷電隨神筆，魚龍落彩箋。閑宵陪雍時，清暑在甘泉。", "耿介非持祿，優遊是養賢。冰清臨百粵，風靡化三川。", "委寄崇推轂，威儀壓控弦。梁園提彀騎，淮水換戎旃。", "照日青油濕，迎風錦帳鮮。黛蛾陳二八，珠履列三千。", "舞轉回紅袖，歌愁斂翠鈿。滿堂開照曜，分座儼嬋娟。", "油額芙蓉帳，香塵玳瑁筵。繡旗隨影合，金陣似波旋。", "緹幕深回互，朱門暗接連。彩虯蟠畫戟，花馬立金鞭。", "有客將誰托，無媒竊自憐。抑揚中散曲，漂泊孝廉船。", "未展幹時策，徒拋負郭田。轉蓬猶邈爾，懷橘更潸然。", "投足乖蹊徑，冥心向簡編。未知魚躍地，空愧鹿鳴篇。", "稷下期方至，漳濱病未痊。定非籠外鳥，真是殼中蟬。", "蕙徑鄰幽澹，荊扉興靜便。草堂苔點點，蔬囿水濺濺。", "釣罷溪雲重，樵歸澗月圓。懶多成宿疢，愁甚似春眠。", "木直終難怨，膏明只自煎。鄭鄉空健羨，陳榻未招延。", "旅食逢春盡，羈遊為事牽。宦無毛義檄，婚乏阮修錢。", "冉弱營中柳，披敷幕下蓮。儻能容委質，非敢望差肩。", "澀劍猶堪淬，餘朱或可研。從師當鼓篋，窮理久忘筌。"]'),
('yuding-2','題翠微寺二十二韻','溫庭筠','唐','御定全唐诗','yuding','','[]','邠土初成邑，虞賓竟讓王。幹符初得位，天弩夜收鋩。',264,'御定全唐詩/json/580.json','["邠土初成邑，虞賓竟讓王。幹符初得位，天弩夜收鋩。", "偃息齊三代，優遊念四方。萬靈扶正寢，千嶂抱重岡。", "幽石歸階陛，喬柯入棟樑。火雲如沃雪，湯殿似含霜。", "澗籟添仙曲，岩花借禦香。野麋陪獸舞，林鳥逐鵷行。", "鏡寫三秦色，窗搖八水光。問雲征楚女，疑粉試何郎。", "蘭芷承雕輦，杉蘿入畫堂。受朝松露曉，頒朔桂煙涼。", "嵐濕金鋪外，溪鳴錦幄傍。倚絲憂漢祖，持璧告秦皇。", "短景催風馭，長星屬羽觴。儲君猶問豎，元老已登床。", "鶴蓋趨平樂，雞人下建章。龍髯悲滿眼，螭首淚沾裳。", "疊鼓嚴靈仗，吹笙送夕陽。斷泉辭劍佩，昏日伴旗常。", "遺廟青蓮在，頹垣碧草芳。無因奏韶濩，流涕對幽篁。"]'),
('yuding-3','過孔北海墓二十韻','溫庭筠','唐','御定全唐诗','yuding','','[]','撫事如神遇，臨風獨涕零。墓平春草綠，碑折古苔青。',240,'御定全唐詩/json/580.json','["撫事如神遇，臨風獨涕零。墓平春草綠，碑折古苔青。", "珪玉埋英氣，山河孕炳靈。發言驚辨囿，撝翰動文星。", "蘊策期幹世，持權欲反經。激揚思壯志，流落歎頹齡。", "惡木人皆息，貪泉我獨醒。輪轅無匠石，刀幾有庖丁。", "碌碌迷藏器，規規守挈瓶。憤容淩鼎鑊，公議動朝廷。", "故國將辭寵，危邦竟緩刑。鈍工磨白璧，凡石礪青萍。", "揭日昭東夏，摶風滯北溟。後塵遵軌轍，前席詠儀型。", "木秀當憂悴，弦傷不底寧。矜誇遭斥鷃，光彩困飛螢。", "白羽留談柄，清風襲德馨。鸞凰嬰雪刃，狼虎犯雲屏。", "蘭蕙荒遺址，榛蕪蔽舊坰。鐶轅近沂水，何事戀明庭。"]'),
('yuding-4','過華清宮二十二韻','溫庭筠','唐','御定全唐诗','yuding','','[]','憶昔開元日，承平事勝遊。貴妃專寵倖，天子富春秋。',264,'御定全唐詩/json/580.json','["憶昔開元日，承平事勝遊。貴妃專寵倖，天子富春秋。", "月白霓裳殿，風乾羯鼓樓。鬥雞花蔽膝，騎馬玉搔頭。", "繡轂千門妓，金鞍萬戶侯。薄雲欹雀扇，輕雪犯貂裘。", "過客聞韶濩，居人識冕旒。氣和春不覺，煙暖霽難收。", "澀浪和瓊甃，晴陽上彩斿。卷衣輕鬢懶，窺鏡澹蛾羞。", "屏掩芙蓉帳，簾褰玳瑁鉤。重瞳分渭曲，纖手指神州。", "禦案迷萱草，天袍妒石榴。深岩藏浴鳳，鮮隰媚潛虯。", "不料邯鄲虱，俄成即墨牛。劍鋒揮太皞，旗焰拂蚩尤。", "內嬖陪行在，孤臣預坐籌。瑤簪遺翡翠，霜仗駐驊騮。", "豔笑雙飛斷，香魂一哭休。早梅悲蜀道，高樹隔昭丘。", "朱閣重霄近，蒼崖萬古愁。至今湯殿水，嗚咽縣前流。"]'),
('yuding-5','洞戶二十二韻','溫庭筠','唐','御定全唐诗','yuding','','[]','洞戶連珠網，方疏隱碧潯。燭盤煙墜燼，簾壓月通陰。',264,'御定全唐詩/json/580.json','["洞戶連珠網，方疏隱碧潯。燭盤煙墜燼，簾壓月通陰。", "粉白仙郎署，霜清玉女砧。醉鄉高窈窈，棋陣靜愔愔。", "素手琉璃扇，玄髫玳瑁簪。昔邪看寄跡，梔子詠同心。", "樹列千秋勝，樓懸七夕針。舊詞翻白紵，新賦換黃金。", "唳鶴調蠻鼓，驚蟬應寶琴。舞疑繁易度，歌轉斷難尋。", "露委花相妒，風欹柳不禁。橋彎雙表迥，池漲一篙深。", "清蹕傳恢囿，黃旗幸上林。神鷹參翰苑，天馬破蹄涔。", "武庫方題品，文園有好音。朱莖殊菌蠢，丹桂欲蕭森。", "黼帳回瑤席，華燈對錦衾。畫圖驚走獸，書帖得來禽。", "河曙秦樓映，山晴魏闕臨。綠囊逢趙後，青鎖見王沈。", "任達嫌孤憤，疏慵倦九箴。若為南遁客，猶作臥龍吟。"]'),
('yuding-0','送洛南李主簿','溫庭筠','唐','御定全唐诗','yuding','','[]','想君秦塞外，因見楚山青。槲葉曉迷路，枳花春滿庭。',48,'御定全唐詩/json/581.json','["想君秦塞外，因見楚山青。槲葉曉迷路，枳花春滿庭。", "祿優仍侍膳，官散得專經。子敬懷愚穀，歸心在翠屏。"]'),
('yuding-1','巫山神女廟','溫庭筠','唐','御定全唐诗','yuding','','[]','黯黯閉宮殿，霏霏蔭薜蘿。曉峰眉上色，春水臉前波。',48,'御定全唐詩/json/581.json','["黯黯閉宮殿，霏霏蔭薜蘿。曉峰眉上色，春水臉前波。", "古樹芳菲盡，扁舟離恨多。一叢斑竹夜，環佩響如何。"]'),
('yuding-2','地肺山春日','溫庭筠','唐','御定全唐诗','yuding','','[]','冉冉花明岸，涓涓水繞山。幾時拋俗事，來共白雲閑。',24,'御定全唐詩/json/581.json','["冉冉花明岸，涓涓水繞山。幾時拋俗事，來共白雲閑。"]'),
('yuding-3','題陳處士幽居','溫庭筠','唐','御定全唐诗','yuding','','[]','松軒塵外客，高枕自蕭疏。雨後苔侵井，霜來葉滿渠。',48,'御定全唐詩/json/581.json','["松軒塵外客，高枕自蕭疏。雨後苔侵井，霜來葉滿渠。", "閑看鏡湖畫，秋得越僧書。若待前溪月，誰人伴釣魚。"]'),
('yuding-4','握柘詞','溫庭筠','唐','御定全唐诗','yuding','','[]','楊柳縈橋綠，玫瑰拂地紅。繡衫金騕褭，花髻玉瓏璁。',48,'御定全唐詩/json/581.json','["楊柳縈橋綠，玫瑰拂地紅。繡衫金騕褭，花髻玉瓏璁。", "宿雨香潛潤，春流水暗通。畫樓初夢斷，曉日照湘風。"]'),
('yuding-5','題盧處士山居','溫庭筠','唐','御定全唐诗','yuding','','[]','西溪問樵客，遙識楚人家。古樹老連石，急泉清露沙。',48,'御定全唐詩/json/581.json','["西溪問樵客，遙識楚人家。古樹老連石，急泉清露沙。", "千峰隨雨暗，一徑入雲斜。日暮飛鴉集，滿山蕎麥花。"]'),
('yuding-6','初秋寄友人','溫庭筠','唐','御定全唐诗','yuding','','[]','閑夢正悠悠，涼風生竹樓。夜琴知欲雨，曉簟覺新秋。',48,'御定全唐詩/json/581.json','["閑夢正悠悠，涼風生竹樓。夜琴知欲雨，曉簟覺新秋。", "獨鳥楚山遠，一蟬關樹愁。憑將離別恨，江外問同遊。"]'),
('yuding-7','題豐安裏王相林亭二首','溫庭筠','唐','御定全唐诗','yuding','','[]','花竹有薄埃，嘉遊集上才。白蘋安石渚，紅葉子雲台。',96,'御定全唐詩/json/581.json','["花竹有薄埃，嘉遊集上才。白蘋安石渚，紅葉子雲台。", "朱戶雀羅設，黃門馭騎來。不知淮水濁，丹藕為誰開。", "偶到烏衣巷，含情更惘然。西州曲堤柳，東府舊池蓮。", "星坼悲元老，雲歸送墨仙。誰知濟川楫，今作野人船。"]'),
('yuding-8','早秋山居','溫庭筠','唐','御定全唐诗','yuding','','[]','山近覺寒早，草堂霜氣晴。樹凋窗有日，池滿水無聲。',48,'御定全唐詩/json/581.json','["山近覺寒早，草堂霜氣晴。樹凋窗有日，池滿水無聲。", "果落見猿過，葉幹聞鹿行。素琴機慮靜，空伴夜泉清。"]'),
('yuding-9','和友人磐石寺逢舊友','溫庭筠','唐','御定全唐诗','yuding','','[]','楚寺上方宿，滿堂皆舊遊。月溪逢遠客，煙浪有歸舟。',48,'御定全唐詩/json/581.json','["楚寺上方宿，滿堂皆舊遊。月溪逢遠客，煙浪有歸舟。", "江館白蘋夜，水關紅葉秋。西風吹暮雨，汀草更堪愁。"]'),
('yuding-10','送人南游','溫庭筠','唐','御定全唐诗','yuding','','[]','送君游楚國，江浦樹蒼然。沙淨有波跡，岸平多草煙。',48,'御定全唐詩/json/581.json','["送君游楚國，江浦樹蒼然。沙淨有波跡，岸平多草煙。", "角悲臨海郡，月到渡淮船。唯以一杯酒，相思高楚天。"]'),
('yuding-11','贈鄭處士','溫庭筠','唐','御定全唐诗','yuding','','[]','飄然隨釣艇，雲水是天涯。紅葉下荒井，碧梧侵古槎。',48,'御定全唐詩/json/581.json','["飄然隨釣艇，雲水是天涯。紅葉下荒井，碧梧侵古槎。", "醉收陶令菊，貧賣邵平瓜。更有相期處，南籬一樹花。"]'),
('yuding-12','江岸即事','溫庭筠','唐','御定全唐诗','yuding','','[]','水容侵古岸，峰影度青蘋。廟竹唯聞鳥，江帆不見人。',48,'御定全唐詩/json/581.json','["水容侵古岸，峰影度青蘋。廟竹唯聞鳥，江帆不見人。", "雀聲花外暝，客思柳邊春。別恨轉難盡，行行汀草新。"]'),
('yuding-13','贈隱者','溫庭筠','唐','御定全唐诗','yuding','','[]','茅堂對薇蕨，爐暖一裘輕。醉後楚山夢，覺來春鳥聲。',48,'御定全唐詩/json/581.json','["茅堂對薇蕨，爐暖一裘輕。醉後楚山夢，覺來春鳥聲。", "採茶溪樹綠，煮藥石泉清。不問人間事，忘機過此生。"]'),
('yuding-14','渚宮晚春寄秦地友人','溫庭筠','唐','御定全唐诗','yuding','','[]','風華已眇然，獨立思江天。鳧雁野塘水，牛羊春草煙。',48,'御定全唐詩/json/581.json','["風華已眇然，獨立思江天。鳧雁野塘水，牛羊春草煙。", "秦原曉重疊，灞浪夜潺湲。今日思歸客，愁容在鏡懸。"]'),
('yuding-15','碧澗驛曉思','溫庭筠','唐','御定全唐诗','yuding','','[]','香燈伴殘夢，楚國在天涯。月落子規歇，滿庭山杏花。',24,'御定全唐詩/json/581.json','["香燈伴殘夢，楚國在天涯。月落子規歇，滿庭山杏花。"]'),
('yuding-16','送並州郭書記','溫庭筠','唐','御定全唐诗','yuding','','[]','賓筵得佳客，侯印有光輝。候騎不傳箭，回文空上機。',48,'御定全唐詩/json/581.json','["賓筵得佳客，侯印有光輝。候騎不傳箭，回文空上機。", "塞城收馬去，烽火射雕歸。惟有嚴家瀨，回環徑草微。"]'),
('yuding-17','贈越僧嶽雲二首','溫庭筠','唐','御定全唐诗','yuding','','[]','世機消已盡，巾屨亦飄然。一室故山月，滿瓶秋澗泉。',96,'御定全唐詩/json/581.json','["世機消已盡，巾屨亦飄然。一室故山月，滿瓶秋澗泉。", "禪庵過微雪，鄉寺隔寒煙。應共白蓮客，相期松桂前。", "蘭亭舊都講，今日意如何。有樹關深院，無塵到淺莎。", "僧居隨處好，人事出門多。不及新春雁，年年鏡水波。"]'),
('yuding-18','詠山雞','溫庭筠','唐','御定全唐诗','yuding','','[]','萬壑動晴景，山禽淩翠微。繡翎翻草去，紅觜啄花歸。',48,'御定全唐詩/json/581.json','["萬壑動晴景，山禽淩翠微。繡翎翻草去，紅觜啄花歸。", "巢暖碧雲色，影孤清鏡輝。不知春樹伴，何處又分飛。"]'),
('yuding-19','清旦題采藥翁草堂','溫庭筠','唐','御定全唐诗','yuding','','[]','幽人尋藥徑，來自曉雲邊。衣濕術花雨，語成松嶺煙。',48,'御定全唐詩/json/581.json','["幽人尋藥徑，來自曉雲邊。衣濕術花雨，語成松嶺煙。", "解藤開澗戶，踏石過溪泉。林外晨光動，山昏鳥滿天。"]'),
('yuding-20','商山早行','溫庭筠','唐','御定全唐诗','yuding','','[]','晨起動征鐸，客行悲故鄉。雞聲茅店月，人跡板橋霜。',48,'御定全唐詩/json/581.json','["晨起動征鐸，客行悲故鄉。雞聲茅店月，人跡板橋霜。", "槲葉落山路，枳花明驛牆。因思杜陵夢，鳧雁滿回塘。"]'),
('yuding-21','題竹穀神祠','溫庭筠','唐','御定全唐诗','yuding','','[]','蒼蒼松竹晚，一徑入荒祠。古樹風吹馬，虛廊日照旗。',48,'御定全唐詩/json/581.json','["蒼蒼松竹晚，一徑入荒祠。古樹風吹馬，虛廊日照旗。", "煙煤朝奠處，風雨夜歸時。寂寞東湖客，空看蔣帝碑。"]'),
('yuding-22','途中有懷','溫庭筠','唐','御定全唐诗','yuding','','[]','驅車何日閑，擾擾路岐間。歲暮自多感，客程殊未還。',48,'御定全唐詩/json/581.json','["驅車何日閑，擾擾路岐間。歲暮自多感，客程殊未還。", "亭皋汝陽道，風雪穆陵關。臘後寒梅發，誰人在故山。"]'),
('yuding-23','經李處士杜城別業','溫庭筠','唐','御定全唐诗','yuding','','[]','憶昔幾遊集，今來倍歎傷。百花情易老，一笑事難忘。',48,'御定全唐詩/json/581.json','["憶昔幾遊集，今來倍歎傷。百花情易老，一笑事難忘。", "白社已蕭索，青樓空豔陽。不閑雲雨夢，猶欲過高唐。"]'),
('yuding-24','登李羽士東樓','溫庭筠','唐','御定全唐诗','yuding','','[]','經客有餘音，他年終故林。高樓本危睇，涼月更傷心。',48,'御定全唐詩/json/581.json','["經客有餘音，他年終故林。高樓本危睇，涼月更傷心。", "此意竟難折，伊人成古今。流塵其可欲，非複懶鳴琴。"]'),
('yuding-25','題僧泰恭院二首','溫庭筠','唐','御定全唐诗','yuding','','[]','昔歲東林下，深公識姓名。爾來辭半偈，空複歎勞生。',96,'御定全唐詩/json/581.json','["昔歲東林下，深公識姓名。爾來辭半偈，空複歎勞生。", "憂患慕禪味，寂寥遺世情。所歸心自得，何事倦塵纓。", "微生竟勞止，晤言猶是非。出門還有淚，看竹暫忘機。", "爽氣三秋近，浮生一笑稀。故山松菊在，終欲掩荊扉。"]'),
('yuding-26','西遊書懷','溫庭筠','唐','御定全唐诗','yuding','','[]','渭川通野戍，有路上桑幹。獨鳥青天暮，驚麏赤燒殘。',48,'御定全唐詩/json/581.json','["渭川通野戍，有路上桑幹。獨鳥青天暮，驚麏赤燒殘。", "高秋辭故國，昨日夢長安。客意自如此，非關行路難。"]'),
('yuding-27','送人東游','溫庭筠','唐','御定全唐诗','yuding','','[]','荒戍落黃葉，浩然離故關。高風漢陽渡，初日郢門山。',48,'御定全唐詩/json/581.json','["荒戍落黃葉，浩然離故關。高風漢陽渡，初日郢門山。", "江上幾人在，天涯孤棹還。何當重相見，尊酒慰離顏。"]'),
('yuding-28','寄山中友人','溫庭筠','唐','御定全唐诗','yuding','','[]','惟昔有歸趣，今茲固願言。嘯歌成往事，風雨坐涼軒。',48,'御定全唐詩/json/581.json','["惟昔有歸趣，今茲固願言。嘯歌成往事，風雨坐涼軒。", "時物信佳節，歲華非故園。固知春草色，何意為王孫。"]'),
('yuding-29','偶題','溫庭筠','唐','御定全唐诗','yuding','','[]','孔雀眠高閣，櫻桃拂短簷。畫明金冉冉，箏語玉纖纖。',48,'御定全唐詩/json/581.json','["孔雀眠高閣，櫻桃拂短簷。畫明金冉冉，箏語玉纖纖。", "細雨無妨燭，輕寒不隔簾。欲將紅錦段，因夢寄江淹。"]'),
('yuding-30','贈考功盧郎中','溫庭筠','唐','御定全唐诗','yuding','','[]','白首方辭滿，荊扉對渚田。雪中無陋巷，醉後似當年。',48,'御定全唐詩/json/581.json','["白首方辭滿，荊扉對渚田。雪中無陋巷，醉後似當年。", "一笈負山藥，兩瓶攜澗泉。夜來風浪起，何處認漁船。"]'),
('yuding-31','題蕭山廟','溫庭筠','唐','御定全唐诗','yuding','','[]','故道木陰濃，荒祠山影東。杉松一庭雨，幡蓋滿堂風。',48,'御定全唐詩/json/581.json','["故道木陰濃，荒祠山影東。杉松一庭雨，幡蓋滿堂風。", "客奠曉莎濕，馬嘶秋廟空。夜深池上歇，龍入古潭中。"]'),
('yuding-32','春日寄岳州從事李員外二首','溫庭筠','唐','御定全唐诗','yuding','','[]','苒弱樓前柳，輕空花外窗。蝶高飛有伴，鶯早語無雙。',96,'御定全唐詩/json/581.json','["苒弱樓前柳，輕空花外窗。蝶高飛有伴，鶯早語無雙。", "剪勝裁春字，開屏見曉江。從來共情戰，今日欲歸降。", "從小識賓卿，恩深若弟兄。相逢在何日，此別不勝情。", "紅粉座中客，彩斿江上城。尚平婚嫁累，無路逐雙旌。"]'),
('yuding-33','和段少常柯古','溫庭筠','唐','御定全唐诗','yuding','','[]','稱觴慚座客，懷刺即門人。素向寧知貴，清淡不厭貧。',48,'御定全唐詩/json/581.json','["稱觴慚座客，懷刺即門人。素向寧知貴，清淡不厭貧。", "野梅江上晚，堤柳雨中春。未報淮南詔，何勞問白蘋。"]'),
('yuding-34','海榴','溫庭筠','唐','御定全唐诗','yuding','','[]','海榴開似火，先解報春風。葉亂裁箋綠，花宜插鬢紅。',48,'御定全唐詩/json/581.json','["海榴開似火，先解報春風。葉亂裁箋綠，花宜插鬢紅。", "蠟珠攢作蒂，緗彩剪成叢。鄭驛多歸思，相期一笑同。"]'),
('yuding-35','李先生別墅望僧舍寶刹，因作雙韻聲','溫庭筠','唐','御定全唐诗','yuding','','[]','棲息消心象，簷楹溢豔陽。簾櫳蘭露落，鄰里柳林涼。',48,'御定全唐詩/json/581.json','["棲息消心象，簷楹溢豔陽。簾櫳蘭露落，鄰里柳林涼。", "高閣過空穀，孤竿隔古岡。潭廬同淡蕩，仿佛複芬芳。"]'),
('yuding-36','敷水小桃盛開因作','溫庭筠','唐','御定全唐诗','yuding','','[]','敷水小橋東，娟娟照露叢。所嗟非勝地，堪恨是春風。',48,'御定全唐詩/json/581.json','["敷水小橋東，娟娟照露叢。所嗟非勝地，堪恨是春風。", "二月豔陽節，一枝惆悵紅。定知留不住，吹落路塵中。"]'),
('yuding-0','寄山中人','溫庭筠','唐','御定全唐诗','yuding','','[]','月中一雙鶴，石上千尺松。素琴入爽籟，山酒和春容。',48,'御定全唐詩/json/582.json','["月中一雙鶴，石上千尺松。素琴入爽籟，山酒和春容。", "幽瀑有時斷，片雲無所從。何事蘇門生，攜手東南峰。"]'),
('yuding-1','送淮陰孫令之官','溫庭筠','唐','御定全唐诗','yuding','','[]','隋堤楊柳煙，孤棹正悠然。蕭寺通淮戍，蕪城枕楚壖。',49,'御定全唐詩/json/582.json','["隋堤楊柳煙，孤棹正悠然。蕭寺通淮戍，蕪城枕楚壖。", "魚鹽橋上市，燈火雨中船。故老青葭岸，先知i7子賢。"]'),
('yuding-2','宿輝公精舍','溫庭筠','唐','御定全唐诗','yuding','','[]','禪房無外物，清話此宵同。林彩水煙裏，澗聲山月中。',48,'御定全唐詩/json/582.json','["禪房無外物，清話此宵同。林彩水煙裏，澗聲山月中。", "橡霜諸壑霽，杉火一爐空。擁褐寒更徹，心知覺路通。"]'),
('yuding-3','旅泊新津卻寄一二知己','溫庭筠','唐','御定全唐诗','yuding','','[]','維舟息行役，霽景近江村。並起別離恨，似聞歌吹喧。',48,'御定全唐詩/json/582.json','["維舟息行役，霽景近江村。並起別離恨，似聞歌吹喧。", "高林月初上，遠水霧猶昏。王粲平生感，登臨幾斷魂。"]'),
('yuding-4','贈僧雲棲','溫庭筠','唐','御定全唐诗','yuding','','[]','麈尾與筇杖，幾年離石壇。梵餘林雪厚，棋罷岳鐘殘。',48,'御定全唐詩/json/582.json','["麈尾與筇杖，幾年離石壇。梵餘林雪厚，棋罷岳鐘殘。", "開卷喜先悟，漱瓶知早寒。衡陽寺前雁，今日到長安。"]'),
('yuding-5','雪夜與友生同宿曉寄近鄰','溫庭筠','唐','御定全唐诗','yuding','','[]','閉門群動息，積雪透疏林。有客寒方覺，無聲曉已深。',48,'御定全唐詩/json/582.json','["閉門群動息，積雪透疏林。有客寒方覺，無聲曉已深。", "正繁聞近雁，並落起棲禽。寂寞寒塘路，憐君獨阻尋。"]'),
('yuding-6','題造微禪師院','溫庭筠','唐','御定全唐诗','yuding','','[]','夜香聞偈後，岑寂掩雙扉。照竹燈和雪，看松月到衣。',48,'御定全唐詩/json/582.json','["夜香聞偈後，岑寂掩雙扉。照竹燈和雪，看松月到衣。", "草堂疏磬斷，江寺故人稀。唯憶湘南雨，春風獨鳥歸。"]'),
('yuding-7','正見寺曉別生公','溫庭筠','唐','御定全唐诗','yuding','','[]','清曉盥秋水，高窗留夕陰。初陽到古寺，宿鳥起寒林。',48,'御定全唐詩/json/582.json','["清曉盥秋水，高窗留夕陰。初陽到古寺，宿鳥起寒林。", "香火有良願，宦名非素心。靈山緣未絕，他日重來尋。"]'),
('yuding-8','旅次盱眙縣','溫庭筠','唐','御定全唐诗','yuding','','[]','離離麥擢芒，楚客意偏傷。波上旅愁起，天邊歸路長。',48,'御定全唐詩/json/582.json','["離離麥擢芒，楚客意偏傷。波上旅愁起，天邊歸路長。", "孤橈投楚驛，殘月在淮檣。外杜三千里，誰人數雁行。"]'),
('yuding-9','鄠郊別墅寄所知','溫庭筠','唐','御定全唐诗','yuding','','[]','持頤望平綠，萬景集所思。南塘遇新雨，百草生容姿。',48,'御定全唐詩/json/582.json','["持頤望平綠，萬景集所思。南塘遇新雨，百草生容姿。", "幽鳥不相識，美人如何期。徒然委搖盪，惆悵春風時。"]'),
('yuding-10','京兆公池上作','溫庭筠','唐','御定全唐诗','yuding','','[]','稻香山色疊，平野接荒陂。蓮折舟行遠，萍多釣下遲。',48,'御定全唐詩/json/582.json','["稻香山色疊，平野接荒陂。蓮折舟行遠，萍多釣下遲。", "壞堤泉落處，涼簟雨來時。京口兵堪用，何因入夢思。"]'),
('yuding-11','盧氏池上遇雨贈同游者','溫庭筠','唐','御定全唐诗','yuding','','[]','簟翻涼氣集，溪上潤殘棋。萍皺風來後，荷喧雨到時。',48,'御定全唐詩/json/582.json','["簟翻涼氣集，溪上潤殘棋。萍皺風來後，荷喧雨到時。", "寂寥閑望久，飄灑獨歸遲。無限松江恨，煩君解釣絲。"]'),
('yuding-12','題薛昌之所居','溫庭筠','唐','御定全唐诗','yuding','','[]','所得乃清曠，寂寥常掩關。獨來春尚在，相得暮方還。',48,'御定全唐詩/json/582.json','["所得乃清曠，寂寥常掩關。獨來春尚在，相得暮方還。", "花白風露晚，柳青街陌閑。翠微應有雪，窗外見南山。"]'),
('yuding-13','東歸有懷','溫庭筠','唐','御定全唐诗','yuding','','[]','晴川通野陂，此地昔傷離。一去跡常在，獨來心自知。',48,'御定全唐詩/json/582.json','["晴川通野陂，此地昔傷離。一去跡常在，獨來心自知。", "鷺眠茭葉折，魚靜蓼花垂。無限高秋淚，扁舟極路岐。"]'),
('yuding-14','休浣日西掖謁所知','溫庭筠','唐','御定全唐诗','yuding','','[]','赤墀高閣自從容，玉女窗扉報曙鐘。日麗九門青鎖闥，',40,'御定全唐詩/json/582.json','["赤墀高閣自從容，玉女窗扉報曙鐘。日麗九門青鎖闥，", "荀令鳳池春婉娩，好將餘潤變魚龍。"]'),
('yuding-15','博山','溫庭筠','唐','御定全唐诗','yuding','','[]','博山香重欲成雲，錦段機絲妒鄂君。粉蝶團飛花轉影，',40,'御定全唐詩/json/582.json','["博山香重欲成雲，錦段機絲妒鄂君。粉蝶團飛花轉影，", "見說楊朱無限淚，豈能空為路岐分。"]'),
('yuding-16','送盧處士游吳越','溫庭筠','唐','御定全唐诗','yuding','','[]','羨君東去見殘梅，唯有王孫獨未回。吳苑夕陽明古堞，',40,'御定全唐詩/json/582.json','["羨君東去見殘梅，唯有王孫獨未回。吳苑夕陽明古堞，", "試逐漁舟看雪浪，幾多江燕荇花開。"]'),
('yuding-17','過新豐','溫庭筠','唐','御定全唐诗','yuding','','[]','一劍乘時帝業成，沛中鄉里到咸京。寰區已作皇居貴，',40,'御定全唐詩/json/582.json','["一劍乘時帝業成，沛中鄉里到咸京。寰區已作皇居貴，", "至今留得離家恨，雞犬相聞落照明。"]'),
('yuding-18','過潼關','溫庭筠','唐','御定全唐诗','yuding','','[]','地形盤屈帶河流，景氣澄明是勝遊。十裏曉雞關樹暗，',40,'御定全唐詩/json/582.json','["地形盤屈帶河流，景氣澄明是勝遊。十裏曉雞關樹暗，", "麈尾角巾應曠望，更嗟芳靄隔秦樓。"]'),
('yuding-19','題西平王舊賜屏風','溫庭筠','唐','御定全唐诗','yuding','','[]','曾向金扉玉砌來，百花鮮濕隔塵埃。披香殿下櫻桃熟，',40,'御定全唐詩/json/582.json','["曾向金扉玉砌來，百花鮮濕隔塵埃。披香殿下櫻桃熟，", "世間剛有東流水，一送恩波更不回。"]'),
('yuding-20','河中陪帥遊亭','溫庭筠','唐','御定全唐诗','yuding','','[]','倚闌愁立獨徘徊，欲賦慚非宋玉才。滿座山光搖劍戟，',40,'御定全唐詩/json/582.json','["倚闌愁立獨徘徊，欲賦慚非宋玉才。滿座山光搖劍戟，", "添得五湖多少恨，柳花飄蕩似寒梅。"]'),
('yuding-21','和趙嘏題岳寺','溫庭筠','唐','御定全唐诗','yuding','','[]','疏鐘細響亂鳴泉，客省高臨似水天。嵐翠暗來空覺潤，',40,'御定全唐詩/json/582.json','["疏鐘細響亂鳴泉，客省高臨似水天。嵐翠暗來空覺潤，", "張邴宦情何太薄，遠公窗外有池蓮。"]'),
('yuding-22','蘇武廟','溫庭筠','唐','御定全唐诗','yuding','','[]','蘇武魂銷漢使前，古祠高樹兩茫然。雲邊雁斷胡天月，',40,'御定全唐詩/json/582.json','["蘇武魂銷漢使前，古祠高樹兩茫然。雲邊雁斷胡天月，", "茂陵不見封侯印，空向秋波哭逝川。"]'),
('yuding-23','送客偶作','溫庭筠','唐','御定全唐诗','yuding','','[]','石路荒涼接野蒿，西風吹馬利如刀。小橋連驛楊柳晚，',40,'御定全唐詩/json/582.json','["石路荒涼接野蒿，西風吹馬利如刀。小橋連驛楊柳晚，", "故山有夢不歸去，官樹陌塵何太勞。"]'),
('yuding-24','寒食前有懷','溫庭筠','唐','御定全唐诗','yuding','','[]','萬物鮮華雨乍晴，春寒寂曆近清明。殘芳荏苒雙飛蝶，',40,'御定全唐詩/json/582.json','["萬物鮮華雨乍晴，春寒寂曆近清明。殘芳荏苒雙飛蝶，", "悠然更起嚴灘恨，一宿東風蕙草生。"]'),
('yuding-25','宿雲際寺','溫庭筠','唐','御定全唐诗','yuding','','[]','白蓋微雲一徑深，東峰弟子遠相尋。蒼苔路熟僧歸寺，',40,'御定全唐詩/json/582.json','["白蓋微雲一徑深，東峰弟子遠相尋。蒼苔路熟僧歸寺，", "自從紫桂岩前別，不見南能直至今。"]'),
('yuding-26','寄岳州李外郎遠','溫庭筠','唐','御定全唐诗','yuding','','[]','含蘋不語坐持頤，天遠樓高宋玉悲。湖上殘棋人散後，',40,'御定全唐詩/json/582.json','["含蘋不語坐持頤，天遠樓高宋玉悲。湖上殘棋人散後，", "獨有袁宏正憔悴，一樽惆悵落花時。"]'),
('yuding-27','游南塘寄知者','溫庭筠','唐','御定全唐诗','yuding','','[]','白鳥梳翎立岸莎，藻花菱刺泛微波。煙光似帶侵垂柳，',40,'御定全唐詩/json/582.json','["白鳥梳翎立岸莎，藻花菱刺泛微波。煙光似帶侵垂柳，", "鎦公不信歸心切，聽取江樓一曲歌。"]'),
('yuding-28','寄盧生','溫庭筠','唐','御定全唐诗','yuding','','[]','遺業荒涼近故都，門前堤路枕平湖。綠楊陰裏千家月，',40,'御定全唐詩/json/582.json','["遺業荒涼近故都，門前堤路枕平湖。綠楊陰裏千家月，", "他年猶擬金貂換，寄語黃公舊酒壚。"]'),
('yuding-29','春日訪李十四處士','溫庭筠','唐','御定全唐诗','yuding','','[]','花深橋轉水潺潺，甪裏先生自閉關。看竹已知行處好，',40,'御定全唐詩/json/582.json','["花深橋轉水潺潺，甪裏先生自閉關。看竹已知行處好，", "一局殘棋千點雨，綠萍池上暮方還。"]'),
('yuding-30','宿松門寺','溫庭筠','唐','御定全唐诗','yuding','','[]','白石青崖世界分，捲簾孤坐對氛氳。林間禪室春深雪，',40,'御定全唐詩/json/582.json','["白石青崖世界分，捲簾孤坐對氛氳。林間禪室春深雪，", "西山舊是經行地，願漱寒瓶逐領軍。"]'),
('yuding-31','詠寒宵','溫庭筠','唐','御定全唐诗','yuding','','[]','寒宵何耿耿，良宴有餘姿。寶靺徘徊處，熏爐悵望時。',96,'御定全唐詩/json/582.json','["寒宵何耿耿，良宴有餘姿。寶靺徘徊處，熏爐悵望時。", "曲瓊垂翡翠，斜月到罘罳。委墜金釭燼，闌珊玉局棋。", "話窮猶注睇，歌罷尚持頤。晻暖遙相屬，氛氳積所思。", "秦蛾卷衣晚，胡雁度雲遲。上郡歸來夢，那知錦字詩。"]'),
('yuding-32','寄渚宮遺民弘裏生','溫庭筠','唐','御定全唐诗','yuding','','[]','柳弱湖堤曲，籬疏水巷深。酒闌初促席，歌罷欲分襟。',120,'御定全唐詩/json/582.json','["柳弱湖堤曲，籬疏水巷深。酒闌初促席，歌罷欲分襟。", "波月欺華燭，汀雲潤故琴。鏡清花並蒂，床冷簟連心。", "荷疊平橋暗，萍稀敗舫沉。城頭五通鼓，窗外萬家砧。", "異縣魚投浪，當年鳥共林。八行香未滅，千里夢難尋。", "未肯睽良願，空期嗣好音。他時因詠作，猶得比南金。"]'),
('yuding-33','春盡與友人入裴氏林探漁竿','溫庭筠','唐','御定全唐诗','yuding','','[]','一徑互紆直，茅棘亦已繁。晴陽入荒竹，曖曖和春園。',72,'御定全唐詩/json/582.json','["一徑互紆直，茅棘亦已繁。晴陽入荒竹，曖曖和春園。", "倚杖息慚倦，徘徊戀微暄。曆尋嬋娟節，剪破蒼筤根。", "地閉修莖孤，林振餘籜翻。適心在所好，非必尋湘沅。"]'),
('yuding-34','春日','溫庭筠','唐','御定全唐诗','yuding','','[]','問君何所思，迢遞豔陽時。門靜人歸晚，牆高蝶過遲。',72,'御定全唐詩/json/582.json','["問君何所思，迢遞豔陽時。門靜人歸晚，牆高蝶過遲。", "一雙青瑣燕，千萬綠楊絲。屏上吳山遠，樓中朔管悲。", "寶書無寄處，香轂有來期。草色將林彩，相添入黛眉。"]'),
('yuding-35','洛陽','溫庭筠','唐','御定全唐诗','yuding','','[]','鞏樹先春雪滿枝，上陽宮柳囀黃鸝。',32,'御定全唐詩/json/582.json','["鞏樹先春雪滿枝，上陽宮柳囀黃鸝。", "桓譚未便忘西笑，豈為長安有鳳池。"]'),
('yuding-36','題賀知章故居疊韻作','溫庭筠','唐','御定全唐诗','yuding','','[]','廢砌翳薜荔，枯湖無菰蒲。老媼飽槁草，愚儒輸逋租。',24,'御定全唐詩/json/582.json','["廢砌翳薜荔，枯湖無菰蒲。老媼飽槁草，愚儒輸逋租。"]'),
('yuding-37','雨中與李先生期垂釣先後相失，因作疊韻','溫庭筠','唐','御定全唐诗','yuding','','[]','隔石覓屐跡，西溪迷雞啼。小鳥擾曉沼，犁泥齊低畦。',24,'御定全唐詩/json/582.json','["隔石覓屐跡，西溪迷雞啼。小鳥擾曉沼，犁泥齊低畦。"]'),
('yuding-0','春日雨','溫庭筠','唐','御定全唐诗','yuding','','[]','細雨濛濛入絳紗，湖亭寒食孟珠家。',32,'御定全唐詩/json/583.json','["細雨濛濛入絳紗，湖亭寒食孟珠家。", "南朝漫自稱流品，宮體何曾為杏花。"]'),
('yuding-1','細雨','溫庭筠','唐','御定全唐诗','yuding','','[]','憑軒望秋雨，涼入暑衣清。極目鳥頻沒，片時雲複輕。',48,'御定全唐詩/json/583.json','["憑軒望秋雨，涼入暑衣清。極目鳥頻沒，片時雲複輕。", "沼萍開更斂，山葉動還鳴。楚客秋江上，蕭蕭故國情。"]'),
('yuding-2','秋雨','溫庭筠','唐','御定全唐诗','yuding','','[]','雲滿鳥行滅，池涼龍氣腥。斜飄看棋簟，疏灑望山亭。',48,'御定全唐詩/json/583.json','["雲滿鳥行滅，池涼龍氣腥。斜飄看棋簟，疏灑望山亭。", "細響鳴林葉，圓文破沼萍。秋陰杳無際，平野但冥冥。"]'),
('yuding-3','春初對暮雨','溫庭筠','唐','御定全唐诗','yuding','','[]','淅瀝生叢筱，空蒙泫網軒。暝姿看遠樹，春意入塵根。',72,'御定全唐詩/json/583.json','["淅瀝生叢筱，空蒙泫網軒。暝姿看遠樹，春意入塵根。", "點細飄風急，聲輕入夜繁。雀喧爭槿樹，人靜出蔬園。", "瓦濕光先起，房深影易昏。不應江上草，相與滯王孫。"]'),
('yuding-4','雪二首','溫庭筠','唐','御定全唐诗','yuding','','[]','硯水池先凍，窗風酒易消。鴉聲出山郭，人跡過村橋。',120,'御定全唐詩/json/583.json','["硯水池先凍，窗風酒易消。鴉聲出山郭，人跡過村橋。", "稍急方縈轉，才深未寂寥。細光穿暗隙，輕白駐寒條。", "草靜封還折，松欹墮複搖。謝莊今病眼，無意坐通宵。", "羸驂出更慵，林寺已疏鐘。踏緊寒聲澀，飛交細點重。", "圃斜人過跡，階靜鳥行蹤。寂寞梁鴻病，誰人代夜舂。"]'),
('yuding-5','送人游淮海','溫庭筠','唐','御定全唐诗','yuding','','[]','背檣燈色暗，宿客夢初成。半夜竹窗雨，滿池荷葉聲。',48,'御定全唐詩/json/583.json','["背檣燈色暗，宿客夢初成。半夜竹窗雨，滿池荷葉聲。", "簟涼秋合思，木落故山情。明發又愁起，桂花溪水清。"]'),
('yuding-6','原隰荑綠柳','溫庭筠','唐','御定全唐诗','yuding','','[]','迥野韶光早，晴川柳滿堤。拂塵生嫩綠，披雪見柔荑。',72,'御定全唐詩/json/583.json','["迥野韶光早，晴川柳滿堤。拂塵生嫩綠，披雪見柔荑。", "碧玉牙猶短，黃金縷未齊。腰肢弄寒吹，眉意入春閨。", "預恐狂夫折，迎牽逸客迷。新鶯將出谷，應借一枝棲。"]'),
('yuding-7','宿秦生山齋','溫庭筠','唐','御定全唐诗','yuding','','[]','衡巫路不同，結室在東峰。歲晚得支遁，夜寒逢戴顒。',48,'御定全唐詩/json/583.json','["衡巫路不同，結室在東峰。歲晚得支遁，夜寒逢戴顒。", "龕燈落葉寺，山雪隔林鐘。行解無由發，曹溪欲施舂。"]'),
('yuding-8','贈楚雲上人','溫庭筠','唐','御定全唐诗','yuding','','[]','松根滿苔石，盡日閉禪關。有伴年年月，無家處處山。',48,'御定全唐詩/json/583.json','["松根滿苔石，盡日閉禪關。有伴年年月，無家處處山。", "煙波五湖遠，瓶屨一身閑。岳寺蕙蘭晚，幾時幽鳥還。"]'),
('yuding-9','宿白蓋峰寺寄僧','溫庭筠','唐','御定全唐诗','yuding','','[]','山房霜氣晴，一宿遂平生。合上見林影，月中聞澗聲。',48,'御定全唐詩/json/583.json','["山房霜氣晴，一宿遂平生。合上見林影，月中聞澗聲。", "佛燈銷永夜，僧磬徹寒更。不學何居士，焚香為宦情。"]'),
('yuding-10','送僧東游','溫庭筠','唐','御定全唐诗','yuding','','[]','師歸舊山去，此別已淒然。燈影秋江寺，篷聲夜雨船。',48,'御定全唐詩/json/583.json','["師歸舊山去，此別已淒然。燈影秋江寺，篷聲夜雨船。", "鷗飛吳市外，麟臥晉陵前。若到東林社，誰人更問禪。"]'),
('yuding-11','磐石寺留別成公','溫庭筠','唐','御定全唐诗','yuding','','[]','槲葉蕭蕭帶葦風，寺前歸客別支公。三秋岸雪花初白，',40,'御定全唐詩/json/583.json','["槲葉蕭蕭帶葦風，寺前歸客別支公。三秋岸雪花初白，", "悠然旅榜頻回首，無複松窗半偈同。"]'),
('yuding-12','題中南佛塔寺','溫庭筠','唐','御定全唐诗','yuding','','[]','鳴泉隔翠微，千里到柴扉。地勝人無欲，林昏虎有威。',48,'御定全唐詩/json/583.json','["鳴泉隔翠微，千里到柴扉。地勝人無欲，林昏虎有威。", "澗苔侵客屨，山雪入禪衣。桂樹芳陰在，還期歲晏歸。"]'),
('yuding-13','馬嵬佛寺','溫庭筠','唐','御定全唐诗','yuding','','[]','荒雞夜唱戰塵深，五鼓雕輿過上林。才信傾城是真語，',40,'御定全唐詩/json/583.json','["荒雞夜唱戰塵深，五鼓雕輿過上林。才信傾城是真語，", "曼倩死來無絕藝，後人誰肯惜青禽。"]'),
('yuding-14','清涼寺','溫庭筠','唐','御定全唐诗','yuding','','[]','黃花紅樹謝芳蹊，宮殿參差黛巘西。詩合曉窗藏雪嶺，',40,'御定全唐詩/json/583.json','["黃花紅樹謝芳蹊，宮殿參差黛巘西。詩合曉窗藏雪嶺，", "妙跡奇名竟何在，下方煙暝草萋萋。"]'),
('yuding-15','贈盧長史','溫庭筠','唐','御定全唐诗','yuding','','[]','移病欲成隱，扁舟歸舊居。地深新事少，官散故交疏。',48,'御定全唐詩/json/583.json','["移病欲成隱，扁舟歸舊居。地深新事少，官散故交疏。", "道直更無侶，家貧唯有書。東門煙水夢，非獨為鱸魚。"]'),
('yuding-16','秋日旅舍寄義山李侍禦','溫庭筠','唐','御定全唐诗','yuding','','[]','一水悠悠隔渭城，渭城風物近柴荊。寒蛩乍響催機杼，',40,'御定全唐詩/json/583.json','["一水悠悠隔渭城，渭城風物近柴荊。寒蛩乍響催機杼，", "子虛何處堪消渴，試向文園問長卿。"]'),
('yuding-17','晚坐寄友人','溫庭筠','唐','御定全唐诗','yuding','','[]','九枝燈在瑣窗空，希逸無聊恨不同。曉夢未離金夾膝，',40,'御定全唐詩/json/583.json','["九枝燈在瑣窗空，希逸無聊恨不同。曉夢未離金夾膝，", "應卷鰕簾看皓齒，鏡中惆悵見梧桐。"]'),
('yuding-18','送渤海王子歸本國','溫庭筠','唐','御定全唐诗','yuding','','[]','疆理雖重海，車書本一家。盛勳歸舊國，佳句在中華。',48,'御定全唐詩/json/583.json','["疆理雖重海，車書本一家。盛勳歸舊國，佳句在中華。", "定界分秋漲，開帆到曙霞。九門風月好，回首是天涯。"]'),
('yuding-19','送北陽袁明府','溫庭筠','唐','御定全唐诗','yuding','','[]','楚鄉千里路，君去及良晨。葦浦迎船火，茶山候吏塵。',48,'御定全唐詩/json/583.json','["楚鄉千里路，君去及良晨。葦浦迎船火，茶山候吏塵。", "桑濃蠶臥晚，麥秀雉聲春。莫作東籬興，青雲有故人。"]'),
('yuding-20','送李生歸舊居','溫庭筠','唐','御定全唐诗','yuding','','[]','一從征戰後，故社幾人歸。薄宦離山久，高談與世稀。',48,'御定全唐詩/json/583.json','["一從征戰後，故社幾人歸。薄宦離山久，高談與世稀。", "夕陽當板檻，春日入柴扉。莫卻嚴灘意，西溪有釣磯。"]'),
('yuding-21','早春滻水送友人','溫庭筠','唐','御定全唐诗','yuding','','[]','青門煙野外，渡滻送行人。鴨臥溪沙暖，鳩鳴社樹春。',48,'御定全唐詩/json/583.json','["青門煙野外，渡滻送行人。鴨臥溪沙暖，鳩鳴社樹春。", "殘波青有石，幽草綠無塵。楊柳東風裏，相看淚滿巾。"]'),
('yuding-22','送襄州李中丞赴從事','溫庭筠','唐','御定全唐诗','yuding','','[]','漢庭文采有相如，天子通宵愛子虛。把釣看棋高興盡，',40,'御定全唐詩/json/583.json','["漢庭文采有相如，天子通宵愛子虛。把釣看棋高興盡，", "江雨瀟瀟帆一片，此行誰道為鱸魚。"]'),
('yuding-23','江上別友人','溫庭筠','唐','御定全唐诗','yuding','','[]','秋色滿葭菼，離人西複東。幾年方暫見，一笑又難同。',48,'御定全唐詩/json/583.json','["秋色滿葭菼，離人西複東。幾年方暫見，一笑又難同。", "地勢蕭陵歇，江聲禹廟空。如何暮灘上，千里逐征鴻。"]'),
('yuding-24','與友人別','溫庭筠','唐','御定全唐诗','yuding','','[]','半醉別都門，含淒上古原。晚風楊葉社，寒食杏花村。',48,'御定全唐詩/json/583.json','["半醉別都門，含淒上古原。晚風楊葉社，寒食杏花村。", "薄暮牽離緒，傷春憶晤言。年芳本無限，何況有蘭孫。"]'),
('yuding-25','鴻臚寺有開元中錫宴堂樓臺池沼雅為勝絕荒涼遺址僅有存者偶成四十韻','溫庭筠','唐','御定全唐诗','yuding','','[]','明皇昔禦極，神聖垂耿光。沈機發雷電，逸躅陵堯湯。',480,'御定全唐詩/json/583.json','["明皇昔禦極，神聖垂耿光。沈機發雷電，逸躅陵堯湯。", "西覃積石山，北至窮發鄉。四凶有獬豸，一臂無螳螂。", "嬋娟得神豔，郁烈聞國香。紫絛鳴羯鼓，玉管吹霓裳。", "祿山未封侯，林甫才為郎。昭融廓日月，妥帖安紀綱。", "群生到壽域，百辟趨明堂。四海正夷宴，一塵不飛揚。", "天子自猶豫，侍臣宜樂康。軋然閶闔開，赤日生扶桑。", "玉砌露盤紆，金壺漏丁當。劍佩相擊觸，左右隨趨蹌。", "玄珠十二旒，紅粉三千行。顧盻生羽翼，叱嗟回雪霜。", "神霞淩雲閣，春水驪山陽。盤鬥九子粽，甌擎五雲漿。", "雙瓊京兆博，七鼓邯鄲娼。毰毸碧雞鬥，蘢蔥翠雉場。", "仗官繡蔽膝，寶馬金鏤錫。椒塗隔鸚鵡，柘彈驚鴛鴦。", "猗歟華國臣，鬢髮俱蒼蒼。錫宴得幽致，車從真煒煌。", "畫鷁照魚鱉，鳴騶亂甃鶬。颭灩蕩碧波，炫煌迷橫塘。", "縈盈舞回雪，宛轉歌繞梁。豔帶畫銀絡，寶梳金鈿筐。", "沈冥類漢相，醉倒疑楚狂。一旦紫微東，胡星森耀芒。", "憑陵逐鯨鯢，唐突驅犬羊。縱火三月赤，戰塵千里黃。", "殽函與府寺，從此俱荒涼。茲地乃蔓草，故基摧壞牆。", "枯池接斷岸，唧唧啼寒螿。敗荷塌作泥，死竹森如槍。", "遊人問老吏，相對聊感傷。豈必見麋鹿，然後堪回腸。", "幸今遇太平，令節稱羽觴。誰知曲江曲，歲歲棲鸞凰。"]'),
('yuding-26','訪知玄上人遇暴經因有贈','溫庭筠','唐','御定全唐诗','yuding','','[]','縹帙無塵滿畫廊，鐘山弟子靜焚香。惠能未肯傳心法，',40,'御定全唐詩/json/583.json','["縹帙無塵滿畫廊，鐘山弟子靜焚香。惠能未肯傳心法，", "客兒自有翻經處，江上秋來蕙草荒。"]'),
('yuding-27','寄崔先生','溫庭筠','唐','御定全唐诗','yuding','','[]','往年江海別元卿，家近山陽古郡城。蓮浦香中離席散，',40,'御定全唐詩/json/583.json','["往年江海別元卿，家近山陽古郡城。蓮浦香中離席散，", "菰黍正肥魚正美，五侯門下負平生。"]'),
('yuding-28','敬答李先生','溫庭筠','唐','御定全唐诗','yuding','','[]','七裏灘聲舜廟前，杏花初盛草芊芊。綠昏晴氣春風岸，',40,'御定全唐詩/json/583.json','["七裏灘聲舜廟前，杏花初盛草芊芊。綠昏晴氣春風岸，", "一瓢無事麛裘暖，手弄溪波坐釣船。"]'),
('yuding-29','宿灃曲僧舍','溫庭筠','唐','御定全唐诗','yuding','','[]','東郊和氣新，芳靄遠如塵。客舍停疲馬，僧牆畫故人。',48,'御定全唐詩/json/583.json','["東郊和氣新，芳靄遠如塵。客舍停疲馬，僧牆畫故人。", "沃田桑景晚，平野菜花春。更想嚴家瀨，微風蕩白蘋。"]'),
('yuding-30','宿一公精舍','溫庭筠','唐','御定全唐诗','yuding','','[]','夜闌黃葉寺，瓶錫兩俱能。松下石橋路，雨中山殿燈。',48,'御定全唐詩/json/583.json','["夜闌黃葉寺，瓶錫兩俱能。松下石橋路，雨中山殿燈。", "茶爐天姥客，棋席剡溪僧。還笑長門賦，高秋臥茂陵。"]'),
('yuding-31','月中宿雲居寺上方','溫庭筠','唐','御定全唐诗','yuding','','[]','虛合披衣坐，寒階踏葉行。眾星中夜少，圓月上方明。',48,'御定全唐詩/json/583.json','["虛合披衣坐，寒階踏葉行。眾星中夜少，圓月上方明。", "靄盡無林色，暄餘有澗聲。只應愁恨事，還逐曉光生。"]'),
('yuding-32','登盧氏台','溫庭筠','唐','御定全唐诗','yuding','','[]','勝地當通邑，前山有故居。台高秋盡出，林斷野無餘。',48,'御定全唐詩/json/583.json','["勝地當通邑，前山有故居。台高秋盡出，林斷野無餘。", "白露鳴蛩急，晴天度雁疏。由來放懷地，非獨在吾廬。"]'),
('yuding-33','牡丹二首','溫庭筠','唐','御定全唐诗','yuding','','[]','輕陰隔翠幃，宿雨泣晴暉。醉後佳期在，歌餘舊意非。',88,'御定全唐詩/json/583.json','["輕陰隔翠幃，宿雨泣晴暉。醉後佳期在，歌餘舊意非。", "蝶繁經粉住，蜂重抱香歸。莫惜熏爐夜，因風到舞衣。", "水漾晴紅壓疊波，曉來金粉覆庭莎。裁成豔思偏應巧，", "華堂客散簾垂地，想憑闌幹斂翠蛾。"]'),
('yuding-34','反生桃花發因題','溫庭筠','唐','御定全唐诗','yuding','','[]','疾眼逢春四壁空，夜來山雪破東風。未知王母千年熟，',40,'御定全唐詩/json/583.json','["疾眼逢春四壁空，夜來山雪破東風。未知王母千年熟，", "僧虔蠟炬高三尺，莫惜連宵照露叢。"]'),
('yuding-35','杏花','溫庭筠','唐','御定全唐诗','yuding','','[]','紅花初綻雪花繁，重疊高低滿小園。正見盛時猶悵望，',40,'御定全唐詩/json/583.json','["紅花初綻雪花繁，重疊高低滿小園。正見盛時猶悵望，", "杳杳豔歌春日午，出牆何處隔朱門。"]'),
('yuding-36','和太常杜少卿東都修行裏有嘉蓮','溫庭筠','唐','御定全唐诗','yuding','','[]','春秋罷注直銅龍，舊宅嘉蓮照水紅。兩處龜巢清露裏，',40,'御定全唐詩/json/583.json','["春秋罷注直銅龍，舊宅嘉蓮照水紅。兩處龜巢清露裏，", "應為臨川多麗句，故持重豔向西風。"]'),
('yuding-37','題磁嶺海棠花','溫庭筠','唐','御定全唐诗','yuding','','[]','幽態竟誰賞，歲華空與期。島回香盡處，泉照豔濃時。',48,'御定全唐詩/json/583.json','["幽態竟誰賞，歲華空與期。島回香盡處，泉照豔濃時。", "蜀彩淡搖曳，吳妝低怨思。王孫又誰恨，惆悵下山遲。"]'),
('yuding-38','苦楝花','溫庭筠','唐','御定全唐诗','yuding','','[]','院裏鶯歌歇，牆頭蝶舞孤。天香熏羽葆，宮紫暈流蘇。',48,'御定全唐詩/json/583.json','["院裏鶯歌歇，牆頭蝶舞孤。天香熏羽葆，宮紫暈流蘇。", "晻曖迷青瑣，氤氳向畫圖。只應春惜別，留與博山爐。"]'),
('yuding-39','自有扈至京師已後朱櫻之期','溫庭筠','唐','御定全唐诗','yuding','','[]','露圓霞赤數千枝，銀籠誰家寄所思。秦苑飛禽諳熟早，',40,'御定全唐詩/json/583.json','["露圓霞赤數千枝，銀籠誰家寄所思。秦苑飛禽諳熟早，", "盡日徘徊濃影下，只應重作釣魚期。"]'),
('yuding-40','答段柯古見嘲','溫庭筠','唐','御定全唐诗','yuding','','[]','彩翰殊翁金繚繞，一千二百逃飛鳥。',32,'御定全唐詩/json/583.json','["彩翰殊翁金繚繞，一千二百逃飛鳥。", "尾薪橋下未為癡，暮雨朝雲世間少。"]'),
('yuding-41','蓮花','溫庭筠','唐','御定全唐诗','yuding','','[]','綠塘搖灩接星津，軋軋蘭橈入白蘋。應為洛神波上襪，至今蓮蕊有香塵。',32,'御定全唐詩/json/583.json','["綠塘搖灩接星津，軋軋蘭橈入白蘋。應為洛神波上襪，至今蓮蕊有香塵。"]'),
('yuding-42','過吳景帝陵','溫庭筠','唐','御定全唐诗','yuding','','[]','王氣銷來水淼茫，豈能才與命相妨。',32,'御定全唐詩/json/583.json','["王氣銷來水淼茫，豈能才與命相妨。", "虛開直瀆三千里，青蓋何曾到洛陽。"]'),
('yuding-43','龍尾驛婦人圖','溫庭筠','唐','御定全唐诗','yuding','','[]','慢笑開元有幸臣，直教天子到蒙塵。',32,'御定全唐詩/json/583.json','["慢笑開元有幸臣，直教天子到蒙塵。", "今來看畫猶如此，何況親逢絕世人。"]'),
('yuding-44','薛氏池垂釣','溫庭筠','唐','御定全唐诗','yuding','','[]','池塘經雨更蒼蒼，萬點荷珠曉氣涼。',32,'御定全唐詩/json/583.json','["池塘經雨更蒼蒼，萬點荷珠曉氣涼。", "朱瑀空偷禦溝水，錦鱗紅尾屬嚴光。"]'),
('yuding-45','簡同志','溫庭筠','唐','御定全唐诗','yuding','','[]','開濟由來變盛衰，五車才得號鎡基。',32,'御定全唐詩/json/583.json','["開濟由來變盛衰，五車才得號鎡基。", "留侯功業何容易，一卷兵書作帝師。"]'),
('yuding-46','瑟瑟釵','溫庭筠','唐','御定全唐诗','yuding','','[]','翠染冰輕透露光，墮雲孫壽有餘香。',32,'御定全唐詩/json/583.json','["翠染冰輕透露光，墮雲孫壽有餘香。", "只因七夕回天浪，添作湘妃淚兩行。"]'),
('yuding-47','元日','溫庭筠','唐','御定全唐诗','yuding','','[]','神耀破氛昏，新陽入晏溫。緒風調玉吹，端日應銅渾。',48,'御定全唐詩/json/583.json','["神耀破氛昏，新陽入晏溫。緒風調玉吹，端日應銅渾。", "威鳳蹌瑤簴，升龍護璧門。雨暘春令煦，裘冕晬容尊。"]'),
('yuding-48','二月十五日櫻桃盛開自所居躡履吟玩競名王澤章洋才','溫庭筠','唐','御定全唐诗','yuding','','[]','曉覺籠煙重，春深染雪輕。靜應留得蝶，繁欲不勝鶯。',48,'御定全唐詩/json/583.json','["曉覺籠煙重，春深染雪輕。靜應留得蝶，繁欲不勝鶯。", "影亂晨飆急，香多夜雨晴。似將千萬恨，西北為卿卿。"]'),
('yuding-49','寒食節日寄楚望二首','溫庭筠','唐','御定全唐诗','yuding','','[]','芳蘭無意綠，弱柳何窮縷。心斷入淮山，夢長穿楚雨。',192,'御定全唐詩/json/583.json','["芳蘭無意綠，弱柳何窮縷。心斷入淮山，夢長穿楚雨。", "繁花如二八，好月當三五。愁碧竟平皋，韶紅換幽圃。", "流鶯隱員樹，乳燕喧餘哺。曠望戀曾台，離憂集環堵。", "當年不自遣，晚得終何補。鄭谷有樵蘇，歸來要腰斧。", "家乏兩千萬，時當一百五。颸颸楊柳風，穰穰櫻桃雨。", "年芳苦沉潦，心事如摧櫓。金犢近蘭汀，銅龍接花塢。", "青蔥建楊宅，隱轔端門鼓。彩素拂庭柯，輕球落鄰圃。", "三春謝遊衍，一笑牽規矩。獨有恩澤侯，歸來看楚舞。"]'),
('yuding-50','清明日','溫庭筠','唐','御定全唐诗','yuding','','[]','清娥畫扇中，春樹郁金紅。出犯繁花露，歸穿弱柳風。',48,'御定全唐詩/json/583.json','["清娥畫扇中，春樹郁金紅。出犯繁花露，歸穿弱柳風。", "馬驕偏避幰，雞駭乍開籠。柘彈何人發，黃鸝隔故宮。"]'),
('yuding-51','禁火日','溫庭筠','唐','御定全唐诗','yuding','','[]','駘蕩清明日，儲胥小苑東。舞衫萱草綠，春鬢杏花紅。',48,'御定全唐詩/json/583.json','["駘蕩清明日，儲胥小苑東。舞衫萱草綠，春鬢杏花紅。", "馬轡輕銜雪，車衣弱向風。□愁聞百舌，殘睡正朦朧。"]'),
('yuding-52','嘲三月十八日雪','溫庭筠','唐','御定全唐诗','yuding','','[]','三月雪連夜，未應傷物華。只緣春欲盡，留著伴梨花。',24,'御定全唐詩/json/583.json','["三月雪連夜，未應傷物華。只緣春欲盡，留著伴梨花。"]'),
('yuding-53','楊柳八首','溫庭筠','唐','御定全唐诗','yuding','','[]','宜春苑外最長條，閑嫋春風伴舞腰。',256,'御定全唐詩/json/583.json','["宜春苑外最長條，閑嫋春風伴舞腰。", "正是玉人腸斷處，一渠春水赤闌橋。", "南內牆東禦路旁，預知春色柳絲黃。", "杏花未肯無情思，何是情人最斷腸。", "蘇小門前柳萬條，毿毿金線拂平橋。", "黃鶯不語東風起，深閉朱門伴細腰。", "金縷毿毿碧瓦溝，六宮眉黛惹春愁。", "晚來更帶龍池雨，半拂闌幹半入樓。", "館娃宮外鄴城西，遠映征帆近拂堤。", "系得王孫歸意切，不關春草綠萋萋。", "兩兩黃鸝色似金，嫋枝啼露動芳音。", "春來幸自長如線，可惜牽纏蕩子心。", "禦柳如絲映九重，鳳凰窗柱繡芙蓉。", "景陽樓畔千條露，一面新妝待曉鐘。", "織錦機邊鶯語頻，停梭垂淚憶征人。", "塞門三月猶蕭索，縱有垂楊未覺春。"]'),
('yuding-54','客愁','溫庭筠','唐','御定全唐诗','yuding','','[]','客愁看柳色，日日逐春深。蕩漾春風裏，誰知曆亂心。',24,'御定全唐詩/json/583.json','["客愁看柳色，日日逐春深。蕩漾春風裏，誰知曆亂心。"]'),
('yuding-55','和周繇','溫庭筠','唐','御定全唐诗','yuding','','[]','齊馬馳千駟，盧姬逞十三。玳筵方喜睞，金勒自䟃𧽼。',72,'御定全唐詩/json/583.json','["齊馬馳千駟，盧姬逞十三。玳筵方喜睞，金勒自䟃𧽼。", "墮珥情初洽，鳴鞭戰未酣。神交花冉冉，眉語柳毿毿。", "卻略青鸞鏡，翹翻翠鳳篸。專城有佳對，寧肯顧春蠶。"]'),
('yuding-56','光風亭夜宴妓有醉毆者','溫庭筠','唐','御定全唐诗','yuding','','[]','吳國初成陣，王家欲解圍。拂巾雙雉叫，飄瓦兩鴛飛。',24,'御定全唐詩/json/583.json','["吳國初成陣，王家欲解圍。拂巾雙雉叫，飄瓦兩鴛飛。"]'),
('yuding-57','南歌子詞二首','溫庭筠','唐','御定全唐诗','yuding','','[]','一尺深紅勝曲塵，天生舊物不如新。',64,'御定全唐詩/json/583.json','["一尺深紅勝曲塵，天生舊物不如新。", "合歡桃核終堪恨，裏許元來別有人。", "井底點燈深燭伊，共郎長行莫圍棋。", "玲瓏骰子安紅豆，入骨相思知不知。"]'),
('yuding-58','題李衛公詩二首','溫庭筠','唐','御定全唐诗','yuding','','[]','蒿棘深春衛國門，九年於此盜乾坤。兩行密疏傾天下，',80,'御定全唐詩/json/583.json','["蒿棘深春衛國門，九年於此盜乾坤。兩行密疏傾天下，", "當時誰是承恩者，肯有餘波達鬼村。", "勢欲淩雲威觸天，權傾諸夏力排山。三年驥尾有人附，", "千岩萬壑應惆悵，流水斜傾出武關。"]'),
('yuding-59','題谷隱蘭若','溫庭筠','唐','御定全唐诗','yuding','','[]','風帶巢熊拗樹聲，老僧相引入雲行。',32,'御定全唐詩/json/583.json','["風帶巢熊拗樹聲，老僧相引入雲行。", "半坡新路畬才了，一穀寒煙燒不成。"]'),
('yuding-60','觀棋','溫庭筠','唐','御定全唐诗','yuding','','[]','閑對楸枰傾一壺，黃華坪上幾成盧。',32,'御定全唐詩/json/583.json','["閑對楸枰傾一壺，黃華坪上幾成盧。", "他時謁帝銅龍水，便賭宣城太守無。"]'),
('yuding-61','句','溫庭筠','唐','御定全唐诗','yuding','','[]','春水碧於天，畫船聽雨眠。',34,'御定全唐詩/json/583.json','["春水碧於天，畫船聽雨眠。", "綠樹繞村含細雨，寒潮背郭卷平沙。（《送人》，"]'),
('yuding-0','觀山燈獻徐尚書','段成式','唐','御定全唐诗','yuding','','[]','風杪影淩亂，露輕光陸離。如霞散仙掌，似燒上峨嵋。',144,'御定全唐詩/json/584.json','["風杪影淩亂，露輕光陸離。如霞散仙掌，似燒上峨嵋。", "道樹千花發，扶桑九日移。因山成眾像，不復藉蟠螭。", "湧出多寶塔，往來飛錫僧。分明三五月，傳照百千燈。", "馴狖移高柱，慶雲遮半層。夜深寒焰白，猶自綴金繩。", "磊落風初定，輕明雲乍妨。疏中搖月彩，繁處雜星芒。", "火樹枝柯密，燭龍鱗甲張。窮愁讀書者，應得假餘光。"]'),
('yuding-1','和徐商賀盧員外賜緋','段成式','唐','御定全唐诗','yuding','','[]','雲雨軒懸鶯語新，一篇佳句占陽春。銀黃年少偏欺酒，',40,'御定全唐詩/json/584.json','["雲雨軒懸鶯語新，一篇佳句占陽春。銀黃年少偏欺酒，", "莫辭倒載吟歸去，看欲東山又吐茵。"]'),
('yuding-2','河出榮光','段成式','唐','御定全唐诗','yuding','','[]','符命自陶唐，吾君應會昌。千年清德水，九折滿榮光。',96,'御定全唐詩/json/584.json','["符命自陶唐，吾君應會昌。千年清德水，九折滿榮光。", "極岸浮佳氣，微波照夕陽。澄輝明貝闕，散彩入龍堂。", "近帶關雲紫，遙連日道黃。馮夷矜海若，漢武貴宣房。", "漸沒孤槎影，仍呈一葦航。撫躬悲未濟，作頌喜時康。"]'),
('yuding-3','哭李群玉','段成式','唐','御定全唐诗','yuding','','[]','曾話黃陵事，今為白日催。老無兒女累，誰哭到泉台。',24,'御定全唐詩/json/584.json','["曾話黃陵事，今為白日催。老無兒女累，誰哭到泉台。"]'),
('yuding-4','寄溫飛卿箋紙','段成式','唐','御定全唐诗','yuding','','[]','三十六鱗充使時，數番猶得裹相思。',32,'御定全唐詩/json/584.json','["三十六鱗充使時，數番猶得裹相思。", "待將袍襖重抄了，盡寫襄陽播掿詞。"]'),
('yuding-5','題石泉蘭若','段成式','唐','御定全唐诗','yuding','','[]','矗竹為籬松作門，石楠陰底藉芳蓀。',32,'御定全唐詩/json/584.json','["矗竹為籬松作門，石楠陰底藉芳蓀。", "方袍近日少平叔，注得逍遙無處論。"]'),
('yuding-6','怯酒贈周繇','段成式','唐','御定全唐诗','yuding','','[]','大白東西飛正狂，新芻石凍雜梅香。',32,'御定全唐詩/json/584.json','["大白東西飛正狂，新芻石凍雜梅香。", "詩中反語常回避，尤怯花前喚索郎。"]'),
('yuding-7','牛尊師宅看牡丹','段成式','唐','御定全唐诗','yuding','','[]','洞裏仙春日更長，翠叢風翦紫霞芳。',32,'御定全唐詩/json/584.json','["洞裏仙春日更長，翠叢風翦紫霞芳。", "若為蕭史通家客，情願扛壺入醉鄉。"]'),
('yuding-8','觀棋','段成式','唐','御定全唐诗','yuding','','[]','閑對弈楸傾一壺，黃羊枰上幾成都。',32,'御定全唐詩/json/584.json','["閑對弈楸傾一壺，黃羊枰上幾成都。", "他時謁帝銅池曉，便賭宣城太守無。"]'),
('yuding-9','題僧壁','段成式','唐','御定全唐诗','yuding','','[]','有僧支頰撚眉毫，起就夕陽磨剃刀。',32,'御定全唐詩/json/584.json','["有僧支頰撚眉毫，起就夕陽磨剃刀。", "到此既知閑最樂，俗心何啻九牛毛。"]'),
('yuding-10','哭房處士','段成式','唐','御定全唐诗','yuding','','[]','獨上黃壇幾度盟，印開龍渥喜丹成。',32,'御定全唐詩/json/584.json','["獨上黃壇幾度盟，印開龍渥喜丹成。", "豈同叔夜終無分，空向人間著養生。"]'),
('yuding-11','呈輪上人','段成式','唐','御定全唐诗','yuding','','[]','虎到前頭心不驚，殘陽擇虱懶逢迎。',32,'御定全唐詩/json/584.json','["虎到前頭心不驚，殘陽擇虱懶逢迎。", "東林水石未勝此，要假遠公方有名。"]'),
('yuding-12','題谷隱蘭若三首','段成式','唐','御定全唐诗','yuding','','[]','風惹閑雲半谷陰，岩西隱者醉相尋。',96,'御定全唐詩/json/584.json','["風惹閑雲半谷陰，岩西隱者醉相尋。", "草衰乍覺徑增險，葉盡卻疑溪不深。", "鳥啄靈雛戀落暉，村情山趣頓忘機。", "丹成道士過門數，葉盡寒猿下嶺稀。", "風帶巢熊拗樹聲，老僧相引入雲行。", "半陂新路畬才了，一穀寒煙燒不成。"]'),
('yuding-13','不赴光風亭夜飲贈周繇','段成式','唐','御定全唐诗','yuding','','[]','屏開屈膝見吳娃，蠻蠟同心四照花。',32,'御定全唐詩/json/584.json','["屏開屈膝見吳娃，蠻蠟同心四照花。", "姹女不愁難管領，斬新鉛裏得黃牙。"]'),
('yuding-14','嘲元中丞','段成式','唐','御定全唐诗','yuding','','[]','鶯裏花前選孟光，東山逋客酒初狂。',32,'御定全唐詩/json/584.json','["鶯裏花前選孟光，東山逋客酒初狂。", "素娥畢竟難防備，燒得河車莫遣嘗。"]'),
('yuding-15','寄周繇求人參','段成式','唐','御定全唐诗','yuding','','[]','少賦令才猶強作，眾醫多識不能呼。',32,'御定全唐詩/json/584.json','["少賦令才猶強作，眾醫多識不能呼。", "九莖仙草真難得，五葉靈根許惠無。"]'),
('yuding-16','嘲飛卿七首','段成式','唐','御定全唐诗','yuding','','[]','曾見當壚一個人，入時裝束好腰身。',224,'御定全唐詩/json/584.json','["曾見當壚一個人，入時裝束好腰身。", "少年花蒂多芳思，只向詩中寫取真。", "醉袂幾侵魚子纈，飄纓長罥鳳凰釵。", "知君欲作閒情賦，應願將身作錦鞋。", "翠蝶密偎金叉首，青蟲危泊玉釵梁。", "愁生半額不開靨，只為多情團扇郎。", "柳煙梅雪隱青樓，殘日黃鸝語未休。", "見說自能裁袙腹，不知誰更著帩頭。", "愁機懶織同心苣，悶繡先描連理枝。", "多少風流詞句裏，愁中空詠早環詩。", "燕支山色重能輕，南陽水澤鬥分明。", "不煩射雉先張翳，自有琴中威鳳聲。", "半歲愁中鏡似荷，牽環撩鬢卻須磨。", "花前不復抱瓶渴，月底還應琢刺歌。"]'),
('yuding-17','柔卿解籍戲呈飛卿三首','段成式','唐','御定全唐诗','yuding','','[]','長擔犢車初入門，金牙新醞盈深樽。',96,'御定全唐詩/json/584.json','["長擔犢車初入門，金牙新醞盈深樽。", "良人為漬木瓜粉，遮卻紅腮交午痕。", "最宜全幅碧鮫綃，自襞春羅等舞腰。", "未有長錢求鄴錦，且令裁取一團嬌。", "出意挑鬟一尺長，金為鈿鳥簇釵梁。", "郁金種得花茸細，添入春衫領裏香。"]'),
('yuding-18','戲高侍禦七首','段成式','唐','御定全唐诗','yuding','','[]','百媚城中一個人，紫羅垂手見精神。',224,'御定全唐詩/json/584.json','["百媚城中一個人，紫羅垂手見精神。", "青琴仙子長教示，自小來來號阿真。", "七尺發猶三角梳，玳牛獨駕長簷車。", "曾城自有三青鳥，不要蓮東雙鯉魚。", "花恨紅腰柳妒眉，東鄰牆短不曾窺。", "猶憐最小分瓜日，奈許迎春得藕時。", "自等腰身尺六強，兩重危鬢盡釵長。", "欲熏羅薦嫌龍腦，須為尋求石葉香。", "別起青樓作幾層，斜陽幔卷鹿盧繩。", "厭裁魚子深紅纈，泥覓蜻蜓淺碧綾。", "詐嫌嚼貝磨衣鈍，私帶男錢壓鬢低。", "不獨邯鄲新嫁女，四枝鬟上插通犀。", "可羨羅敷自有夫，愁中漫捋白髭須。", "豹錢驄子能擎舉，兼著連幹許換無。"]'),
('yuding-19','送僧二首','段成式','唐','御定全唐诗','yuding','','[]','形神不滅論初成，愛馬乘閑入帝京。',64,'御定全唐詩/json/584.json','["形神不滅論初成，愛馬乘閑入帝京。", "四十三年虛過了，方知僧裏有唐生。", "想到頭陀最上方，桂陰猶認惠宗房。", "因行戀燒歸來晚，窗下猶殘一字香。"]'),
('yuding-20','猿','段成式','唐','御定全唐诗','yuding','','[]','卻憶書齋值晚晴，挽枝閑嘯激蟬清。',32,'御定全唐詩/json/584.json','["卻憶書齋值晚晴，挽枝閑嘯激蟬清。", "影沈巴峽夜岩色，蹤絕石塘寒瀨聲。"]'),
('yuding-21','送穆郎中赴闕','段成式','唐','御定全唐诗','yuding','','[]','應念愁中恨索居，鸝歌聲裏且踟躕。',32,'御定全唐詩/json/584.json','["應念愁中恨索居，鸝歌聲裏且踟躕。", "若逢金馬門前客，為說虞卿久著書。"]'),
('yuding-22','題商山廟','段成式','唐','御定全唐诗','yuding','','[]','偶出雲泉謁禮闈，篇章曾沐漢皇知。',32,'御定全唐詩/json/584.json','["偶出雲泉謁禮闈，篇章曾沐漢皇知。", "無謀靜國東歸去，羞過商山四老祠。"]'),
('yuding-23','折楊柳七首','段成式','唐','御定全唐诗','yuding','','[]','枝枝交影鎖長門，嫩色曾沾雨露恩。',224,'御定全唐詩/json/584.json','["枝枝交影鎖長門，嫩色曾沾雨露恩。", "鳳輦不來春欲盡，空留鶯語到黃昏。", "水殿年年占早芳，柔條偏惹禦爐香。", "而今萬乘多巡狩，輦路無陰綠草長。", "玉樓煙薄不勝芳，金屋寒輕翠帶長。", "公子驊騮往何處，綠陰堪系紫遊韁。", "嫩葉初齊不耐寒，風和時拂玉欄幹。", "君王去日曾攀折，泣雨傷春翠黛殘。", "微黃才綻未成陰，繡戶珠簾相映深。", "長恨早梅無賴極，先將春色出前林。", "隋家堤上已成塵，漢將營邊不復春。", "只向江南並塞北，酒旗相伴惹行人。", "陌上河邊千萬枝，怕寒愁雨盡低垂。", "黃金穟短人多折，已恨東風不展眉。"]'),
('yuding-24','哭李群玉','段成式','唐','御定全唐诗','yuding','','[]','酒裏詩中三十年，縱橫唐突世喧喧。',32,'御定全唐詩/json/584.json','["酒裏詩中三十年，縱橫唐突世喧喧。", "明時不作禰衡死，傲盡公卿歸九泉。"]'),
('yuding-25','漢宮詞二首','段成式','唐','御定全唐诗','yuding','','[]','歌舞初承恩寵時，六宮學妾畫蛾眉。',64,'御定全唐詩/json/584.json','["歌舞初承恩寵時，六宮學妾畫蛾眉。", "君王厭世妾頭白，聞唱歌聲卻淚垂。", "二人能歌得進名，人言選入便光榮。", "豈知妃後多嬌妒，不許君前唱一聲。"]'),
('yuding-26','醉中吟','段成式','唐','御定全唐诗','yuding','','[]','只愛糟床滴滴聲，長愁聲絕又醒醒。',32,'御定全唐詩/json/584.json','["只愛糟床滴滴聲，長愁聲絕又醒醒。", "人間榮辱不常定，唯有南山依舊青。"]'),
('yuding-27','桃源僧舍看花','段成式','唐','御定全唐诗','yuding','','[]','前年帝裏探春時，寺寺名花我盡知。',32,'御定全唐詩/json/584.json','["前年帝裏探春時，寺寺名花我盡知。", "今日長安已灰燼，忍能南國對芳枝。"]'),
('yuding-28','和周繇見嘲','段成式','唐','御定全唐诗','yuding','','[]','才甘魚目並，藝怯馬蹄間。王謝初飛蓋，姬薑盡下山。',72,'御定全唐詩/json/584.json','["才甘魚目並，藝怯馬蹄間。王謝初飛蓋，姬薑盡下山。", "縛雞方角逐，射雉豈開顏。亂翠移林色，狂紅照座殷。", "防梭齒雖在，乞帽鬢慚斑。儻恕相如瘦，應容累騎還。"]'),
('yuding-29','和張希複詠宣律和尚袈裟','段成式','唐','御定全唐诗','yuding','','[]','南山披時寒夜中，一角不動毗嵐風。',32,'御定全唐詩/json/584.json','["南山披時寒夜中，一角不動毗嵐風。", "何人見此生慚愧，斷續猶應護得龍。"]'),
('yuding-30','句','段成式','唐','御定全唐诗','yuding','','[]','高談敬風鑒，古貌怯冰棱。',134,'御定全唐詩/json/584.json','["高談敬風鑒，古貌怯冰棱。", "虱暴妨歸夢，蟲喧徹曙更。", "夢裏思甘露，言中惜惠燈。", "新破毗曇義，相期蔔夜論。", "隨樵劫猿藏，隈石覷熊緣。", "捽胡雲彩落，疻面月痕消。", "擲履仙鳧起，撦衣蝴蝶飄。羞中含薄怒，顰裏帶餘嬌。", "醒後猶攘臂，歸時更折腰。狂夫自纓絕，眉勢倩人描。", "不願石郎戴笠，難甘玉女披衣。"]'),
('yuding-0','皎皎詞','劉駕','唐','御定全唐诗','yuding','','[]','皎皎複皎皎，逢時即為好。高秋亦有花，不及當春草。',48,'御定全唐詩/json/585.json','["皎皎複皎皎，逢時即為好。高秋亦有花，不及當春草。", "班姬入後宮，飛燕舞東風。青娥中夜起，長歎月明裏。"]'),
('yuding-1','長安旅舍紓情投先達','劉駕','唐','御定全唐诗','yuding','','[]','岐路不在地，馬蹄徒苦辛。上國聞姓名，不如山中人。',96,'御定全唐詩/json/585.json','["岐路不在地，馬蹄徒苦辛。上國聞姓名，不如山中人。", "大宅滿六街，此身入誰門。愁心日散亂，有似空中塵。", "白露下長安，百蟲鳴草根。方當秋賦日，卻憶歸山村。", "靜女頭欲白，良媒況我鄰。無令苦長歎，長歎銷人魂。"]'),
('yuding-2','送友下第游雁門','劉駕','唐','御定全唐诗','yuding','','[]','相別灞水湄，夾水柳依依。我願醉如死，不見君去時。',120,'御定全唐詩/json/585.json','["相別灞水湄，夾水柳依依。我願醉如死，不見君去時。", "所詣星斗北，直行到猶遲。況複挈空囊，求人悲路岐。", "北門記室賢，愛我學古詩。待君如待我，此事固不疑。", "雁門春色外，四月雁未歸。主人拂金台，延客夜開扉。", "舒君鬱鬱懷，飲彼白玉卮。若不化女子，功名豈無期。"]'),
('yuding-3','讀史','劉駕','唐','御定全唐诗','yuding','','[]','平地見天涯，登高天更遠。功名及所望，岐路又滿眼。',60,'御定全唐詩/json/585.json','["平地見天涯，登高天更遠。功名及所望，岐路又滿眼。", "萬金買園林，千金修池館。他人厭遊覽，身獨戀軒冕。", "唯有漢二疏，應覺還家晚。"]'),
('yuding-4','反賈客樂','劉駕','唐','御定全唐诗','yuding','','[]','無言賈客樂，賈客多無墓。行舟觸風浪，盡入魚腹去。',36,'御定全唐詩/json/585.json','["無言賈客樂，賈客多無墓。行舟觸風浪，盡入魚腹去。", "農夫更苦辛，所以羨爾身。"]'),
('yuding-5','送李垣先輩歸嵩少舊居','劉駕','唐','御定全唐诗','yuding','','[]','高秋灞滻路，遊子多慘戚。君於此地行，獨似尋春色。',72,'御定全唐詩/json/585.json','["高秋灞滻路，遊子多慘戚。君於此地行，獨似尋春色。", "文章滿人口，高第非苟得。要路在長安，歸山卻為客。", "□□□□□，狂歌罷歎息。我豈無故山，千里同外國。"]'),
('yuding-6','苦寒吟','劉駕','唐','御定全唐诗','yuding','','[]','百泉凍皆咽，我吟寒更切。半夜倚喬松，不覺滿衣雪。',60,'御定全唐詩/json/585.json','["百泉凍皆咽，我吟寒更切。半夜倚喬松，不覺滿衣雪。", "竹竿有甘苦，我愛抱苦節。鳥聲有悲歡，我愛口流血。", "潘生若解吟，更早生白髮。"]'),
('yuding-7','上巳日','劉駕','唐','御定全唐诗','yuding','','[]','上巳曲江濱，喧于市朝路。相尋不見者，此地皆相遇。',72,'御定全唐詩/json/585.json','["上巳曲江濱，喧于市朝路。相尋不見者，此地皆相遇。", "日光去此遠，翠幕張如霧。何事歡娛中，易覺春城暮。", "物情重此節，不是愛芳樹。明日花更多，何人肯回顧。"]'),
('yuding-8','春台','劉駕','唐','御定全唐诗','yuding','','[]','臺上樹陰合，台前流水多。青春不出門，坐見野田花。',48,'御定全唐詩/json/585.json','["臺上樹陰合，台前流水多。青春不出門，坐見野田花。", "誰能學公子，走馬逐香車。六街塵滿衣，鼓絕方還家。"]'),
('yuding-9','釣台懷古','劉駕','唐','御定全唐诗','yuding','','[]','澄流可濯纓，嚴子但垂綸。孤坐九層石，遠笑清渭濱。',84,'御定全唐詩/json/585.json','["澄流可濯纓，嚴子但垂綸。孤坐九層石，遠笑清渭濱。", "潛龍飛上天，四海豈無雲。清氣不零雨，安使洗塵氛。", "我來吟高風，仿佛見斯人。江月尚皎皎，江石亦磷磷。", "如何台下路，明日又迷津。"]'),
('yuding-10','勵志','劉駕','唐','御定全唐诗','yuding','','[]','白髮豈有情，貴賤同日生。二輪不暫駐，似趁長安程。',72,'御定全唐詩/json/585.json','["白髮豈有情，貴賤同日生。二輪不暫駐，似趁長安程。", "前堂吹參差，不作緱山聲。後園植木槿，月照無餘英。", "及時立功德，身後猶光明。仲尼亦為土，魯人焉敢耕。"]'),
('yuding-11','桑婦','劉駕','唐','御定全唐诗','yuding','','[]','牆下桑葉盡，春蠶半未老。城南路迢迢，今日起更早。',72,'御定全唐詩/json/585.json','["牆下桑葉盡，春蠶半未老。城南路迢迢，今日起更早。", "四鄰無去伴，醉臥青樓曉。妾顏不如誰，所貴守婦道。", "一春常在樹，自覺身如鳥。歸來見小姑，新妝弄百草。"]'),
('yuding-12','上馬歎','劉駕','唐','御定全唐诗','yuding','','[]','羸馬行遲遲，頑童去我遠。時時一回顧，不覺白日晚。',84,'御定全唐詩/json/585.json','["羸馬行遲遲，頑童去我遠。時時一回顧，不覺白日晚。", "路傍豪家宅，樓上紅妝滿。十月庭花開，花前吹玉管。", "君當未貴日，豈不常屯蹇。如何見布衣，忽若塵入眼。", "布衣豈常賤，世事車輪轉。"]'),
('yuding-13','唐樂府十首：送征夫','劉駕','唐','御定全唐诗','yuding','','[]','昔送征夫苦，今送征夫樂。寒衣縱攜去，應向歸時著。',36,'御定全唐詩/json/585.json','["昔送征夫苦，今送征夫樂。寒衣縱攜去，應向歸時著。", "天子待功成，別造淩煙閣。"]'),
('yuding-14','唐樂府十首：輸者謳','劉駕','唐','御定全唐诗','yuding','','[]','挽粟上高山，高山若平地。力盡心不怨，同我家私事。',60,'御定全唐詩/json/585.json','["挽粟上高山，高山若平地。力盡心不怨，同我家私事。", "去者不遑寧，歸者唱歌行。相逢古城下，立語天未明。", "一身遠出塞，十口無稅征。"]'),
('yuding-15','唐樂府十首：吊西人','劉駕','唐','御定全唐诗','yuding','','[]','河湟父老地，盡知歸明主。將軍入空城，城下吊黃土。',36,'御定全唐詩/json/585.json','["河湟父老地，盡知歸明主。將軍入空城，城下吊黃土。", "所願邊人耕，歲歲生禾黍。"]'),
('yuding-16','唐樂府十首：邊軍過','劉駕','唐','御定全唐诗','yuding','','[]','城前兵馬過，城裏人高臥。官家自供給，畏我田產破。',72,'御定全唐詩/json/585.json','["城前兵馬過，城裏人高臥。官家自供給，畏我田產破。", "健兒食肥肉，戰馬食新穀。食飽物有餘，所恨無兩腹。", "草青見軍過，草白見軍回。軍回人更多，盡系西戎來。"]'),
('yuding-17','唐樂府十首：望歸馬','劉駕','唐','御定全唐诗','yuding','','[]','東人望歸馬，馬歸蓮峰下。蓮峰與地平，亦不更徵兵。',24,'御定全唐詩/json/585.json','["東人望歸馬，馬歸蓮峰下。蓮峰與地平，亦不更徵兵。"]'),
('yuding-18','唐樂府十首：祝河水','劉駕','唐','御定全唐诗','yuding','','[]','河水清彌彌，照見遠樹枝。征人不飲馬，再拜祝馮夷。',36,'御定全唐詩/json/585.json','["河水清彌彌，照見遠樹枝。征人不飲馬，再拜祝馮夷。", "從今億萬歲，不見河濁時。"]'),
('yuding-19','唐樂府十首：田西邊','劉駕','唐','御定全唐诗','yuding','','[]','刀劍作鋤犁，耕田古城下。高秋禾黍多，無地放羊馬。',24,'御定全唐詩/json/585.json','["刀劍作鋤犁，耕田古城下。高秋禾黍多，無地放羊馬。"]'),
('yuding-20','唐樂府十首：昆山','劉駕','唐','御定全唐诗','yuding','','[]','肯時玉為寶，昆山過不得。今時玉為塵，昆山入中國。',36,'御定全唐詩/json/585.json','["肯時玉為寶，昆山過不得。今時玉為塵，昆山入中國。", "白玉尚如塵，誰肯愛金銀。"]'),
('yuding-21','唐樂府十首：樂邊人','劉駕','唐','御定全唐诗','yuding','','[]','在鄉身亦勞，在邊腹亦飽。父兄若一處，任向邊頭老。',24,'御定全唐詩/json/585.json','["在鄉身亦勞，在邊腹亦飽。父兄若一處，任向邊頭老。"]'),
('yuding-22','唐樂府十首：獻賀觴','劉駕','唐','御定全唐诗','yuding','','[]','莫但取河湟，河湟非邊疆。願今日入處，亦似天中央。',36,'御定全唐詩/json/585.json','["莫但取河湟，河湟非邊疆。願今日入處，亦似天中央。", "天子壽萬歲，再拜獻此觴。"]'),
('yuding-23','且可憐行','劉駕','唐','御定全唐诗','yuding','','[]','園中花自早，不信外無花。良人未朝去，先出登香車。',84,'御定全唐詩/json/585.json','["園中花自早，不信外無花。良人未朝去，先出登香車。", "□□五□輪，滿城聞嘔啞。侍兒衣各別，頭上金雀多。", "只是一家人，路人疑千家。過後香滿陌，直到春日斜。", "今朝且可憐，莫問久如何。"]'),
('yuding-24','築臺詞','劉駕','唐','御定全唐诗','yuding','','[]','前杵與後杵，築城聲不住。我願築更高，得見秦皇墓。',24,'御定全唐詩/json/585.json','["前杵與後杵，築城聲不住。我願築更高，得見秦皇墓。"]'),
('yuding-25','鄰女','劉駕','唐','御定全唐诗','yuding','','[]','君嫌鄰女醜，取婦他鄉縣。料嫁與君人，亦為鄰所賤。',36,'御定全唐詩/json/585.json','["君嫌鄰女醜，取婦他鄉縣。料嫁與君人，亦為鄰所賤。", "菖蒲花可貴，只為人難見。"]'),
('yuding-26','山中夜坐','劉駕','唐','御定全唐诗','yuding','','[]','半夜山雨過，起來滿山月。落盡醉處花，荒溝水決決。',48,'御定全唐詩/json/585.json','["半夜山雨過，起來滿山月。落盡醉處花，荒溝水決決。", "愴然惜春去，似與故人別。誰遣我多情，壯年無鬢髮。"]'),
('yuding-27','秦娥','劉駕','唐','御定全唐诗','yuding','','[]','秦娥十四五，面白於指爪。羞人夜采桑，驚起戴勝鳥。',24,'御定全唐詩/json/585.json','["秦娥十四五，面白於指爪。羞人夜采桑，驚起戴勝鳥。"]'),
('yuding-28','牧童','劉駕','唐','御定全唐诗','yuding','','[]','牧童見客拜，山果懷中落。晝日驅牛歸，前溪風雨惡。',24,'御定全唐詩/json/585.json','["牧童見客拜，山果懷中落。晝日驅牛歸，前溪風雨惡。"]'),
('yuding-29','古出塞','劉駕','唐','御定全唐诗','yuding','','[]','胡風不開花，四氣多作雪。北人尚凍死，況我本南越。',72,'御定全唐詩/json/585.json','["胡風不開花，四氣多作雪。北人尚凍死，況我本南越。", "古來犬羊地，巡狩無遺轍。九土耕不盡，武皇猶征伐。", "中天有高閣，圖畫何時歇。坐恐塞上山，低於沙中骨。"]'),
('yuding-30','寄遠','劉駕','唐','御定全唐诗','yuding','','[]','雪花豈結子，徒滿連理枝。嫁作征人妻，不得長相隨。',72,'御定全唐詩/json/585.json','["雪花豈結子，徒滿連理枝。嫁作征人妻，不得長相隨。", "去年君點行，賤妾是新姬。別早見未熟，入夢無定姿。", "悄悄空閨中，蛩聲繞羅幃。得書喜猶甚，況複見君時。"]'),
('yuding-31','下第後屏居長安，書懷寄太原從事','劉駕','唐','御定全唐诗','yuding','','[]','刖足豈更長，良工隔千里。故山彭蠡上，歸夢向汾水。',96,'御定全唐詩/json/585.json','["刖足豈更長，良工隔千里。故山彭蠡上，歸夢向汾水。", "低摧神氣盡，僮僕心亦恥。未達誰不然，達者心思此。", "行年忽已壯，去老年更幾。功名生不彰，身歿豈為鬼。", "才看芳草歇，即歎涼風起。匹馬未來期，嘶聲尚在耳。"]'),
('yuding-32','早行','劉駕','唐','御定全唐诗','yuding','','[]','馬上續殘夢，馬嘶時複驚。心孤多所虞，僮僕近我行。',48,'御定全唐詩/json/585.json','["馬上續殘夢，馬嘶時複驚。心孤多所虞，僮僕近我行。", "棲禽未分散，落月照古城。莫羨居者閑，塚邊人已耕。"]'),
('yuding-33','青門路','劉駕','唐','御定全唐诗','yuding','','[]','青門有歸路，坦坦高槐下。貧賤自恥歸，此地誰留我。',72,'御定全唐詩/json/585.json','["青門有歸路，坦坦高槐下。貧賤自恥歸，此地誰留我。", "門開送客去，落日懶回馬。旅食帝城中，不如遠遊者。", "舟成於陸地，風水終相假。吾道諒如斯，立身無苟且。"]'),
('yuding-34','效古','劉駕','唐','御定全唐诗','yuding','','[]','融融芳景和，杳杳春日斜。嬌嬈不自持，清唱嚬雙蛾。',60,'御定全唐詩/json/585.json','["融融芳景和，杳杳春日斜。嬌嬈不自持，清唱嚬雙蛾。", "終曲翻成泣，新人下香車。新人且莫喜，故人曾如此。", "燕趙猶生女，郎豈有終始。"]'),
('yuding-35','戰城南','劉駕','唐','御定全唐诗','yuding','','[]','城南征戰多，城北無饑鴉。白骨馬蹄下，誰言皆有家。',48,'御定全唐詩/json/585.json','["城南征戰多，城北無饑鴉。白骨馬蹄下，誰言皆有家。", "城前水聲苦，倏忽流萬古。莫爭城外城，城裏終閑土。"]'),
('yuding-36','曲江春霽','劉駕','唐','御定全唐诗','yuding','','[]','宿雨洗秦樹，舊花如新開。池邊草未幹，日照人馬來。',60,'御定全唐詩/json/585.json','["宿雨洗秦樹，舊花如新開。池邊草未幹，日照人馬來。", "馬蹄踏流水，漸漸成塵埃。鴛鴦不敢下，飛繞岸東西。", "此地喧仍舊，歸人亦滿街。"]'),
('yuding-37','贈先達','劉駕','唐','御定全唐诗','yuding','','[]','終南蒼翠好，未必如故山。心期在榮名，三載居長安。',96,'御定全唐詩/json/585.json','["終南蒼翠好，未必如故山。心期在榮名，三載居長安。", "昔蒙大雅匠，勉我工五言。業成時不重，辛苦只自憐。", "皎皎機上絲，盡作秦箏弦。貧女皆罷織，富人豈不寒。", "驚風起長波，浩浩何時還。待君當要路，一指王化源。"]'),
('yuding-38','有感','劉駕','唐','御定全唐诗','yuding','','[]','弓劍不自行，難引河湟思。將軍半夜飲，十裏聞歌吹。',48,'御定全唐詩/json/585.json','["弓劍不自行，難引河湟思。將軍半夜飲，十裏聞歌吹。", "高門幾世宅，舞袖仍新賜。誰遣一書來，燈前問邊事。"]'),
('yuding-39','姑蘇台','劉駕','唐','御定全唐诗','yuding','','[]','勾踐飲膽日，吳酒正滿杯。笙歌入海雲，聲自姑蘇來。',84,'御定全唐詩/json/585.json','["勾踐飲膽日，吳酒正滿杯。笙歌入海雲，聲自姑蘇來。", "西施舞初罷，侍兒整金釵。眾女不敢妒，自比泉下泥。", "越鼓聲騰騰，吳天隔塵埃。難將甬東地，更學會稽棲。", "霸跡一朝盡，草中棠梨開。"]'),
('yuding-40','豪家','劉駕','唐','御定全唐诗','yuding','','[]','九陌槐葉盡，青春在豪家。嬌鶯不出城，長宿庭上花。',48,'御定全唐詩/json/585.json','["九陌槐葉盡，青春在豪家。嬌鶯不出城，長宿庭上花。", "高樓登夜半，已見南山多。恩深勢自然，不是愛驕奢。"]'),
('yuding-41','山中有招','劉駕','唐','御定全唐诗','yuding','','[]','朗朗山月出，塵中事由生。人心雖不閑，九陌夜無行。',108,'御定全唐詩/json/585.json','["朗朗山月出，塵中事由生。人心雖不閑，九陌夜無行。", "學古以求聞，有如石上耕。齊薑早作婦，豈識閨中情。", "何如此幽居，地僻人不爭。嘉樹自昔有，茅屋因我成。", "取薪不出門，采藥於前庭。春花雖無種，枕席芙蓉馨。", "君來食葵藿，天爵豈不榮。"]'),
('yuding-42','空城雀','劉駕','唐','御定全唐诗','yuding','','[]','饑啄空城土，莫近太倉粟。一粒未充腸，卻入公子腹。',48,'御定全唐詩/json/585.json','["饑啄空城土，莫近太倉粟。一粒未充腸，卻入公子腹。", "且吊城上骨，幾曾害爾族。不聞莊辛語，今日寒蕪綠。"]'),
('yuding-43','馮叟居','劉駕','唐','御定全唐诗','yuding','','[]','天作馮叟居，山僧尚嫌僻。開門因兩樹，結宇倚翠壁。',96,'御定全唐詩/json/585.json','["天作馮叟居，山僧尚嫌僻。開門因兩樹，結宇倚翠壁。", "溪南有微徑，時遇采芝客。往往白雲生，對面千里隔。", "機忘若僮僕，常與猿鳥劇。曬藥上小峰，庭深無日色。", "自忘歸鄉里，不見新舊戚。累累子孫墓，秋風吹古柏。"]'),
('yuding-44','醒後','劉駕','唐','御定全唐诗','yuding','','[]','醉臥芳草間，酒醒日落後。壺觴半傾覆，客去應已久。',36,'御定全唐詩/json/585.json','["醉臥芳草間，酒醒日落後。壺觴半傾覆，客去應已久。", "不記折花時，何得花在手。"]'),
('yuding-45','棄婦','劉駕','唐','御定全唐诗','yuding','','[]','回車在門前，欲上心更悲。路傍見花發，似妾初嫁時。',72,'御定全唐詩/json/585.json','["回車在門前，欲上心更悲。路傍見花發，似妾初嫁時。", "養蠶已成繭，織素猶在機。新人應笑此，何如畫蛾眉。", "昨日惜紅顏，今日畏老遲。良媒去不遠，此恨今告誰。"]'),
('yuding-46','送李殷游邊','劉駕','唐','御定全唐诗','yuding','','[]','十年夢相識，一覯俄遠別。征駕在我傍，草草意難說。',120,'御定全唐詩/json/585.json','["十年夢相識，一覯俄遠別。征駕在我傍，草草意難說。", "君居洞庭日，詩句滿魏闕。如何萬里來，青桂看人折。", "行裝不及備，西去偶然訣。孟夏出都門，紅塵客衣熱。", "荒城見羊馬，野館具薇蕨。邊境漸無虞，旅宿常待月。", "西園置酒地，日夕簪裾列。壯志安可留，槐花樽前發。"]'),
('yuding-47','江村','劉駕','唐','御定全唐诗','yuding','','[]','江水灌稻田，饑年稻亦熟。舟中愛桑麻，日午因成宿。',72,'御定全唐詩/json/585.json','["江水灌稻田，饑年稻亦熟。舟中愛桑麻，日午因成宿。", "相承幾十代，居止連茅屋。四鄰不相離，安肯去骨肉。", "書生說太苦，客路常在目。縱使富貴還，交親幾墳綠。"]'),
('yuding-48','出門','劉駕','唐','御定全唐诗','yuding','','[]','出門羨他人，奔走如得塗。翻思他人意，與我或不殊。',96,'御定全唐詩/json/585.json','["出門羨他人，奔走如得塗。翻思他人意，與我或不殊。", "以茲聊自安，默默行九衢。生計逐羸馬，每出似移居。", "客從我鄉來，但得鄰里書。田園幾換主，夢歸猶荷鋤。", "進猶希萬一，退複何所如。況今辟公道，安得不躊躇。"]'),
('yuding-49','別道者','劉駕','唐','御定全唐诗','yuding','','[]','自君入城市，北邙無新墳。始信壺中藥，不落白楊根。',48,'御定全唐詩/json/585.json','["自君入城市，北邙無新墳。始信壺中藥，不落白楊根。", "如何忽告歸，蕣華還笑人。玉笙無遺音，悵望緱嶺雲。"]'),
('yuding-50','蘭昌宮','劉駕','唐','御定全唐诗','yuding','','[]','宮蘭非瑤草，安得春長在。回首春又歸，翠華不能待。',48,'御定全唐詩/json/585.json','["宮蘭非瑤草，安得春長在。回首春又歸，翠華不能待。", "悲風生輦路，山川寂已晦。邊恨在行人，行人無盡歲。"]'),
('yuding-51','送友人擢第東歸','劉駕','唐','御定全唐诗','yuding','','[]','同家楚天南，相識秦雲西。古來懸弧義，豈顧子與妻。',96,'御定全唐詩/json/585.json','["同家楚天南，相識秦雲西。古來懸弧義，豈顧子與妻。", "攜手踐名場，正遇公道開。君榮我雖黜，感恩同所懷。", "有馬不復羸，有奴不復饑。灞岸秋草綠，卻是還家時。", "青門一瓢空，分手去遲遲。期君轍未平，我車繼東歸。"]'),
('yuding-52','久客','劉駕','唐','御定全唐诗','yuding','','[]','久客心易足，主人有餘力。如何昨宵夢，到曉家山色。',36,'御定全唐詩/json/585.json','["久客心易足，主人有餘力。如何昨宵夢，到曉家山色。", "南音入誰耳，曲盡頭自白。"]'),
('yuding-53','秋夕','劉駕','唐','御定全唐诗','yuding','','[]','促織燈下吟，燈光冷于水。鄉魂坐中去，倚壁身如死。',60,'御定全唐詩/json/585.json','["促織燈下吟，燈光冷于水。鄉魂坐中去，倚壁身如死。", "求名為骨肉，骨肉萬餘裏。富貴在何時，離別今如此。", "出門長歎息，月白西風起。"]'),
('yuding-54','效陶','劉駕','唐','御定全唐诗','yuding','','[]','兩曜無停馭，蓬壺應有墓。何況北邙山，只近市朝路。',96,'御定全唐詩/json/585.json','["兩曜無停馭，蓬壺應有墓。何況北邙山，只近市朝路。", "大恢生死網，飛走無逃處。白髮忽已新，紅顏豈如故。", "我有杯中物，可以消萬慮。醉舞日婆娑，誰能記朝暮。", "如求神仙藥，階下亦種黍。但使長兀然，始見天地祖。"]'),
('yuding-55','長門怨','劉駕','唐','御定全唐诗','yuding','','[]','禦泉長繞鳳凰樓，只是恩波別處流。',32,'御定全唐詩/json/585.json','["禦泉長繞鳳凰樓，只是恩波別處流。", "閑揲舞衣歸未得，夜來砧杵六宮秋。"]'),
('yuding-56','苦寒行','劉駕','唐','御定全唐诗','yuding','','[]','嚴寒動八荒，刺刺無休時。陽烏不自暖，雪壓扶桑枝。',60,'御定全唐詩/json/585.json','["嚴寒動八荒，刺刺無休時。陽烏不自暖，雪壓扶桑枝。", "歲暮寒益壯，青春安得歸。朔雁到南海，越禽何處飛。", "誰言貧士歎，不為身無衣。"]'),
('yuding-57','琪樹下因吟六韻呈先達者','劉駕','唐','御定全唐诗','yuding','','[]','舉世愛嘉樹，此樹何人識。清秋遠山意，偶向亭際得。',72,'御定全唐詩/json/585.json','["舉世愛嘉樹，此樹何人識。清秋遠山意，偶向亭際得。", "奇柯交若鬥，珍葉密如織。塵中尚青蔥，更想塵外色。", "所宜巢三鳥，影入瑤池碧。移根豈無時，一問紫煙客。"]'),
('yuding-58','送人登第東歸','劉駕','唐','御定全唐诗','yuding','','[]','學古既到古，反求鑒者難。見詩未識君，疑生建安前。',156,'御定全唐詩/json/585.json','["學古既到古，反求鑒者難。見詩未識君，疑生建安前。", "海畔豈無家，終難成故山。得失雖由命，世途多險艱。", "我皇追古風，文柄付大賢。此時如為君，果在甲科間。", "晚達多早貴，舉世咸為然。一夕顏卻少，雖病心且安。", "所居似清明，冷灶起新煙。高情懶行樂，花盛僕馬前。", "歸程不淹留，指期到田園。香醪四鄰熟，霜橘千株繁。", "肯憶長安夜，論詩風雪寒。"]'),
('yuding-59','賈客詞','劉駕','唐','御定全唐诗','yuding','','[]','賈客燈下起，猶言發已遲。高山有疾路，暗行終不疑。',72,'御定全唐詩/json/585.json','["賈客燈下起，猶言發已遲。高山有疾路，暗行終不疑。", "寇盜伏其路，猛獸來相追。金玉四散去，空囊委路岐。", "揚州有大宅，白骨無地歸。少婦當此日，對鏡弄花枝。"]'),
('yuding-60','塞下曲','劉駕','唐','御定全唐诗','yuding','','[]','勒兵遼水邊，風急卷旌旃。絕塞陰無草，平沙去盡天。',48,'御定全唐詩/json/585.json','["勒兵遼水邊，風急卷旌旃。絕塞陰無草，平沙去盡天。", "下營看鬥建，傳號信狼煙。聖代書青史，當時破虜年。"]'),
('yuding-61','春夜二首','劉駕','唐','御定全唐诗','yuding','','[]','一別杜陵歸未期，只憑魂夢接親知。',64,'御定全唐詩/json/585.json','["一別杜陵歸未期，只憑魂夢接親知。", "近來欲睡兼難睡，夜夜夜深聞子規。", "幾歲干戈阻路岐，憶山心切與心違。", "時難何處披衷抱，日日日斜空醉歸。"]'),
('yuding-62','郪中感懷','劉駕','唐','御定全唐诗','yuding','','[]','頃年曾住此中來，今日重遊事可哀。',32,'御定全唐詩/json/585.json','["頃年曾住此中來，今日重遊事可哀。", "憶得幾家歡宴處，家家家業盡成灰。"]'),
('yuding-63','曉登迎春閣','劉駕','唐','御定全唐诗','yuding','','[]','未櫛憑欄眺錦城，煙籠萬井二江明。',32,'御定全唐詩/json/585.json','["未櫛憑欄眺錦城，煙籠萬井二江明。", "香風滿閣花滿樹，樹樹樹梢啼曉鶯。"]'),
('yuding-64','白髭','劉駕','唐','御定全唐诗','yuding','','[]','到處逢人求至藥，幾回染了又成絲。',32,'御定全唐詩/json/585.json','["到處逢人求至藥，幾回染了又成絲。", "素絲易染髭難染，墨翟當年合泣髭。"]'),
('yuding-65','送盧使君赴夔州','劉駕','唐','御定全唐诗','yuding','','[]','鐃管隨征旆，高秋上遠巴。白波連霧雨，青壁斷蒹葭。',48,'御定全唐詩/json/585.json','["鐃管隨征旆，高秋上遠巴。白波連霧雨，青壁斷蒹葭。", "憑幾雙瞳靜，登樓萬井斜。政成知俗變，當應畫輪車。"]'),
('yuding-66','望月','劉駕','唐','御定全唐诗','yuding','','[]','清秋新霽與君同，江上高樓倚碧空。',32,'御定全唐詩/json/585.json','["清秋新霽與君同，江上高樓倚碧空。", "酒盡露零賓客散，更更更漏月明中。"]'),
('yuding-67','古意','劉駕','唐','御定全唐诗','yuding','','[]','蒲帆出浦去，但見浦邊樹。不如馬行郎，馬跡猶在路。',48,'御定全唐詩/json/585.json','["蒲帆出浦去，但見浦邊樹。不如馬行郎，馬跡猶在路。", "大舟不相載，買宅令委住。莫道留金多，本非愛郎富。"]'),
('yuding-0','長洲懷古','劉滄','唐','御定全唐诗','yuding','','[]','野燒原空盡荻灰，吳王此地有樓臺。千年事往人何在，',40,'御定全唐詩/json/586.json','["野燒原空盡荻灰，吳王此地有樓臺。千年事往人何在，", "停車日晚薦蘋藻，風靜寒塘花正開。"]'),
('yuding-1','經煬帝行宮','劉滄','唐','御定全唐诗','yuding','','[]','此地曾經翠輦過，浮雲流水竟如何。香銷南國美人盡，',40,'御定全唐詩/json/586.json','["此地曾經翠輦過，浮雲流水竟如何。香銷南國美人盡，", "行人遙起廣陵思，古渡月明聞棹歌。"]'),
('yuding-2','春日游嘉陵江','劉滄','唐','御定全唐诗','yuding','','[]','獨泛扁舟映綠楊，嘉陵江水色蒼蒼。行看芳草故鄉遠，',40,'御定全唐詩/json/586.json','["獨泛扁舟映綠楊，嘉陵江水色蒼蒼。行看芳草故鄉遠，", "今來誰識東歸意，把酒閑吟思洛陽。"]'),
('yuding-3','秋日山齋書懷','劉滄','唐','御定全唐诗','yuding','','[]','啟戶清風枕簟幽，蟲絲吹落掛簾鉤。蟬吟高樹雨初霽，',40,'御定全唐詩/json/586.json','["啟戶清風枕簟幽，蟲絲吹落掛簾鉤。蟬吟高樹雨初霽，", "空將方寸荷知己，身寄煙蘿恩未酬。"]'),
('yuding-4','晚秋洛陽客舍','劉滄','唐','御定全唐诗','yuding','','[]','清洛平分兩岸沙，沙邊水色近人家。隋朝古陌銅駝柳，',40,'御定全唐詩/json/586.json','["清洛平分兩岸沙，沙邊水色近人家。隋朝古陌銅駝柳，", "未成歸計關河阻，空望白雲鄉路賒。"]'),
('yuding-5','深愁喜友人至','劉滄','唐','御定全唐诗','yuding','','[]','不避驅羸道路長，青山同喜惜年光。燈前話舊階草夜，',40,'御定全唐詩/json/586.json','["不避驅羸道路長，青山同喜惜年光。燈前話舊階草夜，", "此身未遂歸休計，一半生涯寄岳陽。"]'),
('yuding-6','秋日望西陽','劉滄','唐','御定全唐诗','yuding','','[]','古木蒼苔墜幾層，行人一望旅情增。太行山下黃河水，',40,'御定全唐詩/json/586.json','["古木蒼苔墜幾層，行人一望旅情增。太行山下黃河水，", "野花似泣紅妝淚，寒露滿枝枝不勝。"]'),
('yuding-7','鄴都懷古','劉滄','唐','御定全唐诗','yuding','','[]','昔時霸業何蕭索，古木唯多鳥雀聲。芳草自生宮殿處，',40,'御定全唐詩/json/586.json','["昔時霸業何蕭索，古木唯多鳥雀聲。芳草自生宮殿處，", "一望青山便惆悵，西陵無主月空明。"]'),
('yuding-8','題龍門僧房','劉滄','唐','御定全唐诗','yuding','','[]','靜室遙臨伊水東，寂寥誰與此身同。禹門山色度寒磬，',40,'御定全唐詩/json/586.json','["靜室遙臨伊水東，寂寥誰與此身同。禹門山色度寒磬，", "偶將心地問高士，坐指浮生一夢中。"]'),
('yuding-9','秋夕山齋即事','劉滄','唐','御定全唐诗','yuding','','[]','衡門無事閉蒼苔，籬下蕭疏野菊開。半夜秋風江色動，',40,'御定全唐詩/json/586.json','["衡門無事閉蒼苔，籬下蕭疏野菊開。半夜秋風江色動，", "獨坐高窗此時節，一彈瑤瑟自成哀。"]'),
('yuding-10','江行書事','劉滄','唐','御定全唐诗','yuding','','[]','遠渚蒹葭覆綠苔，姑蘇南望思裴徊。空江獨樹楚山背，',40,'御定全唐詩/json/586.json','["遠渚蒹葭覆綠苔，姑蘇南望思裴徊。空江獨樹楚山背，", "寒潮欲上泛萍藻，寄薦三閭情自哀。"]'),
('yuding-11','過鑄鼎原','劉滄','唐','御定全唐诗','yuding','','[]','黃帝修真萬國朝，鼎成龍駕上丹霄。天風乍起鶴聲遠，',40,'御定全唐詩/json/586.json','["黃帝修真萬國朝，鼎成龍駕上丹霄。天風乍起鶴聲遠，", "唯留古跡寒原在，碧水蒼蒼空寂寥。"]'),
('yuding-12','秋日寓懷','劉滄','唐','御定全唐诗','yuding','','[]','海上生涯一釣舟，偶因名利事淹留。旅塗誰見客青眼，',40,'御定全唐詩/json/586.json','["海上生涯一釣舟，偶因名利事淹留。旅塗誰見客青眼，", "如何未盡此行役，西入潼關雲木秋。"]'),
('yuding-13','江城晚望','劉滄','唐','御定全唐诗','yuding','','[]','一望江城思有餘，遙分野徑入樵漁。青山經雨菊花盡，',40,'御定全唐詩/json/586.json','["一望江城思有餘，遙分野徑入樵漁。青山經雨菊花盡，", "秋期又涉潼關路，不得年年向此居。"]'),
('yuding-14','宿蒼溪館','劉滄','唐','御定全唐诗','yuding','','[]','孤館門開對碧岑，竹窗燈下聽猿吟。巴山夜雨別離夢，',40,'御定全唐詩/json/586.json','["孤館門開對碧岑，竹窗燈下聽猿吟。巴山夜雨別離夢，", "空思知己隔雲嶺，鄉路獨歸春草深。"]'),
('yuding-15','題王母廟','劉滄','唐','御定全唐诗','yuding','','[]','寂寥珠翠想遺聲，門掩煙微水殿清。拂曙紫霞生古壁，',40,'御定全唐詩/json/586.json','["寂寥珠翠想遺聲，門掩煙微水殿清。拂曙紫霞生古壁，", "武帝無名在仙籍，玉壇星月夜空明。"]'),
('yuding-16','留別複本修古二上人','劉滄','唐','御定全唐诗','yuding','','[]','二遠相知是昔年，此身長寄禮香煙。綠蕪風晚水邊寺，',40,'御定全唐詩/json/586.json','["二遠相知是昔年，此身長寄禮香煙。綠蕪風晚水邊寺，", "西峰話別又須去，終日關山在馬前。"]'),
('yuding-17','邊思','劉滄','唐','御定全唐诗','yuding','','[]','漢將邊方背轆轤，受降城北是單于。黃河晚凍雪風急，',40,'御定全唐詩/json/586.json','["漢將邊方背轆轤，受降城北是單于。黃河晚凍雪風急，", "蛾眉一沒空留怨，青塚月明啼夜烏。"]'),
('yuding-18','登龍門敬善寺閣','劉滄','唐','御定全唐诗','yuding','','[]','獨步危梯入杳冥，天風瀟灑拂簷楹。禹門煙樹正春色，',40,'御定全唐詩/json/586.json','["獨步危梯入杳冥，天風瀟灑拂簷楹。禹門煙樹正春色，", "瑣窗朱檻同仙界，半夜緱山有鶴聲。"]'),
('yuding-19','題王校書山齋','劉滄','唐','御定全唐诗','yuding','','[]','猿鳥無聲晝掩扉，寒原隔水到人稀。雲晴古木月初上，',40,'御定全唐詩/json/586.json','["猿鳥無聲晝掩扉，寒原隔水到人稀。雲晴古木月初上，", "棲遲慣得滄浪思，雲閣還應夢釣磯。"]'),
('yuding-20','浙江晚渡懷古','劉滄','唐','御定全唐诗','yuding','','[]','蟬噪秋風滿古堤，荻花寒渡思萋萋。潮聲歸海鳥初下，',40,'御定全唐詩/json/586.json','["蟬噪秋風滿古堤，荻花寒渡思萋萋。潮聲歸海鳥初下，", "此來一見垂綸者，卻憶舊居明月溪。"]'),
('yuding-21','及第後宴曲江','劉滄','唐','御定全唐诗','yuding','','[]','及第新春選勝遊，杏園初宴曲江頭。紫毫粉壁題仙籍，',40,'御定全唐詩/json/586.json','["及第新春選勝遊，杏園初宴曲江頭。紫毫粉壁題仙籍，", "歸時不省花間醉，綺陌香車似水流。"]'),
('yuding-22','秋日山寺懷友人','劉滄','唐','御定全唐诗','yuding','','[]','蕭寺樓臺對夕陰，淡煙疏磬散空林。風生寒渚白蘋動，',40,'御定全唐詩/json/586.json','["蕭寺樓臺對夕陰，淡煙疏磬散空林。風生寒渚白蘋動，", "相思不見又經歲，坐向松窗彈玉琴。"]'),
('yuding-23','八月十五日夜玩月','劉滄','唐','御定全唐诗','yuding','','[]','中秋朗月靜天河，烏鵲南飛客恨多。寒色滿窗明枕簟，',40,'御定全唐詩/json/586.json','["中秋朗月靜天河，烏鵲南飛客恨多。寒色滿窗明枕簟，", "此夜空亭聞木落，蒹葭霜磧雁初過。"]'),
('yuding-24','晚春宿僧院','劉滄','唐','御定全唐诗','yuding','','[]','蕭寺春風正落花，淹留數宿惠休家。碧空雲盡磬聲遠，',40,'御定全唐詩/json/586.json','["蕭寺春風正落花，淹留數宿惠休家。碧空雲盡磬聲遠，", "微微一點寒燈在，鄉夢不成聞曙鴉。"]'),
('yuding-25','懷汶陽兄弟','劉滄','唐','御定全唐诗','yuding','','[]','回看雲嶺思茫茫，幾處關河隔汶陽。書信經年鄉國遠，',40,'御定全唐詩/json/586.json','["回看雲嶺思茫茫，幾處關河隔汶陽。書信經年鄉國遠，", "終日路岐歸未得，秋來空羨雁成行。"]'),
('yuding-26','題天宮寺閣','劉滄','唐','御定全唐诗','yuding','','[]','丹闕侵霄壯複危，排空霞影動簷扉。城連伊水禹門近，',40,'御定全唐詩/json/586.json','["丹闕侵霄壯複危，排空霞影動簷扉。城連伊水禹門近，", "此來閑望更何有，無限清風生客衣。"]'),
('yuding-27','游上方石窟寺','劉滄','唐','御定全唐诗','yuding','','[]','苔徑縈回景漸分，翛然空界靜埃氛。一聲疏磬過寒水，',40,'御定全唐詩/json/586.json','["苔徑縈回景漸分，翛然空界靜埃氛。一聲疏磬過寒水，", "幾來吟嘯立朱檻，風起天香處處聞。"]'),
('yuding-28','懷江南友人','劉滄','唐','御定全唐诗','yuding','','[]','久絕音書隔塞塵，路岐誰與子相親。愁中獨坐秦城夜，',40,'御定全唐詩/json/586.json','["久絕音書隔塞塵，路岐誰與子相親。愁中獨坐秦城夜，", "空勞兩地望明月，多感斷蓬千里身。"]'),
('yuding-29','題敬亭山廟','劉滄','唐','御定全唐诗','yuding','','[]','森森古木列岩隈，迥壓寒原霽色開。雲雨只從山上起，',40,'御定全唐詩/json/586.json','["森森古木列岩隈，迥壓寒原霽色開。雲雨只從山上起，", "花落空庭春晝晚，石床松殿滿青苔。"]'),
('yuding-30','經麻姑山','劉滄','唐','御定全唐诗','yuding','','[]','麻姑此地煉神丹，寂寞煙霞古灶殘。一自仙娥歸碧落，',40,'御定全唐詩/json/586.json','["麻姑此地煉神丹，寂寞煙霞古灶殘。一自仙娥歸碧落，", "山頂白雲千萬片，時聞鸞鶴下仙壇。"]'),
('yuding-31','對殘春','劉滄','唐','御定全唐诗','yuding','','[]','楊花漠漠暗長堤，春盡人愁鳥又啼。鬢髮近來生處白，',40,'御定全唐詩/json/586.json','["楊花漠漠暗長堤，春盡人愁鳥又啼。鬢髮近來生處白，", "唯有年光堪自惜，不勝煙草日萋萋。"]'),
('yuding-32','過滄浪峽','劉滄','唐','御定全唐诗','yuding','','[]','山疊雲重一徑幽，蒼苔古石瀨清流。出岩樹色見來靜，',40,'御定全唐詩/json/586.json','["山疊雲重一徑幽，蒼苔古石瀨清流。出岩樹色見來靜，", "如何地近東西路，馬足車輪不暫留。"]'),
('yuding-33','經過建業','劉滄','唐','御定全唐诗','yuding','','[]','六代興衰曾此地，西風露泣白蘋花。煙波浩渺空亡國，',40,'御定全唐詩/json/586.json','["六代興衰曾此地，西風露泣白蘋花。煙波浩渺空亡國，", "淒涼處處漁樵路，鳥去人歸山影斜。"]'),
('yuding-34','贈道者','劉滄','唐','御定全唐诗','yuding','','[]','真趣淡然居物外，忘機多是隱天臺。停燈深夜看仙籙，',40,'御定全唐詩/json/586.json','["真趣淡然居物外，忘機多是隱天臺。停燈深夜看仙籙，", "無因朝市知名姓，地僻衡門對嶽開。"]'),
('yuding-35','題馬太尉華山莊','劉滄','唐','御定全唐诗','yuding','','[]','別開池館背山陰，近得幽奇物外心。竹色拂雲連嶽寺，',40,'御定全唐詩/json/586.json','["別開池館背山陰，近得幽奇物外心。竹色拂雲連嶽寺，", "自是功成閑劍履，西齋長臥對瑤琴。"]'),
('yuding-36','秋日夜懷','劉滄','唐','御定全唐诗','yuding','','[]','砧杵寥寥秋色長，繞枝寒鵲客情傷。關山雲盡九秋月，',40,'御定全唐詩/json/586.json','["砧杵寥寥秋色長，繞枝寒鵲客情傷。關山雲盡九秋月，", "如何節候變容發，明鏡一看愁異常。"]'),
('yuding-37','題巫山廟','劉滄','唐','御定全唐诗','yuding','','[]','十二嵐峰掛夕暉，廟門深閉霧煙微。天高木落楚人思，',40,'御定全唐詩/json/586.json','["十二嵐峰掛夕暉，廟門深閉霧煙微。天高木落楚人思，", "嬋娟似恨襄王夢，猿叫斷岩秋蘚稀。"]'),
('yuding-38','題吳宮苑','劉滄','唐','御定全唐诗','yuding','','[]','吳苑荒涼故國名，吳山月上照江明。殘春碧樹自留影，',40,'御定全唐詩/json/586.json','["吳苑荒涼故國名，吳山月上照江明。殘春碧樹自留影，", "經過此地千年恨，荏苒東風露色清。"]'),
('yuding-39','旅館書懷','劉滄','唐','御定全唐诗','yuding','','[]','秋看庭樹換風煙，兄弟飄零寄海邊。客計倦行分陝路，',40,'御定全唐詩/json/586.json','["秋看庭樹換風煙，兄弟飄零寄海邊。客計倦行分陝路，", "落葉蟲絲滿窗戶，秋堂獨坐思悠然。"]'),
('yuding-40','贈天臺隱者','劉滄','唐','御定全唐诗','yuding','','[]','靜者多依猿鳥叢，衡門野色四郊通。天開宿霧海生日，',40,'御定全唐詩/json/586.json','["靜者多依猿鳥叢，衡門野色四郊通。天開宿霧海生日，", "看書飲酒餘無事，自樂樵漁狎釣翁。"]'),
('yuding-41','洛陽月夜書懷','劉滄','唐','御定全唐诗','yuding','','[]','疏柳高槐古巷通，月明西照上陽宮。一聲邊雁塞門雪，',40,'御定全唐詩/json/586.json','["疏柳高槐古巷通，月明西照上陽宮。一聲邊雁塞門雪，", "孤吟此夕驚秋晚，落葉殘花樹色中。"]'),
('yuding-42','江行夜泊','劉滄','唐','御定全唐诗','yuding','','[]','白浪連空極渺漫，孤舟此夜泊中灘。岳陽秋霽寺鐘遠，',40,'御定全唐詩/json/586.json','["白浪連空極渺漫，孤舟此夜泊中灘。岳陽秋霽寺鐘遠，", "鄉遙楚國生歸思，欲曙山光上木蘭。"]'),
('yuding-43','贈顓頊山人','劉滄','唐','御定全唐诗','yuding','','[]','浩氣含真玉片輝，著書精義入玄微。洛陽紫陌幾曾醉，',40,'御定全唐詩/json/586.json','["浩氣含真玉片輝，著書精義入玄微。洛陽紫陌幾曾醉，", "知君濟世有長策，莫問滄浪隱釣磯。"]'),
('yuding-44','長安冬夜書情','劉滄','唐','御定全唐诗','yuding','','[]','上國棲遲歲欲終，此情多寄寂寥中。鐘傳半夜旅人館，',40,'御定全唐詩/json/586.json','["上國棲遲歲欲終，此情多寄寂寥中。鐘傳半夜旅人館，", "今來唯問心期事，獨望青雲路未通。"]'),
('yuding-45','經古行宮','劉滄','唐','御定全唐诗','yuding','','[]','玉輦西歸已至今，古原風景自沉沉。禦溝流水長芳草，',40,'御定全唐詩/json/586.json','["玉輦西歸已至今，古原風景自沉沉。禦溝流水長芳草，", "路人不記當年事，台殿寂寥山影侵。"]'),
('yuding-46','秋日登醴泉縣樓','劉滄','唐','御定全唐诗','yuding','','[]','閑上高樓時一望，綠蕪寒野靜中分。人行直路入秦樹，',40,'御定全唐詩/json/586.json','["閑上高樓時一望，綠蕪寒野靜中分。人行直路入秦樹，", "秋風高柳出危葉，獨聽蟬聲日欲曛。"]'),
('yuding-47','春日旅遊','劉滄','唐','御定全唐诗','yuding','','[]','玄發辭家事遠遊，春風歸雁一聲愁。花開忽憶故山樹，',40,'御定全唐詩/json/586.json','["玄發辭家事遠遊，春風歸雁一聲愁。花開忽憶故山樹，", "秦川楚塞煙波隔，怨別路岐何日休。"]'),
('yuding-48','送友人下第歸吳','劉滄','唐','御定全唐诗','yuding','','[]','共惜年華未立名，路岐終日軫羈情。青春半是往來盡，',40,'御定全唐詩/json/586.json','["共惜年華未立名，路岐終日軫羈情。青春半是往來盡，", "東歸自有故山約，花落石床苔蘚平。"]'),
('yuding-49','訪友人郊居','劉滄','唐','御定全唐诗','yuding','','[]','登原過水訪相如，竹塢莎庭似故居。空塞山當清晝晚，',40,'御定全唐詩/json/586.json','["登原過水訪相如，竹塢莎庭似故居。空塞山當清晝晚，", "醉唱勞歌翻自歎，釣船漁浦夢難疏。"]'),
('yuding-50','匡城尋薛閔秀才不遇','劉滄','唐','御定全唐诗','yuding','','[]','音容一別近三年，往事空思意浩然。匹馬東西何處客，',40,'御定全唐詩/json/586.json','["音容一別近三年，往事空思意浩然。匹馬東西何處客，", "不見故人勞夢寐，獨吟風月過南燕。"]'),
('yuding-51','與僧話舊','劉滄','唐','御定全唐诗','yuding','','[]','巾舄同時下翠微，舊遊因話事多違。南朝古寺幾僧在，',40,'御定全唐詩/json/586.json','["巾舄同時下翠微，舊遊因話事多違。南朝古寺幾僧在，", "此時相見又相別，即是關河朔雁飛。"]'),
('yuding-52','寄遠','劉滄','唐','御定全唐诗','yuding','','[]','西園楊柳暗驚秋，寶瑟朱弦結遠愁。霜落雁聲來紫塞，',40,'御定全唐詩/json/586.json','["西園楊柳暗驚秋，寶瑟朱弦結遠愁。霜落雁聲來紫塞，", "錦字織成添別恨，關河萬里路悠悠。"]'),
('yuding-53','長安逢友人','劉滄','唐','御定全唐诗','yuding','','[]','上國相逢塵滿襟，傾杯一話昔年心。荒台共望秋山立，',40,'御定全唐詩/json/586.json','["上國相逢塵滿襟，傾杯一話昔年心。荒台共望秋山立，", "終期白日青雲路，休感鬢毛霜雪侵。"]'),
('yuding-54','下第東歸途中書事','劉滄','唐','御定全唐诗','yuding','','[]','峽路誰知倦此情，往來多是半年程。孤吟洛苑逢春盡，',40,'御定全唐詩/json/586.json','["峽路誰知倦此情，往來多是半年程。孤吟洛苑逢春盡，", "東歸海上有餘業，牢落田園荒草平。"]'),
('yuding-55','經龍門廢寺','劉滄','唐','御定全唐诗','yuding','','[]','因思人事事無窮，幾度經過感此中。山色不移樓殿盡，',40,'御定全唐詩/json/586.json','["因思人事事無窮，幾度經過感此中。山色不移樓殿盡，", "楊柳覆灘清瀨響，暮天沙鳥自西東。"]'),
('yuding-56','下第後懷舊居','劉滄','唐','御定全唐诗','yuding','','[]','幾到青門未立名，芳時多負故鄉情。雨餘秦苑綠蕪合，',40,'御定全唐詩/json/586.json','["幾到青門未立名，芳時多負故鄉情。雨餘秦苑綠蕪合，", "蘋花覆水曲溪暮，獨坐釣舟歌月明。"]'),
('yuding-57','經無可舊居兼傷賈島','劉滄','唐','御定全唐诗','yuding','','[]','塵室寒窗我獨看，別來人事幾凋殘。書空蕭寺一僧去，',40,'御定全唐詩/json/586.json','["塵室寒窗我獨看，別來人事幾凋殘。書空蕭寺一僧去，", "碧雲迢遞長江遠，向夕苦吟歸思難。"]'),
('yuding-58','贈隱者','劉滄','唐','御定全唐诗','yuding','','[]','何時止此幽棲處，獨掩衡門長綠苔。臨水靜聞靈鶴語，',40,'御定全唐詩/json/586.json','["何時止此幽棲處，獨掩衡門長綠苔。臨水靜聞靈鶴語，", "誰識無機養真性，醉眠松石枕空杯。"]'),
('yuding-59','題書齋','劉滄','唐','御定全唐诗','yuding','','[]','一日不曾離此處，風吹疏牖夕雲晴。氣淩霜色劍光動，',40,'御定全唐詩/json/586.json','["一日不曾離此處，風吹疏牖夕雲晴。氣淩霜色劍光動，", "西齋瑤瑟自為侶，門掩半春苔蘚生。"]'),
('yuding-60','題秦女樓','劉滄','唐','御定全唐诗','yuding','','[]','珠翠香銷鴛瓦墮，神仙曾向此中游。青樓月色桂花冷，',40,'御定全唐詩/json/586.json','["珠翠香銷鴛瓦墮，神仙曾向此中游。青樓月色桂花冷，", "一從鳳去千年後，迢遞岐山水石秋。"]'),
('yuding-61','題桃源處士山居留寄','劉滄','唐','御定全唐诗','yuding','','[]','白雲深處葺茅廬，退隱衡門與俗疏。一洞曉煙留水上，',40,'御定全唐詩/json/586.json','["白雲深處葺茅廬，退隱衡門與俗疏。一洞曉煙留水上，", "窮達盡為身外事，浩然元氣樂樵漁。"]'),
('yuding-62','宿題天壇觀','劉滄','唐','御定全唐诗','yuding','','[]','沐發清齋宿洞宮，桂花松韻滿岩風。紫霞曉色秋山霽，',40,'御定全唐詩/json/586.json','["沐發清齋宿洞宮，桂花松韻滿岩風。紫霞曉色秋山霽，", "冥心一悟虛無理，寂寞玄珠象罔中。"]'),
('yuding-63','洛神怨','劉滄','唐','御定全唐诗','yuding','','[]','子建東歸恨思長，飄颻神女步池塘。雲鬟高動水宮影，',40,'御定全唐詩/json/586.json','["子建東歸恨思長，飄颻神女步池塘。雲鬟高動水宮影，", "停車綺陌傍楊柳，片月青樓落未央。"]'),
('yuding-64','龍門留別道友','劉滄','唐','御定全唐诗','yuding','','[]','一顧恩深荷道安，獨垂雙淚下層巒。飛鳴北雁塞雲暮，',40,'御定全唐詩/json/586.json','["一顧恩深荷道安，獨垂雙淚下層巒。飛鳴北雁塞雲暮，", "裴徊偏起舊枝戀，半夜獨吟孤燭殘。"]'),
('yuding-65','題四皓廟','劉滄','唐','御定全唐诗','yuding','','[]','石壁蒼苔翠靄濃，驅車商洛想遺蹤。天高猿叫向山月，',40,'御定全唐詩/json/586.json','["石壁蒼苔翠靄濃，驅車商洛想遺蹤。天高猿叫向山月，", "雪髯仙侶何深隱，千古寂寥雲水重。"]'),
('yuding-66','望未央宮','劉滄','唐','御定全唐诗','yuding','','[]','西上秦原見未央，山嵐川色晚蒼蒼。雲樓欲動入清渭，',40,'御定全唐詩/json/586.json','["西上秦原見未央，山嵐川色晚蒼蒼。雲樓欲動入清渭，", "香風吹落天人語，彩鳳五雲朝漢皇。"]'),
('yuding-67','秋日過昭陵','劉滄','唐','御定全唐诗','yuding','','[]','寢廟徒悲劍與冠，翠華龍馭杳漫漫。原分山勢入空塞，',40,'御定全唐詩/json/586.json','["寢廟徒悲劍與冠，翠華龍馭杳漫漫。原分山勢入空塞，", "那堪獨立斜陽裏，碧落秋光煙樹殘。"]'),
('yuding-68','夏日登慈恩寺','劉滄','唐','御定全唐诗','yuding','','[]','金界時來一訪僧，天香飄翠瑣窗凝。碧池靜照寒松影，',40,'御定全唐詩/json/586.json','["金界時來一訪僧，天香飄翠瑣窗凝。碧池靜照寒松影，", "塵機消盡話玄理，暮磬出林疏韻澄。"]'),
('yuding-69','宿題金山寺','劉滄','唐','御定全唐诗','yuding','','[]','一點青山翠色危，雲岩不掩與星期。海門煙樹潮歸後，',40,'御定全唐詩/json/586.json','["一點青山翠色危，雲岩不掩與星期。海門煙樹潮歸後，", "蕭疏水木清鐘梵，顥氣寒光動石池。"]'),
('yuding-70','送友人游蜀','劉滄','唐','御定全唐诗','yuding','','[]','北去西遊春未半，蜀山雲雪入詩情。青蘿拂水花流影，',40,'御定全唐詩/json/586.json','["北去西遊春未半，蜀山雲雪入詩情。青蘿拂水花流影，", "心期萬里無勞倦，古石蒼苔峽路清。"]'),
('yuding-71','題鄭中丞東溪','劉滄','唐','御定全唐诗','yuding','','[]','一境新開雉堞西，綠苔微徑露淒淒。高軒夜靜竹聲遠，',40,'御定全唐詩/json/586.json','["一境新開雉堞西，綠苔微徑露淒淒。高軒夜靜竹聲遠，", "即隨鳳詔歸清列，幾憶風花夢小溪。"]'),
('yuding-72','代友人悼姬','劉滄','唐','御定全唐诗','yuding','','[]','羅帳香微冷錦裀，歌聲永絕想梁塵。蕭郎獨宿落花夜，',40,'御定全唐詩/json/586.json','["羅帳香微冷錦裀，歌聲永絕想梁塵。蕭郎獨宿落花夜，", "滿庭芳草坐成恨，迢遞蓬萊入夢頻。"]'),
('yuding-73','夏日登西林白上人樓','劉滄','唐','御定全唐诗','yuding','','[]','幾到西林清淨境，層台高視有無間。寒光遠動天邊水，',40,'御定全唐詩/json/586.json','["幾到西林清淨境，層台高視有無間。寒光遠動天邊水，", "曠然多慊登樓意，永日重門深掩關。"]'),
('yuding-74','江樓月夜聞笛','劉滄','唐','御定全唐诗','yuding','','[]','南浦蒹葭疏雨後，寂寥橫笛怨江樓。思飄明月浪花白，',40,'御定全唐詩/json/586.json','["南浦蒹葭疏雨後，寂寥橫笛怨江樓。思飄明月浪花白，", "發寒衣濕曲初罷，露色河光生釣舟。"]'),
('yuding-75','送友人下第東歸','劉滄','唐','御定全唐诗','yuding','','[]','漠漠楊花灞岸飛，幾回傾酒話東歸。九衢春盡生鄉夢，',40,'御定全唐詩/json/586.json','["漠漠楊花灞岸飛，幾回傾酒話東歸。九衢春盡生鄉夢，", "金門自有西來約，莫待螢光照竹扉。"]'),
('yuding-76','從鄭郎中高州游東潭','劉滄','唐','御定全唐诗','yuding','','[]','煙嵐晚入濕旌旗，高檻風清醉未歸。夾路野花迎馬首，',40,'御定全唐詩/json/586.json','["煙嵐晚入濕旌旗，高檻風清醉未歸。夾路野花迎馬首，", "自是謝公心近得，登樓望月思依依。"]'),
('yuding-77','罷華原尉上座主尚書','劉滄','唐','御定全唐诗','yuding','','[]','自憐生計事悠悠，浩渺滄浪一釣舟。千里夢歸清洛近，',40,'御定全唐詩/json/586.json','["自憐生計事悠悠，浩渺滄浪一釣舟。千里夢歸清洛近，", "白露黃花歲時晚，不堪霜鬢鏡前愁。"]'),
('yuding-78','雨後游南門寺','劉滄','唐','御定全唐诗','yuding','','[]','郭南山寺雨初晴，上界尋僧竹裏行。半壁樓臺秋月過，',40,'御定全唐詩/json/586.json','["郭南山寺雨初晴，上界尋僧竹裏行。半壁樓臺秋月過，", "木葉蕭蕭動歸思，西風畫角漢東城。"]'),
('yuding-79','題古寺','劉滄','唐','御定全唐诗','yuding','','[]','古寺蕭條偶宿期，更深霜壓竹枝低。長天月影高窗過，',40,'御定全唐詩/json/586.json','["古寺蕭條偶宿期，更深霜壓竹枝低。長天月影高窗過，", "傷心可惜從前事，寥落朱廊墮粉泥。"]'),
('yuding-80','晚秋野望','劉滄','唐','御定全唐诗','yuding','','[]','秋盡郊原情自哀，菊花寂寞晚仍開。高風疏葉帶霜落，',40,'御定全唐詩/json/586.json','["秋盡郊原情自哀，菊花寂寞晚仍開。高風疏葉帶霜落，", "歸途休問從前事，獨唱勞歌醉數杯。"]'),
('yuding-81','秋月望上陽宮','劉滄','唐','御定全唐诗','yuding','','[]','苔色輕塵鎖洞房，亂鴉群鴿集殘陽。青山空出禁城日，',40,'御定全唐詩/json/586.json','["苔色輕塵鎖洞房，亂鴉群鴿集殘陽。青山空出禁城日，", "此時獨立意難盡，正值西風砧杵涼。"]'),
('yuding-82','入關留別主人','劉滄','唐','御定全唐诗','yuding','','[]','此來多愧食魚心，東閣將辭強一吟。羸馬客程秋草合，',40,'御定全唐詩/json/586.json','["此來多愧食魚心，東閣將辭強一吟。羸馬客程秋草合，", "對酒相看自無語，幾多離思入瑤琴。"]'),
('yuding-83','留別山中友人','劉滄','唐','御定全唐诗','yuding','','[]','欲辭松月戀知音，去住多同羈鳥心。秋盡書窗驚白髮，',40,'御定全唐詩/json/586.json','["欲辭松月戀知音，去住多同羈鳥心。秋盡書窗驚白髮，", "別後寂寥無限意，野花門路草蟲吟。"]'),
('yuding-84','春晚旅次有懷','劉滄','唐','御定全唐诗','yuding','','[]','晚出關河綠野平，依依雲樹動鄉情。殘春花盡黃鶯語，',40,'御定全唐詩/json/586.json','["晚出關河綠野平，依依雲樹動鄉情。殘春花盡黃鶯語，", "東西未遂歸田計，海上青山久廢耕。"]'),
('yuding-85','與重幽上人話舊','劉滄','唐','御定全唐诗','yuding','','[]','雲飛天末水空流，省與師同別異州。庭樹蟬聲初入夏，',40,'御定全唐詩/json/586.json','["雲飛天末水空流，省與師同別異州。庭樹蟬聲初入夏，", "自喜他年接巾舄，滄浪地近虎溪頭。"]'),
('yuding-86','月夜聞鶴唳','劉滄','唐','御定全唐诗','yuding','','[]','碧落風微月正明，霜毛似怨有離情。莓苔石冷想孤立，',40,'御定全唐詩/json/586.json','["碧落風微月正明，霜毛似怨有離情。莓苔石冷想孤立，", "鳳凰樓閣知猶戀，終逐煙霞上玉京。"]'),
('yuding-87','過北邙山','劉滄','唐','御定全唐诗','yuding','','[]','散漫黃埃滿北原，折碑橫路碾苔痕。空山夜月來松影，',40,'御定全唐詩/json/586.json','["散漫黃埃滿北原，折碑橫路碾苔痕。空山夜月來松影，", "白楊落日悲風起，蕭索寒巢鳥獨奔。"]'),
('yuding-88','咸陽懷古','劉滄','唐','御定全唐诗','yuding','','[]','經過此地無窮事，一望淒然感廢興。渭水故都秦二世，',40,'御定全唐詩/json/586.json','["經過此地無窮事，一望淒然感廢興。渭水故都秦二世，", "風景蒼蒼多少恨，寒山半出白雲層。"]'),
('yuding-89','送友人罷舉赴薊門從事','劉滄','唐','御定全唐诗','yuding','','[]','人生行止在知己，遠佐諸侯重所依。綠綬便當身是貴，',40,'御定全唐詩/json/586.json','["人生行止在知己，遠佐諸侯重所依。綠綬便當身是貴，", "此去黃金臺上客，相思應羨雁南歸。"]'),
('yuding-90','看榜日','劉滄','唐','御定全唐诗','yuding','','[]','禁漏初停蘭省開，列仙名目上清來。飛鳴曉日鶯聲遠，',40,'御定全唐詩/json/586.json','["禁漏初停蘭省開，列仙名目上清來。飛鳴曉日鶯聲遠，", "青雲已是酬恩處，莫惜芳時醉酒杯。"]'),
('yuding-91','送李休秀才歸嶺中','劉滄','唐','御定全唐诗','yuding','','[]','南泛孤舟景自饒，蒹葭汀浦晚蕭蕭。秋風漢水旅愁起，',40,'御定全唐詩/json/586.json','["南泛孤舟景自饒，蒹葭汀浦晚蕭蕭。秋風漢水旅愁起，", "故園新過重陽節，黃菊滿籬應未凋。"]'),
('yuding-92','寓居寄友人','劉滄','唐','御定全唐诗','yuding','','[]','雨餘虛館竹陰清，獨坐書窗軫旅情。芳草衡門無馬跡，',40,'御定全唐詩/json/586.json','["雨餘虛館竹陰清，獨坐書窗軫旅情。芳草衡門無馬跡，", "今夜南原賞佳景，月高風定苦吟生。"]'),
('yuding-93','經曲阜城','劉滄','唐','御定全唐诗','yuding','','[]','行經闕裏自堪傷，曾歎東流逝水長。蘿蔓幾凋荒隴樹，',40,'御定全唐詩/json/586.json','["行經闕裏自堪傷，曾歎東流逝水長。蘿蔓幾凋荒隴樹，", "蕭索風高洙泗上，秋山明月夜蒼蒼。"]'),
('yuding-94','汶陽客舍','劉滄','唐','御定全唐诗','yuding','','[]','年光自感益蹉跎，岐路東西竟若何。窗外雨來山色近，',40,'御定全唐詩/json/586.json','["年光自感益蹉跎，岐路東西竟若何。窗外雨來山色近，", "迢遞舊山伊水畔，破齋荒徑閉煙蘿。"]'),
('yuding-95','留別崔澣秀才昆仲','劉滄','唐','御定全唐诗','yuding','','[]','汶陽離思水無窮，去住情深夢寐中。歲晚蟲鳴寒露草，',40,'御定全唐詩/json/586.json','["汶陽離思水無窮，去住情深夢寐中。歲晚蟲鳴寒露草，", "對酒不能傷此別，尺書憑雁往來通。"]'),
('yuding-96','和友人憶洞庭舊居','劉滄','唐','御定全唐诗','yuding','','[]','客舍經時益苦吟，洞庭猶憶在前林。青山殘月有歸夢，',40,'御定全唐詩/json/586.json','["客舍經時益苦吟，洞庭猶憶在前林。青山殘月有歸夢，", "因君話舊起愁思，隔水數聲何處砧。"]'),
('yuding-97','晚歸山居','劉滄','唐','御定全唐诗','yuding','','[]','寥落霜空木葉稀，初行郊野思依依。秋深頻憶故鄉事，',40,'御定全唐詩/json/586.json','["寥落霜空木葉稀，初行郊野思依依。秋深頻憶故鄉事，", "娟娟唯有西林月，不惜清光照竹扉。"]'),
('yuding-98','送元敘上人歸上黨','劉滄','唐','御定全唐诗','yuding','','[]','太行關路戰塵收，白日思鄉別沃州。薄暮焚香臨野燒，',40,'御定全唐詩/json/586.json','["太行關路戰塵收，白日思鄉別沃州。薄暮焚香臨野燒，", "此去寂寥尋舊跡，蒼苔滿徑竹齋秋。"]'),
('yuding-99','秋日旅途即事','劉滄','唐','御定全唐诗','yuding','','[]','驅羸多自感，煙草遠郊平。鄉路幾時盡，旅人終日行。',48,'御定全唐詩/json/586.json','["驅羸多自感，煙草遠郊平。鄉路幾時盡，旅人終日行。", "渡邊寒水驛，山下夕陽城。蕭索更何有，秋風兩鬢生。"]'),
('yuding-100','早行','劉滄','唐','御定全唐诗','yuding','','[]','旅途乘早景，策馬獨淒淒。殘影郡樓月，一聲關樹雞。',48,'御定全唐詩/json/586.json','["旅途乘早景，策馬獨淒淒。殘影郡樓月，一聲關樹雞。", "聽鐘煙柳外，問渡水雲西。當自勉行役，終期功業齊。"]'),
('yuding-101','句','劉滄','唐','御定全唐诗','yuding','','[]','海曙雲浮日，江遙水合天。',12,'御定全唐詩/json/586.json','["海曙雲浮日，江遙水合天。"]'),
('yuding-0','湘口送友人','李頻','唐','御定全唐诗','yuding','','[]','中流欲暮見湘煙，葦岸無窮接楚田。去雁遠沖雲夢雪，',40,'御定全唐詩/json/587.json','["中流欲暮見湘煙，葦岸無窮接楚田。去雁遠沖雲夢雪，", "零落梅花過殘臘，故園歸醉及新年。"]'),
('yuding-1','鄂州頭陀寺上方','李頻','唐','御定全唐诗','yuding','','[]','高寺上方無不見，天涯行客思迢迢。西江帆掛東風急，',40,'御定全唐詩/json/587.json','["高寺上方無不見，天涯行客思迢迢。西江帆掛東風急，", "感時歎物尋僧話，惟向禪心得寂寥。"]'),
('yuding-2','寄遠','李頻','唐','御定全唐诗','yuding','','[]','槐欲成陰分袂時，君期十日複金扉。槐今落葉已將盡，',40,'御定全唐詩/json/587.json','["槐欲成陰分袂時，君期十日複金扉。槐今落葉已將盡，", "須知此意同生死，不學他人空寄衣。"]'),
('yuding-3','題張司馬別墅','李頻','唐','御定全唐诗','yuding','','[]','庭前樹盡手中栽，先後花分幾番開。巢鳥戀雛驚不起，',40,'御定全唐詩/json/587.json','["庭前樹盡手中栽，先後花分幾番開。巢鳥戀雛驚不起，", "門外尋常行樂處，重重履跡在莓苔。"]'),
('yuding-4','長安即事','李頻','唐','御定全唐诗','yuding','','[]','長遇豪家不敢過，此身誰與取高科。故園久絕書來後，',40,'御定全唐詩/json/587.json','["長遇豪家不敢過，此身誰與取高科。故園久絕書來後，", "愁人白髮自生早，我獨少年能幾何。"]'),
('yuding-5','漢上逢同年崔八','李頻','唐','御定全唐诗','yuding','','[]','去歲曾遊帝裏春，杏花開過各離秦。偶先托質逢知己，',40,'御定全唐詩/json/587.json','["去歲曾遊帝裏春，杏花開過各離秦。偶先托質逢知己，", "一回相見一回別，能得幾時年少身。"]'),
('yuding-6','五月一日蒙替本官不得隨例入闕，感懷獻送相公','李頻','唐','御定全唐诗','yuding','','[]','五月傾朝謁紫宸，一朝無分在清塵。含香已去星郎位，',40,'御定全唐詩/json/587.json','["五月傾朝謁紫宸，一朝無分在清塵。含香已去星郎位，", "知將何事酬公道，只養生靈似養身。"]'),
('yuding-7','春閨怨','李頻','唐','御定全唐诗','yuding','','[]','紅妝女兒燈下羞，畫眉夫婿隴西頭。',32,'御定全唐詩/json/587.json','["紅妝女兒燈下羞，畫眉夫婿隴西頭。", "自怨愁容長照鏡，悔教征戍覓封侯。"]'),
('yuding-8','送邊將','李頻','唐','御定全唐诗','yuding','','[]','防秋戎馬恐來奔，詔發將軍出雁門。遙領短兵登隴首，',40,'御定全唐詩/json/587.json','["防秋戎馬恐來奔，詔發將軍出雁門。遙領短兵登隴首，", "若縱干戈更深入，應聞收得到昆侖。"]'),
('yuding-9','太和公主還宮','李頻','唐','御定全唐诗','yuding','','[]','天驕發使犯邊塵，漢將推功遂奪親。離亂應無初去貌，',40,'御定全唐詩/json/587.json','["天驕發使犯邊塵，漢將推功遂奪親。離亂應無初去貌，", "重上鳳樓追故事，幾多愁思向青春。"]'),
('yuding-10','將赴黔州先寄本府中丞','李頻','唐','御定全唐诗','yuding','','[]','八月瞿塘到底翻，孤舟上得已銷魂。幕中職罷猶趨府，',40,'御定全唐詩/json/587.json','["八月瞿塘到底翻，孤舟上得已銷魂。幕中職罷猶趨府，", "感知肺腑終難說，從此辭歸便掃門。"]'),
('yuding-11','和友人下第北遊感懷','李頻','唐','御定全唐诗','yuding','','[]','聖代為儒可致身，誰知又別五陵春。青門獨出空歸鳥，',40,'御定全唐詩/json/587.json','["聖代為儒可致身，誰知又別五陵春。青門獨出空歸鳥，", "且須共漉邊城酒，何必陶家有白綸。"]'),
('yuding-12','樂游原春望','李頻','唐','御定全唐诗','yuding','','[]','五陵佳氣晚氛氳，霸業雄圖勢自分。秦地山河連楚塞，',40,'御定全唐詩/json/587.json','["五陵佳氣晚氛氳，霸業雄圖勢自分。秦地山河連楚塞，", "無那楊華起愁思，滿天飄落雪紛紛。"]'),
('yuding-13','黃雀行','李頻','唐','御定全唐诗','yuding','','[]','欲竊高倉集禦河，翩翩疑渡畏秋波。朱宮晚樹侵鶯語，',40,'御定全唐詩/json/587.json','["欲竊高倉集禦河，翩翩疑渡畏秋波。朱宮晚樹侵鶯語，", "誰令不解高飛去，破宅荒庭有網羅。"]'),
('yuding-14','長安寓居寄柏侍郎','李頻','唐','御定全唐诗','yuding','','[]','霜輕兩鬢欲相侵，愁緒無端不可尋。秦女紅妝空覓伴，',40,'御定全唐詩/json/587.json','["霜輕兩鬢欲相侵，愁緒無端不可尋。秦女紅妝空覓伴，", "獨向灞陵東北望，一封書寄萬重心。"]'),
('yuding-15','春日思歸','李頻','唐','御定全唐诗','yuding','','[]','春情不斷若連環，一夕思歸鬢欲斑。壯志未酬三尺劍，',40,'御定全唐詩/json/587.json','["春情不斷若連環，一夕思歸鬢欲斑。壯志未酬三尺劍，", "卻羨浮雲與飛鳥，因風吹去又吹還。"]'),
('yuding-16','朔中即事','李頻','唐','御定全唐诗','yuding','','[]','關門南北雜戎夷，草木秋來即出師。落日風沙長暝早，',40,'御定全唐詩/json/587.json','["關門南北雜戎夷，草木秋來即出師。落日風沙長暝早，", "自古邊功何不立，漢家中外自相疑。"]'),
('yuding-17','感懷獻門下相公','李頻','唐','御定全唐诗','yuding','','[]','誰雲郎選不由詩，上相憐才積有時。卻是龍鍾到門晚，',40,'御定全唐詩/json/587.json','["誰雲郎選不由詩，上相憐才積有時。卻是龍鍾到門晚，", "日望南宮看列宿，迢迢婺女與鄉比。"]'),
('yuding-18','贈長城庾將軍','李頻','唐','御定全唐诗','yuding','','[]','初年三十拜將軍，近代英雄獨未聞。向國報恩心比石，',40,'御定全唐詩/json/587.json','["初年三十拜將軍，近代英雄獨未聞。向國報恩心比石，", "定擁節麾從此去，安西大破犬戎群。"]'),
('yuding-19','浙東獻鄭大夫','李頻','唐','御定全唐诗','yuding','','[]','聖主東憂漲海濱，思移副相倚陶鈞。樓臺獨坐江山月，',40,'御定全唐詩/json/587.json','["聖主東憂漲海濱，思移副相倚陶鈞。樓臺獨坐江山月，", "幾時入去調元化，天下同為堯舜人。"]'),
('yuding-20','鏡湖夜泊有懷','李頻','唐','御定全唐诗','yuding','','[]','廣水遙堤利物功，因思太守惠無窮。自從版築興農隙，',40,'御定全唐詩/json/587.json','["廣水遙堤利物功，因思太守惠無窮。自從版築興農隙，", "想當戰國開時有，範蠡扁舟祗此中。"]'),
('yuding-21','宣州獻從叔大夫','李頻','唐','御定全唐诗','yuding','','[]','清時選地任賢明，從此觀風輟尹京。日月天中辭洛邑，',40,'御定全唐詩/json/587.json','["清時選地任賢明，從此觀風輟尹京。日月天中辭洛邑，", "聞說聖朝同漢代，已愁征入拜公卿。"]'),
('yuding-22','賀同年翰林從叔舍人知制誥','李頻','唐','御定全唐诗','yuding','','[]','仙禁何人躡近蹤，孔門先選得真龍。別居雲路拋三省，',40,'御定全唐詩/json/587.json','["仙禁何人躡近蹤，孔門先選得真龍。別居雲路拋三省，", "芳年貴盛誰為比，鬱鬱青青嶽頂松。"]'),
('yuding-23','吳門別主人','李頻','唐','御定全唐诗','yuding','','[]','早晚更看吳苑月，小齋長憶落西窗。',32,'御定全唐詩/json/587.json','["早晚更看吳苑月，小齋長憶落西窗。", "不知明夜誰家見，應照離人隔楚江。"]'),
('yuding-24','自黔中歸新安','李頻','唐','御定全唐诗','yuding','','[]','朝過春關辭北闕，暮參戎幕向南巴。',32,'御定全唐詩/json/587.json','["朝過春關辭北闕，暮參戎幕向南巴。", "卻將仙桂東歸去，江月相隨直到家。"]'),
('yuding-25','奉和鄭熏相公','李頻','唐','御定全唐诗','yuding','','[]','三四株松匝草亭，便成彭澤柳為名。',32,'御定全唐詩/json/587.json','["三四株松匝草亭，便成彭澤柳為名。", "蓮峰隱去難辭闕，滻水朝回與出城。"]'),
('yuding-26','及第後還家過峴嶺','李頻','唐','御定全唐诗','yuding','','[]','魏馱山前一朵花，嶺西更有幾千家。',32,'御定全唐詩/json/587.json','["魏馱山前一朵花，嶺西更有幾千家。", "石斑魚鮓香沖鼻，淺水沙田飯繞牙。"]'),
('yuding-27','春日旅舍','李頻','唐','御定全唐诗','yuding','','[]','未識東西南北路，青春白日坐銷難。',32,'御定全唐詩/json/587.json','["未識東西南北路，青春白日坐銷難。", "如何一別故園後，五度花開五處看。"]'),
('yuding-28','過長江傷賈島','李頻','唐','御定全唐诗','yuding','','[]','忽從一宦遠流離，無罪無人子細知。',32,'御定全唐詩/json/587.json','["忽從一宦遠流離，無罪無人子細知。", "到得長江聞杜宇，想君魂魄也相隨。"]'),
('yuding-29','自遣','李頻','唐','御定全唐诗','yuding','','[]','永擬東歸把釣絲，將行忽起半心疑。',32,'御定全唐詩/json/587.json','["永擬東歸把釣絲，將行忽起半心疑。", "青雲道是不平地，還有平人上得時。"]'),
('yuding-30','寄曹鄴','李頻','唐','御定全唐诗','yuding','','[]','終南山是枕前雲，禁鼓無因曉夜聞。',32,'御定全唐詩/json/587.json','["終南山是枕前雲，禁鼓無因曉夜聞。", "朝客秋來不朝日，曲江西岸去尋君。"]'),
('yuding-31','述懷','李頻','唐','御定全唐诗','yuding','','[]','望月疑無得桂緣，春天又待到秋天。',32,'御定全唐詩/json/587.json','["望月疑無得桂緣，春天又待到秋天。", "杏花開與槐花落，愁去愁來過幾年。"]'),
('yuding-32','客洛酬劉駕','李頻','唐','御定全唐诗','yuding','','[]','浮世總應相送老，共君偏更遠行多。',32,'御定全唐詩/json/587.json','["浮世總應相送老，共君偏更遠行多。", "此回不似前回別，聽盡離歌逐棹歌。"]'),
('yuding-33','題釣台障子','李頻','唐','御定全唐诗','yuding','','[]','君家儘是我家山，嚴子前臺枕古灣。',32,'御定全唐詩/json/587.json','["君家儘是我家山，嚴子前臺枕古灣。", "卻把釣竿終不可，幾時入海得魚還。"]'),
('yuding-34','題陽山顧煉師草堂','李頻','唐','御定全唐诗','yuding','','[]','若到當時上升處，長生何事後無人。',32,'御定全唐詩/json/587.json','["若到當時上升處，長生何事後無人。", "前峰自去種松子，坐見年來取茯神。"]'),
('yuding-35','聞金吾妓唱梁州','李頻','唐','御定全唐诗','yuding','','[]','聞君一曲古梁州，驚起黃雲塞上愁。',32,'御定全唐詩/json/587.json','["聞君一曲古梁州，驚起黃雲塞上愁。", "秦女樹前花正發，北風吹落滿城秋。"]'),
('yuding-36','游蜀回簡友人','李頻','唐','御定全唐诗','yuding','','[]','別來十二月，去到漏天邊。不是因逢閏，還應是來年。',24,'御定全唐詩/json/587.json','["別來十二月，去到漏天邊。不是因逢閏，還應是來年。"]'),
('yuding-37','贈涇州王侍禦','李頻','唐','御定全唐诗','yuding','','[]','一旦天書下紫微，三年旌旆隴雲飛。',32,'御定全唐詩/json/587.json','["一旦天書下紫微，三年旌旆隴雲飛。", "塞門無事春空到，邊草青青戰馬肥。"]'),
('yuding-38','夏日宿秘書姚監宅','李頻','唐','御定全唐诗','yuding','','[]','貴宅多嘉樹，先秋有好風。情閑離闕下，夢野在山中。',48,'御定全唐詩/json/587.json','["貴宅多嘉樹，先秋有好風。情閑離闕下，夢野在山中。", "露色浮寒瓦，螢光墮暗叢。聽吟麗句盡，河漢任西東。"]'),
('yuding-39','過嵩陰隱者','李頻','唐','御定全唐诗','yuding','','[]','當門看少室，倚杖複披衣。每日醒還醉，無人是與非。',48,'御定全唐詩/json/587.json','["當門看少室，倚杖複披衣。每日醒還醉，無人是與非。", "架書抽讀亂，庭果摘嘗稀。獨有江南客，思家未得歸。"]'),
('yuding-40','留別山家','李頻','唐','御定全唐诗','yuding','','[]','閑門不易求，半月在林丘。已與山水別，難為花木留。',48,'御定全唐詩/json/587.json','["閑門不易求，半月在林丘。已與山水別，難為花木留。", "孤懷歸靜夜，遠會隔高秋。莫道無言去，冥心在重遊。"]'),
('yuding-41','送人游吳','李頻','唐','御定全唐诗','yuding','','[]','楚田開雪後，草色與君看。積水浮春氣，深山滯雨寒。',48,'御定全唐詩/json/587.json','["楚田開雪後，草色與君看。積水浮春氣，深山滯雨寒。", "毗陵孤月出，建業一鐘殘。為把鄉書去，因收別淚難。"]'),
('yuding-42','東渭橋晚眺','李頻','唐','御定全唐诗','yuding','','[]','秦地有吳洲，千檣渭曲頭。人當返照立，水徹故鄉流。',48,'御定全唐詩/json/587.json','["秦地有吳洲，千檣渭曲頭。人當返照立，水徹故鄉流。", "落第春難過，窮途日易愁。誰知橋上思，萬里在江樓。"]'),
('yuding-43','送延陵韋少府','李頻','唐','御定全唐诗','yuding','','[]','延陵稱貴邑，季子有高蹤。古跡傳多代，仙山管幾峰。',48,'御定全唐詩/json/587.json','["延陵稱貴邑，季子有高蹤。古跡傳多代，仙山管幾峰。", "微泉聲小雨，異木色深冬。去畢三年秩，新詩篋不容。"]'),
('yuding-44','淮南送友人歸滄州','李頻','唐','御定全唐诗','yuding','','[]','風色忽西轉，坐為千里分。高帆背楚落，寒日逆淮曛。',48,'御定全唐詩/json/587.json','["風色忽西轉，坐為千里分。高帆背楚落，寒日逆淮曛。", "斷燒緣喬木，盤雕隱片雲。鄉關百戰地，歸去始休軍。"]'),
('yuding-45','夏日題盩厔友人書齋','李頻','唐','御定全唐诗','yuding','','[]','修竹齊高樹，書齋竹樹中。四時無夏氣，三伏有秋風。',48,'御定全唐詩/json/587.json','["修竹齊高樹，書齋竹樹中。四時無夏氣，三伏有秋風。", "黑處巢幽鳥，陰來叫候蟲。窗西太白雪，萬仞在遙空。"]'),
('yuding-46','尋山','李頻','唐','御定全唐诗','yuding','','[]','一徑入雙崖，初疑有幾家。行窮人不見，坐久日空斜。',48,'御定全唐詩/json/587.json','["一徑入雙崖，初疑有幾家。行窮人不見，坐久日空斜。", "石上生靈草，泉中落異花。終須結茅屋，向此學餐霞。"]'),
('yuding-47','送元遂上人歸錢唐','李頻','唐','御定全唐诗','yuding','','[]','白衣遊帝鄉，已得事空王。卻返湖山寺，高禪水月房。',48,'御定全唐詩/json/587.json','["白衣遊帝鄉，已得事空王。卻返湖山寺，高禪水月房。", "雨中過岳黑，秋後宿船涼。回顧秦人語，他生會別方。"]'),
('yuding-48','貽友人喻坦之','李頻','唐','御定全唐诗','yuding','','[]','從容心自切，飲水勝銜杯。共在山中長，相隨闕下來。',48,'御定全唐詩/json/587.json','["從容心自切，飲水勝銜杯。共在山中長，相隨闕下來。", "修身空有道，取事各無媒。不信升平代，終遺草澤才。"]'),
('yuding-49','送友人往振武','李頻','唐','御定全唐诗','yuding','','[]','風沙遙見說，道路替君愁。磧夜星垂地，雲明火上樓。',48,'御定全唐詩/json/587.json','["風沙遙見說，道路替君愁。磧夜星垂地，雲明火上樓。", "征鴻辭塞雪，戰馬識邊秋。不共將軍語，何因有去留。"]'),
('yuding-50','賦得長城斑竹杖','李頻','唐','御定全唐诗','yuding','','[]','秦興版築時，翦伐不知誰。異代餘根在，幽人得手持。',48,'御定全唐詩/json/587.json','["秦興版築時，翦伐不知誰。異代餘根在，幽人得手持。", "細看生古意，閑倚動邊思。莫作鳩形並，空將鶴發期。"]'),
('yuding-51','送德清喻明府','李頻','唐','御定全唐诗','yuding','','[]','棹返霅溪雲，仍參舊使君。州傳多古跡，縣記是新文。',48,'御定全唐詩/json/587.json','["棹返霅溪雲，仍參舊使君。州傳多古跡，縣記是新文。", "水柵橫舟閉，湖田立木分。但如詩思苦，為政即超群。"]'),
('yuding-52','送薛能少府任盩厔','李頻','唐','御定全唐诗','yuding','','[]','不才甘下第，君子蹇何重。相送昆明岸，同看太白峰。',48,'御定全唐詩/json/587.json','["不才甘下第，君子蹇何重。相送昆明岸，同看太白峰。", "數瓢留頃刻，殘照迫從容。好去煙霞縣，仙人有舊蹤。"]'),
('yuding-53','送許壽下第歸東山','李頻','唐','御定全唐诗','yuding','','[]','吾君設禮闈，誰合學忘機。卻是高人起，難為下第歸。',48,'御定全唐詩/json/587.json','["吾君設禮闈，誰合學忘機。卻是高人起，難為下第歸。", "出關心縱野，避世事終稀。莫更今秋夕，相思望少微。"]'),
('yuding-54','冬夜酬范秘書','李頻','唐','御定全唐诗','yuding','','[]','九衢行一匝，不敢入他門。累日無餘事，通宵得至言。',48,'御定全唐詩/json/587.json','["九衢行一匝，不敢入他門。累日無餘事，通宵得至言。", "命嗟清世蹇，春覺閏冬暄。翻覆吟佳句，何酬國士恩。"]'),
('yuding-55','送陸肱尉江夏','李頻','唐','御定全唐诗','yuding','','[]','如何執簡去，便作掛帆期。澤國三春早，江天落日遲。',48,'御定全唐詩/json/587.json','["如何執簡去，便作掛帆期。澤國三春早，江天落日遲。", "縣人齊候處，洲鳥欲飛時。免褐方三十，青雲豈白髭。"]'),
('yuding-56','漢上送人西歸','李頻','唐','御定全唐诗','yuding','','[]','幾作西歸夢，因為愴別心。野銜天去盡，山夾漢來深。',48,'御定全唐詩/json/587.json','["幾作西歸夢，因為愴別心。野銜天去盡，山夾漢來深。", "疊浪翻殘照，高帆引片陰。空留相贈句，畢我白頭吟。"]'),
('yuding-57','蜀中逢友人','李頻','唐','御定全唐诗','yuding','','[]','自古有行役，誰人免別家。相歡猶陌上，一醉任天涯。',48,'御定全唐詩/json/587.json','["自古有行役，誰人免別家。相歡猶陌上，一醉任天涯。", "積疊山藏蜀，潺湲水繞巴。他年複何處，共說海棠花。"]'),
('yuding-58','寄範評事','李頻','唐','御定全唐诗','yuding','','[]','行坐不相遺，轅門載筆時。雅知難更遇，舊分合長思。',48,'御定全唐詩/json/587.json','["行坐不相遺，轅門載筆時。雅知難更遇，舊分合長思。", "夢即重尋熟，書常轉達遲。山齋終擬到，何日遂心期。"]'),
('yuding-59','南遊過湘漢即事寄友人','李頻','唐','御定全唐诗','yuding','','[]','南去遠驅逐，三湘五月行。巴山雪水下，楚澤火雲生。',48,'御定全唐詩/json/587.json','["南去遠驅逐，三湘五月行。巴山雪水下，楚澤火雲生。", "向野聊中飯，乘涼探暮程。離懷不可說，已迫峽猿聲。"]'),
('yuding-60','送許渾侍禦赴潤州','李頻','唐','御定全唐诗','yuding','','[]','家山近石頭，遂意恣東遊。祖席離烏府，歸帆轉蜃樓。',48,'御定全唐詩/json/587.json','["家山近石頭，遂意恣東遊。祖席離烏府，歸帆轉蜃樓。", "陰氛出海散，落月向潮流。別有為霖日，孤雲未自由。"]'),
('yuding-61','喜友人厲圖南及第','李頻','唐','御定全唐诗','yuding','','[]','相憂過己切，相賀似身榮。心達無前後，神交共死生。',48,'御定全唐詩/json/587.json','["相憂過己切，相賀似身榮。心達無前後，神交共死生。", "承家吾子事，登第世人情。未有通儒術，明時道不行。"]'),
('yuding-62','送友人下第歸越','李頻','唐','御定全唐诗','yuding','','[]','歸意隨流水，江湖共在東。山陰何處去，草際片帆通。',48,'御定全唐詩/json/587.json','["歸意隨流水，江湖共在東。山陰何處去，草際片帆通。", "雨色春愁裏，潮聲曉夢中。雖為半年客，便是往來鴻。"]'),
('yuding-63','寄友人','李頻','唐','御定全唐诗','yuding','','[]','一別一相見，須臾老此生。客衣寒後薄，山思夜深清。',48,'御定全唐詩/json/587.json','["一別一相見，須臾老此生。客衣寒後薄，山思夜深清。", "詩近吟何句，髭新白幾莖。路岐如昨日，來往夢分明。"]'),
('yuding-64','送友人下第歸宛陵','李頻','唐','御定全唐诗','yuding','','[]','天涯長戀親，闕下獨傷春。擬住還求己，須歸不為身。',48,'御定全唐詩/json/587.json','["天涯長戀親，闕下獨傷春。擬住還求己，須歸不為身。", "臨岐仍犯雪，掛席始離塵。共泣東風別，同為滄海人。"]'),
('yuding-65','秋夜對月寄鳳翔范書記','李頻','唐','御定全唐诗','yuding','','[]','月過秋霖後，光應夜夜清。一回相憶起，幾度獨吟行。',48,'御定全唐詩/json/587.json','["月過秋霖後，光應夜夜清。一回相憶起，幾度獨吟行。", "河漢東西直，山川遠近明。寸心遙往處，新有雁來聲。"]'),
('yuding-66','送孫明秀才往潘州訪韋卿','李頻','唐','御定全唐诗','yuding','','[]','北鳥飛不到，北人今去遊。天涯浮瘴水，嶺外問潘州。',48,'御定全唐詩/json/587.json','["北鳥飛不到，北人今去遊。天涯浮瘴水，嶺外問潘州。", "草木春冬茂，猿猱日夜愁。定知遷客淚，應只對君流。"]'),
('yuding-67','八月十五夜對月','李頻','唐','御定全唐诗','yuding','','[]','陰盛此宵中，多為雨與風。坐無雲雨至，看與雪霜同。',48,'御定全唐詩/json/587.json','["陰盛此宵中，多為雨與風。坐無雲雨至，看與雪霜同。", "抱濕離遙海，傾寒向迥空。年年不可值，還似命難通。"]'),
('yuding-68','及第後歸','李頻','唐','御定全唐诗','yuding','','[]','家臨浙水傍，岸對買臣鄉。縱棹隨歸鳥，乘潮向夕陽。',48,'御定全唐詩/json/587.json','["家臨浙水傍，岸對買臣鄉。縱棹隨歸鳥，乘潮向夕陽。", "苦吟身得雪，甘意鬢成霜。況此年猶少，酬知足自強。"]'),
('yuding-69','過巫峽','李頻','唐','御定全唐诗','yuding','','[]','擁棹向驚湍，巫峰直上看。削成從水底，聳出在雲端。',48,'御定全唐詩/json/587.json','["擁棹向驚湍，巫峰直上看。削成從水底，聳出在雲端。", "暮雨晴時少，啼猿渴下難。一聞神女去，風竹掃空壇。"]'),
('yuding-0','送友人往太原','李頻','唐','御定全唐诗','yuding','','[]','離亭聊把酒，此路徹邊頭。草白雁來盡，時清人去遊。',48,'御定全唐詩/json/588.json','["離亭聊把酒，此路徹邊頭。草白雁來盡，時清人去遊。", "汾河流晉地，塞雪滿並州。別後相思夜，空看北斗愁。"]'),
('yuding-1','旅懷','李頻','唐','御定全唐诗','yuding','','[]','萬里共心論，徒言吾道存。奉親無別業，謁帝有何門。',48,'御定全唐詩/json/588.json','["萬里共心論，徒言吾道存。奉親無別業，謁帝有何門。", "水宿驚濤浦，山行落葉村。長安長夢去，欹枕即聞猿。"]'),
('yuding-2','送裴禦史赴湖南','李頻','唐','御定全唐诗','yuding','','[]','關門鳥道中，飛傳複乘驄。暮雪離秦甸，春雲入楚宮。',48,'御定全唐詩/json/588.json','["關門鳥道中，飛傳複乘驄。暮雪離秦甸，春雲入楚宮。", "平蕪天共闊，積水地多空。使府懸帆去，能消幾日風。"]'),
('yuding-3','送姚郜先輩赴汝州辟','李頻','唐','御定全唐诗','yuding','','[]','行李事寒天，東來聘禮全。州當定鼎處，人去偃戈年。',48,'御定全唐詩/json/588.json','["行李事寒天，東來聘禮全。州當定鼎處，人去偃戈年。", "雷雨依嵩嶺，桑麻接楚田。遙知清夜作，不是借戎篇。"]'),
('yuding-4','初離黔中泊江上','李頻','唐','御定全唐诗','yuding','','[]','去去把青桂，平生心不違。更蒙蓮府辟，兼脫布衣歸。',48,'御定全唐詩/json/588.json','["去去把青桂，平生心不違。更蒙蓮府辟，兼脫布衣歸。", "霽嶽明殘雪，清波漾落暉。無窮幽鳥戲，時向棹前飛。"]'),
('yuding-5','黔中酬同院韋判官','李頻','唐','御定全唐诗','yuding','','[]','平生同所為，相遇偶然遲。各著青袍後，無歸白社期。',48,'御定全唐詩/json/588.json','["平生同所為，相遇偶然遲。各著青袍後，無歸白社期。", "江流來絕域，府地管諸夷。聖代都無事，從公且賦詩。"]'),
('yuding-6','和范秘書襄陽舊游','李頻','唐','御定全唐诗','yuding','','[]','聽話揚帆興，初從峴首還。高吟入白浪，遙坐看青山。',48,'御定全唐詩/json/588.json','["聽話揚帆興，初從峴首還。高吟入白浪，遙坐看青山。", "枯木猿啼爽，寒汀鶴步閑。秋來關去夢，幾夜度商顏。"]'),
('yuding-7','秋夜山中思歸送友人','李頻','唐','御定全唐诗','yuding','','[]','蕭條對秋色，相憶在雲泉。木落病身起，潮平歸思懸。',48,'御定全唐詩/json/588.json','["蕭條對秋色，相憶在雲泉。木落病身起，潮平歸思懸。", "涼鐘山頂寺，暝火渡頭船。此地非吾土，淹留又一年。"]'),
('yuding-8','自黔中東歸旅次淮上','李頻','唐','御定全唐诗','yuding','','[]','行旅本同愁，黔吳複阻修。半年方中路，窮節到孤舟。',48,'御定全唐詩/json/588.json','["行旅本同愁，黔吳複阻修。半年方中路，窮節到孤舟。", "夕靄垂陰野，晨光動積流。家山一夜夢，便是昔年遊。"]'),
('yuding-9','江夏春感舊','李頻','唐','御定全唐诗','yuding','','[]','東風出海門，處處動林園。澤國雪霜少，沙汀花木繁。',48,'御定全唐詩/json/588.json','["東風出海門，處處動林園。澤國雪霜少，沙汀花木繁。", "暖魚依水淺，晴雁入空翻。何處陽和力，生萍不駐根。"]'),
('yuding-10','眉州別李使君','李頻','唐','御定全唐诗','yuding','','[]','回首雪峰前，朱門心杳然。離人自嗚咽，流水莫潺湲。',48,'御定全唐詩/json/588.json','["回首雪峰前，朱門心杳然。離人自嗚咽，流水莫潺湲。", "毒草通蠻徼，秋林近漏天。一生從此去，五字有誰憐。"]'),
('yuding-11','送許棠及第歸宣州','李頻','唐','御定全唐诗','yuding','','[]','高科終自致，志業信如神。待得逢公道，由來合貴身。',48,'御定全唐詩/json/588.json','["高科終自致，志業信如神。待得逢公道，由來合貴身。", "秋歸方覺好，舊夢始知真。更想青山宅，誰為後主人。"]'),
('yuding-12','黔中罷職將泛江東','李頻','唐','御定全唐诗','yuding','','[]','黔中初罷職，薄俸亦無殘。舉目鄉關遠，攜家旅食難。',48,'御定全唐詩/json/588.json','["黔中初罷職，薄俸亦無殘。舉目鄉關遠，攜家旅食難。", "野梅將雪競，江月與沙寒。兩鬢愁應白，何勞把鏡看。"]'),
('yuding-13','長安書事寄所知','李頻','唐','御定全唐诗','yuding','','[]','帝裏本無名，端居有道情。睡魂春夢斷，書興晚窗明。',48,'御定全唐詩/json/588.json','["帝裏本無名，端居有道情。睡魂春夢斷，書興晚窗明。", "老擬歸何處，閑應過此生。江湖終一日，拜別便東行。"]'),
('yuding-14','酬姚覃','李頻','唐','御定全唐诗','yuding','','[]','不見又相招，何曾訴寂寥。醉眠春草長，吟坐夜燈銷。',48,'御定全唐詩/json/588.json','["不見又相招，何曾訴寂寥。醉眠春草長，吟坐夜燈銷。", "淚墮思山切，身歸轉路遙。年年送別處，楊柳少垂條。"]'),
('yuding-15','春日鄜州贈裴居言','李頻','唐','御定全唐诗','yuding','','[]','雖將身佐幕，出入似閒居。草色長相待，山情信不疏。',48,'御定全唐詩/json/588.json','["雖將身佐幕，出入似閒居。草色長相待，山情信不疏。", "燈前春睡足，酒後夜寒餘。筆硯時時近，終非署簿書。"]'),
('yuding-16','送於生入蜀','李頻','唐','御定全唐诗','yuding','','[]','家吳聞入蜀，道路頗乖離。一第何多難，都城可少知。',48,'御定全唐詩/json/588.json','["家吳聞入蜀，道路頗乖離。一第何多難，都城可少知。", "江山非久適，命數未終奇。況又將冤抱，經春杜魄隨。"]'),
('yuding-17','送許棠歸涇縣作尉','李頻','唐','御定全唐诗','yuding','','[]','青桂複青袍，一歸榮一高。縣人齊下拜，邑宰共分曹。',48,'御定全唐詩/json/588.json','["青桂複青袍，一歸榮一高。縣人齊下拜，邑宰共分曹。", "繞郭看秧插，尋街聽繭繅。封侯萬里者，燕頷乃徒勞。"]'),
('yuding-18','友人話別','李頻','唐','御定全唐诗','yuding','','[]','論交雖不早，話別且相親。除卻棲禪客，誰非南陌人。',48,'御定全唐詩/json/588.json','["論交雖不早，話別且相親。除卻棲禪客，誰非南陌人。", "半生都返性，終老擬安貧。願入白雲社，高眠自致身。"]'),
('yuding-19','山居','李頻','唐','御定全唐诗','yuding','','[]','欲出窮吾道，東西自未能。卷書唯對鶴，開畫獨留僧。',48,'御定全唐詩/json/588.json','["欲出窮吾道，東西自未能。卷書唯對鶴，開畫獨留僧。", "落葉和雲掃，秋山共月登。何年石上水，夜夜滴高層。"]'),
('yuding-20','寄范郎中','李頻','唐','御定全唐诗','yuding','','[]','藜杖山中出，吟詩對範家。相知從海嶠，寄食向京華。',48,'御定全唐詩/json/588.json','["藜杖山中出，吟詩對範家。相知從海嶠，寄食向京華。", "名宦成何報，清眸未縱賒。臨邛夢來往，雨雪滿褒斜。"]'),
('yuding-21','書懷','李頻','唐','御定全唐诗','yuding','','[]','宦途從不問，身事覺無差。華髮初生女，滄洲未有家。',48,'御定全唐詩/json/588.json','["宦途從不問，身事覺無差。華髮初生女，滄洲未有家。", "卻閑思洞穴，終老曠桑麻。別訪棲禪侶，相期語劫沙。"]'),
('yuding-22','越中行','李頻','唐','御定全唐诗','yuding','','[]','越國臨滄海，芳洲複暮晴。湖通諸浦白，日隱亂峰明。',48,'御定全唐詩/json/588.json','["越國臨滄海，芳洲複暮晴。湖通諸浦白，日隱亂峰明。", "野宿多無定，閒遊免有情。天臺聞不遠，終到石橋行。"]'),
('yuding-23','春日南遊寄浙東許同年','李頻','唐','御定全唐诗','yuding','','[]','孤帆處處宿，不問是誰家。南國平蕪遠，東風細雨斜。',48,'御定全唐詩/json/588.json','["孤帆處處宿，不問是誰家。南國平蕪遠，東風細雨斜。", "旅懷多寄酒，寒意欲留花。更想前途去，茫茫滄海涯。"]'),
('yuding-24','明州江亭夜別段秀才','李頻','唐','御定全唐诗','yuding','','[]','離亭向水開，時候複蒸梅。霹靂燈燭滅，蒹葭風雨來。',48,'御定全唐詩/json/588.json','["離亭向水開，時候複蒸梅。霹靂燈燭滅，蒹葭風雨來。", "京關雖共語，海嶠不同回。莫為蓴鱸美，天涯滯爾才。"]'),
('yuding-25','臨岐留別相知','李頻','唐','御定全唐诗','yuding','','[]','百歲竟何事，一身長遠遊。行行將近老，處處不離愁。',48,'御定全唐詩/json/588.json','["百歲竟何事，一身長遠遊。行行將近老，處處不離愁。", "世路多相取，權門不自投。難為此時別，欲別願人留。"]'),
('yuding-26','鄂渚湖上即事','李頻','唐','御定全唐诗','yuding','','[]','杜門聊自適，湖水在窗間。縱得滄洲去，無過白日閑。',48,'御定全唐詩/json/588.json','["杜門聊自適，湖水在窗間。縱得滄洲去，無過白日閑。", "多慵空好道，少賤早凋顏。獨有東山月，依依自往還。"]'),
('yuding-27','辭夏口崔尚書','李頻','唐','御定全唐诗','yuding','','[]','一飯仍難受，依仁況一年。終期身可報，不擬骨空鐫。',48,'御定全唐詩/json/588.json','["一飯仍難受，依仁況一年。終期身可報，不擬骨空鐫。", "城晚風高角，江春浪起船。同來棲止地，獨去塞鴻前。"]'),
('yuding-28','秦原早望','李頻','唐','御定全唐诗','yuding','','[]','一忝鄉書薦，長安未得回。年光逐渭水，春色上秦台。',48,'御定全唐詩/json/588.json','["一忝鄉書薦，長安未得回。年光逐渭水，春色上秦台。", "燕掠平蕪去，人沖細雨來。東風生故里，又過幾花開。"]'),
('yuding-29','送友人之揚州','李頻','唐','御定全唐诗','yuding','','[]','一別長安後，晨征便信雞。河聲入峽急，地勢出關低。',48,'御定全唐詩/json/588.json','["一別長安後，晨征便信雞。河聲入峽急，地勢出關低。", "綠樹叢垓下，青蕪闊楚西。路長知不惡，隨處得詩題。"]'),
('yuding-30','過四皓廟','李頻','唐','御定全唐诗','yuding','','[]','東西南北人，高跡自相親。天下已歸漢，山中猶避秦。',48,'御定全唐詩/json/588.json','["東西南北人，高跡自相親。天下已歸漢，山中猶避秦。", "龍樓曾作客，鶴氅不為臣。獨有千年後，青青廟木春。"]'),
('yuding-31','陝下懷歸','李頻','唐','御定全唐诗','yuding','','[]','故園何處在，零落五湖東。日暮無來客，天寒有去鴻。',48,'御定全唐詩/json/588.json','["故園何處在，零落五湖東。日暮無來客，天寒有去鴻。", "大河冰徹塞，高岳雪連空。獨夜懸歸思，迢迢永漏中。"]'),
('yuding-32','送徐處士歸江南','李頻','唐','御定全唐诗','yuding','','[]','行行野雪薄，寒氣日通春。故國又芳草，滄江終白身。',48,'御定全唐詩/json/588.json','["行行野雪薄，寒氣日通春。故國又芳草，滄江終白身。", "游歸花落滿，睡起鳥啼新。莫惜閑書劄，西來問旅人。"]'),
('yuding-33','鄜州留別王從事','李頻','唐','御定全唐诗','yuding','','[]','相識未十日，相知如十年。從來易離別，此去忽留連。',48,'御定全唐詩/json/588.json','["相識未十日，相知如十年。從來易離別，此去忽留連。", "路險行沖雨，山高度隔天。難終清夜坐，更聽說安邊。"]'),
('yuding-34','長安夜懷','李頻','唐','御定全唐诗','yuding','','[]','匹馬西遊日，從吳又轉荊。風雷幾夜坐，山水半年行。',48,'御定全唐詩/json/588.json','["匹馬西遊日，從吳又轉荊。風雷幾夜坐，山水半年行。", "夢永秋燈滅，吟餘曉露明。良時不我與，白髮向秦生。"]'),
('yuding-35','冬夜山中尋友','李頻','唐','御定全唐诗','yuding','','[]','何人山雪夜，相訪不相思。若得長閑日，應無暫到時。',48,'御定全唐詩/json/588.json','["何人山雪夜，相訪不相思。若得長閑日，應無暫到時。", "葉寒凋欲盡，泉凍落還遲。即此天明去，重來未有期。"]'),
('yuding-36','送劉山人歸洞庭','李頻','唐','御定全唐诗','yuding','','[]','君逐雲山去，人間又絕蹤。半湖乘早月，中路入疏鐘。',48,'御定全唐詩/json/588.json','["君逐雲山去，人間又絕蹤。半湖乘早月，中路入疏鐘。", "秋盡草蟲急，夜深山雨重。平生心未已，豈得更相從。"]'),
('yuding-37','古意','李頻','唐','御定全唐诗','yuding','','[]','白馬遊何處，青樓日正長。鳳簫拋舊曲，鸞鏡懶新妝。',48,'御定全唐詩/json/588.json','["白馬遊何處，青樓日正長。鳳簫拋舊曲，鸞鏡懶新妝。", "玄鳥深巢靜，飛花入戶香。雖非竇滔婦，錦字已成章。"]'),
('yuding-38','避暑','李頻','唐','御定全唐诗','yuding','','[]','當暑憶歸林，陶家借柳陰。蟬從初伏噪，客向晚涼吟。',48,'御定全唐詩/json/588.json','["當暑憶歸林，陶家借柳陰。蟬從初伏噪，客向晚涼吟。", "白日欺玄鬢，滄江負素心。神仙倘有術，引我出幽岑。"]'),
('yuding-39','送吳秘書歸杭州','李頻','唐','御定全唐诗','yuding','','[]','為客得從容，官清料複重。海崖歸有業，天目近何峰。',48,'御定全唐詩/json/588.json','["為客得從容，官清料複重。海崖歸有業，天目近何峰。", "是處通春棹，無村不夜舂。馬卿誇貴達，還說返臨邛。"]'),
('yuding-40','中秋對月','李頻','唐','御定全唐诗','yuding','','[]','秋分一夜停，陰魄最晶熒。好是生滄海，徐看曆杳冥。',48,'御定全唐詩/json/588.json','["秋分一夜停，陰魄最晶熒。好是生滄海，徐看曆杳冥。", "層空疑洗色，萬怪想潛形。他夕無相類，晨雞不可聽。"]'),
('yuding-41','八月上峽','李頻','唐','御定全唐诗','yuding','','[]','萬里巴江水，秋來滿峽流。亂山無陸路，行客在孤舟。',48,'御定全唐詩/json/588.json','["萬里巴江水，秋來滿峽流。亂山無陸路，行客在孤舟。", "洶洶灘聲急，冥冥樹色愁。免為三不吊，已白一生頭。"]'),
('yuding-42','送狄明府赴九江','李頻','唐','御定全唐诗','yuding','','[]','字人修祖德，清白定聞傳。匹馬從秦去，孤帆入楚懸。',48,'御定全唐詩/json/588.json','["字人修祖德，清白定聞傳。匹馬從秦去，孤帆入楚懸。", "關中寒食雨，湖上暑衣天。四考兼重請，相知住幾年。"]'),
('yuding-43','陝下投姚諫議','李頻','唐','御定全唐诗','yuding','','[]','舊業在東鄙，西游從楚荊。風雷幾夜坐，山水半年行。',48,'御定全唐詩/json/588.json','["舊業在東鄙，西游從楚荊。風雷幾夜坐，山水半年行。", "夢永秋燈滅，吟孤曉露明。前心若不遂，有恥卻歸耕。"]'),
('yuding-44','關東逢薛能','李頻','唐','御定全唐诗','yuding','','[]','何處不相思，相逢還有時。交心如到老，會面未為遲。',48,'御定全唐詩/json/588.json','["何處不相思，相逢還有時。交心如到老，會面未為遲。", "苦學緣明代，勞生欲白髭。唯君一度別，便似見無期。"]'),
('yuding-45','富春贈孫璐','李頻','唐','御定全唐诗','yuding','','[]','天柱與天目，曾棲絕頂房。青雲求祿晚，白日坐家長。',48,'御定全唐詩/json/588.json','["天柱與天目，曾棲絕頂房。青雲求祿晚，白日坐家長。", "井氣通潮信，窗風引海涼。平生詩稱在，老達亦何妨。"]'),
('yuding-46','送友人游蜀','李頻','唐','御定全唐诗','yuding','','[]','東堂雖不捷，西去複何愁。蜀馬知歸路，巴山似舊遊。',48,'御定全唐詩/json/588.json','["東堂雖不捷，西去複何愁。蜀馬知歸路，巴山似舊遊。", "星臨劍閣動，花落錦江流。鼓吹青林下，時聞祭武侯。"]'),
('yuding-47','夏日盩厔郊居寄姚少府','李頻','唐','御定全唐诗','yuding','','[]','古木有清陰，寒泉有下深。蟬從初伏噪，客向晚涼吟。',48,'御定全唐詩/json/588.json','["古木有清陰，寒泉有下深。蟬從初伏噪，客向晚涼吟。", "白日欺玄鬢，滄江負素心。甚思中夜話，何路許相尋。"]'),
('yuding-48','送胡休處士歸湘江','李頻','唐','御定全唐诗','yuding','','[]','見說湘江切，長愁有去時。江湖秋涉遠，雷雨夜眠遲。',48,'御定全唐詩/json/588.json','["見說湘江切，長愁有去時。江湖秋涉遠，雷雨夜眠遲。", "舊業多歸興，空山盡老期。天寒一瓢酒，落日醉留誰。"]'),
('yuding-49','峽州送清澈上人歸浙西','李頻','唐','御定全唐诗','yuding','','[]','風濤幾千里，歸路半乘舟。此地難相遇，何人更共遊。',48,'御定全唐詩/json/588.json','["風濤幾千里，歸路半乘舟。此地難相遇，何人更共遊。", "坐經嵩頂夏，行值洛陽秋。到寺安禪夕，江雲滿石樓。"]'),
('yuding-50','送僧入天臺','李頻','唐','御定全唐诗','yuding','','[]','一錫隨緣赴，天臺又去登。長亭舊別路，落日獨行僧。',48,'御定全唐詩/json/588.json','["一錫隨緣赴，天臺又去登。長亭舊別路，落日獨行僧。", "夜燒山何處，秋帆浪幾層。他時授巾拂，莫為老無能。"]'),
('yuding-51','回山后寄范酂先輩','李頻','唐','御定全唐诗','yuding','','[]','高樓會月夜，北雁向南分。留住經春雪，辭來見夏雲。',48,'御定全唐詩/json/588.json','["高樓會月夜，北雁向南分。留住經春雪，辭來見夏雲。", "遙空江不極，絕頂日難曛。一與山僧坐，無因得議文。"]'),
('yuding-52','長安送友人東歸','李頻','唐','御定全唐诗','yuding','','[]','白社思歸處，青門見去人。鄉遙茂苑樹，路入廣陵塵。',48,'御定全唐詩/json/588.json','["白社思歸處，青門見去人。鄉遙茂苑樹，路入廣陵塵。", "海日潮浮曉，湖山雪露春。猶期來帝裏，未是得閒人。"]'),
('yuding-53','深秋過源宗上人房','李頻','唐','御定全唐诗','yuding','','[]','到日值搖落，相留山舍空。微寒生夜半，積雨向秋終。',48,'御定全唐詩/json/588.json','["到日值搖落，相留山舍空。微寒生夜半，積雨向秋終。", "度講多來雁，經禪少候蟲。方從聽話後，不省在愁中。"]'),
('yuding-54','秋日登山閣','李頻','唐','御定全唐诗','yuding','','[]','蒼蒼山閣晚，杳杳隙塵秋。偶上多時立，翻成盡日愁。',48,'御定全唐詩/json/588.json','["蒼蒼山閣晚，杳杳隙塵秋。偶上多時立，翻成盡日愁。", "草平連邑動，河滿逐江流。下視窮邊路，行人在隴頭。"]'),
('yuding-55','秋宿慈恩寺遂上人院','李頻','唐','御定全唐诗','yuding','','[]','滿閣終南色，清宵獨倚欄。風高斜漢動，葉下曲江寒。',48,'御定全唐詩/json/588.json','["滿閣終南色，清宵獨倚欄。風高斜漢動，葉下曲江寒。", "帝裏求名老，空門見性難。吾師無一事，不似在長安。"]'),
('yuding-56','題棲霞寺慶上人院','李頻','唐','御定全唐诗','yuding','','[]','居與鳥巢鄰，日將巢鳥親。多生從此性，久集得無身。',48,'御定全唐詩/json/588.json','["居與鳥巢鄰，日將巢鳥親。多生從此性，久集得無身。", "樹老風終夜，山寒雪見春。不知諸祖後，傳印是何人。"]'),
('yuding-57','送友人入蜀','李頻','唐','御定全唐诗','yuding','','[]','天際蜀門開，西看舉別杯。何人不異禮，上客自懷才。',48,'御定全唐詩/json/588.json','["天際蜀門開，西看舉別杯。何人不異禮，上客自懷才。", "夜澗青林發，秋江淥水來。臨邛行樂處，莫到白頭回。"]'),
('yuding-58','贈同官蘇明府','李頻','唐','御定全唐诗','yuding','','[]','山中畿內邑，別覺大夫清。簿領分王事，官資寄野情。',48,'御定全唐詩/json/588.json','["山中畿內邑，別覺大夫清。簿領分王事，官資寄野情。", "閑齋無獄訟，隱幾向泉聲。從此朝天路，門前是去程。"]'),
('yuding-59','送厲圖南往荊州覲伯','李頻','唐','御定全唐诗','yuding','','[]','雲水入荊湘，古來魚鳥鄉。故關重隔遠，春日獨行長。',48,'御定全唐詩/json/588.json','["雲水入荊湘，古來魚鳥鄉。故關重隔遠，春日獨行長。", "山溜含清韻，江雷吐夜光。郡中詞客會，遊子更升堂。"]'),
('yuding-60','山中夜坐','李頻','唐','御定全唐诗','yuding','','[]','歸家來幾夜，倏忽覺秋殘。月滿方塘白，風依老樹寒。',48,'御定全唐詩/json/588.json','["歸家來幾夜，倏忽覺秋殘。月滿方塘白，風依老樹寒。", "戲魚重躍定，驚鳥卻棲難。為有門前路，吾生不得安。"]'),
('yuding-61','送台州唐興陳明府','李頻','唐','御定全唐诗','yuding','','[]','見說海西隅，山川與俗殊。宦遊如不到，仙分即應無。',48,'御定全唐詩/json/588.json','["見說海西隅，山川與俗殊。宦遊如不到，仙分即應無。", "瀑布當公署，天臺是縣圖。遙知為吏去，有術字惸孤。"]'),
('yuding-62','夏日過友人檀溪別業','李頻','唐','御定全唐诗','yuding','','[]','暑天宜野宅，林籟爽泠泠。沙月邀開戶，岩風助掃庭。',48,'御定全唐詩/json/588.json','["暑天宜野宅，林籟爽泠泠。沙月邀開戶，岩風助掃庭。", "鷺棲依綠筱，魚躍出清萍。客抱方如醉，因來得暫醒。"]'),
('yuding-63','自江上入關','李頻','唐','御定全唐诗','yuding','','[]','盡室寄滄洲，孤帆獨溯流。天涯心似夢，江上雨兼秋。',48,'御定全唐詩/json/588.json','["盡室寄滄洲，孤帆獨溯流。天涯心似夢，江上雨兼秋。", "文字為人棄，田園被債收。此名如不得，何處擬將休。"]'),
('yuding-64','冬夜和范秘書宿秘省中作','李頻','唐','御定全唐诗','yuding','','[]','每日得閒吟，清曹闕下深。因知遙夜坐，別有遠山心。',48,'御定全唐詩/json/588.json','["每日得閒吟，清曹闕下深。因知遙夜坐，別有遠山心。", "芸細書中氣，松疏雪後陰。歸時高興足，還複插朝簪。"]'),
('yuding-65','送友人游太原','李頻','唐','御定全唐诗','yuding','','[]','孤帆幾日懸，楚客思飄然。水宿南湖夜，山離舊國年。',48,'御定全唐詩/json/588.json','["孤帆幾日懸，楚客思飄然。水宿南湖夜，山離舊國年。", "秋風高送雁，寒雨入停蟬。此去勤書劄，時常中路傳。"]'),
('yuding-66','江上居寄山中客','李頻','唐','御定全唐诗','yuding','','[]','山后與山前，相思隔叫猿。殘雲收樹末，返照落江源。',48,'御定全唐詩/json/588.json','["山后與山前，相思隔叫猿。殘雲收樹末，返照落江源。", "苦雨秋濤漲，狂風野火翻。朝來賣藥客，遇我達無言。"]'),
('yuding-0','送張郎中赴睦州','李頻','唐','御定全唐诗','yuding','','[]','青山複淥水，想入富春西。夾岸清猿去，中流白日低。',48,'御定全唐詩/json/589.json','["青山複淥水，想入富春西。夾岸清猿去，中流白日低。", "美兼華省出，榮共故鄉齊。賤子遙攀送，歸心逐馬蹄。"]'),
('yuding-1','送鄂渚韋尚書赴鎮','李頻','唐','御定全唐诗','yuding','','[]','夏口本吳頭，重城據上游。戈船轉江漢，風月宿汀洲。',48,'御定全唐詩/json/589.json','["夏口本吳頭，重城據上游。戈船轉江漢，風月宿汀洲。", "執憲傾民望，銜恩赴主憂。誰知舊寮屬，攀餞淚仍流。"]'),
('yuding-2','送崔侍禦書記赴山北座主尚書招辟','李頻','唐','御定全唐诗','yuding','','[]','書記向丘門，旌幢夾穀尊。從來遊幕意，此去並酬恩。',48,'御定全唐詩/json/589.json','["書記向丘門，旌幢夾穀尊。從來遊幕意，此去並酬恩。", "雁叫嫌冰合，驄嘶喜雪繁。同為入室士，不覺別銷魂。"]'),
('yuding-3','入朝遇雪','李頻','唐','御定全唐诗','yuding','','[]','霜鬢持霜簡，朝天向雪天。玉階初辨色，瓊樹乍相鮮。',48,'御定全唐詩/json/589.json','["霜鬢持霜簡，朝天向雪天。玉階初辨色，瓊樹乍相鮮。", "密翳空難曙，盈征瑞不愆。誰為洛陽客，是日更高眠。"]'),
('yuding-4','勉力','李頻','唐','御定全唐诗','yuding','','[]','日月不並照，升沈俱有時。自媒徒欲速，孤立卻宜遲。',48,'御定全唐詩/json/589.json','["日月不並照，升沈俱有時。自媒徒欲速，孤立卻宜遲。", "盡力唯求己，公心任遇誰。人間不得意，半是鬢先衰。"]'),
('yuding-5','郊居寄友人','李頻','唐','御定全唐诗','yuding','','[]','林色樹還曛，何時得見君。獨居度永日，相去遠浮雲。',48,'御定全唐詩/json/589.json','["林色樹還曛，何時得見君。獨居度永日，相去遠浮雲。", "故疾隨秋至，離懷覺夜分。蛩聲非自苦，偏是旅人聞。"]'),
('yuding-6','送陸肱歸吳興','李頻','唐','御定全唐诗','yuding','','[]','雪後江上去，風光故國新。清渾天氣曉，綠動浪花春。',48,'御定全唐詩/json/589.json','["雪後江上去，風光故國新。清渾天氣曉，綠動浪花春。", "勸酒提壺鳥，乘舟震澤人。誰知滄海月，取桂卻來秦。"]'),
('yuding-7','暮秋重過山僧院','李頻','唐','御定全唐诗','yuding','','[]','卻接良宵坐，明河幾轉流。安禪逢小暑，抱疾入高秋。',48,'御定全唐詩/json/589.json','["卻接良宵坐，明河幾轉流。安禪逢小暑，抱疾入高秋。", "靜室聞玄理，深山可白頭。朝朝獻林果，亦欲學獼猴。"]'),
('yuding-8','送新安少府','李頻','唐','御定全唐诗','yuding','','[]','南浮雖六月，風水已秋涼。日亂看江樹，身飛逐楚檣。',48,'御定全唐詩/json/589.json','["南浮雖六月，風水已秋涼。日亂看江樹，身飛逐楚檣。", "後期誰可定，臨別語空長。遠宦須清苦，幽蘭貴獨芳。"]'),
('yuding-9','送人歸吳','李頻','唐','御定全唐诗','yuding','','[]','何人不歸去，君去是閒人。帝裏求相識，山家即近鄰。',48,'御定全唐詩/json/589.json','["何人不歸去，君去是閒人。帝裏求相識，山家即近鄰。", "交情吾道可，離思柳條新。未飲青門酒，先如醉夢身。"]'),
('yuding-10','送姚評事','李頻','唐','御定全唐诗','yuding','','[]','儒服從戎去，須知勝事全。使君開幕日，天子偃戈年。',48,'御定全唐詩/json/589.json','["儒服從戎去，須知勝事全。使君開幕日，天子偃戈年。", "風雨依嵩嶺，桑麻接楚田。新詩隨過客，旋滿洛陽傳。"]'),
('yuding-11','題棲雲寺立上人院','李頻','唐','御定全唐诗','yuding','','[]','是法從生有，修持曆劫塵。獨居岩下室，長似定中身。',48,'御定全唐詩/json/589.json','["是法從生有，修持曆劫塵。獨居岩下室，長似定中身。", "樹老風終夜，山寒雪見春。不知諸祖後，傳印是何人。"]'),
('yuding-12','黔中罷職過峽州題田使君北樓','李頻','唐','御定全唐诗','yuding','','[]','巴中初去日，已遇使君留。及得尋東道，還陪上北樓。',48,'御定全唐詩/json/589.json','["巴中初去日，已遇使君留。及得尋東道，還陪上北樓。", "江沖巫峽出，檣過洛宮收。好是從戎罷，看山覺自由。"]'),
('yuding-13','江上送從兄群玉校書東游','李頻','唐','御定全唐诗','yuding','','[]','逍遙蓬閣吏，才子複詩流。墳籍因窮覽，江湖卻縱遊。',48,'御定全唐詩/json/589.json','["逍遙蓬閣吏，才子複詩流。墳籍因窮覽，江湖卻縱遊。", "眠波聽戍鼓，飯浦約魚舟。處處迎高密，先應掃郡樓。"]'),
('yuding-14','宛陵東峰亭與友人話別','李頻','唐','御定全唐诗','yuding','','[]','坐舉天涯目，停杯語日晡。修篁齊迥檻，列岫限平蕪。',48,'御定全唐詩/json/589.json','["坐舉天涯目，停杯語日晡。修篁齊迥檻，列岫限平蕪。", "亂水通三楚，歸帆掛五湖。不知從此去，何處是前途。"]'),
('yuding-15','華山尋隱者','李頻','唐','御定全唐诗','yuding','','[]','自入華山居，關東相見疏。瓢中誰寄酒，葉上我留書。',48,'御定全唐詩/json/589.json','["自入華山居，關東相見疏。瓢中誰寄酒，葉上我留書。", "巢鳥寒棲盡，潭泉暮凍餘。長聞得藥力，此說又何如。"]'),
('yuding-16','題薦福寺僧棲白上人院','李頻','唐','御定全唐诗','yuding','','[]','空門有才子，得道亦吟詩。內殿頻征入，孤峰久作期。',48,'御定全唐詩/json/589.json','["空門有才子，得道亦吟詩。內殿頻征入，孤峰久作期。", "高名何代比，密行幾生持。長愛喬松院，清涼坐夏時。"]'),
('yuding-17','遊四明山劉樊二真人祠，題山下孫氏居','李頻','唐','御定全唐诗','yuding','','[]','久在仙壇下，全家是地仙。池塘來乳洞，禾黍接芝田。',48,'御定全唐詩/json/589.json','["久在仙壇下，全家是地仙。池塘來乳洞，禾黍接芝田。", "起看青山足，還傾白酒眠。不知塵世事，雙鬢逐流年。"]'),
('yuding-18','和太學趙鴻博士歸蔡中','李頻','唐','御定全唐诗','yuding','','[]','得祿從高第，還鄉見後生。田園休問主，詞賦已垂名。',48,'御定全唐詩/json/589.json','["得祿從高第，還鄉見後生。田園休問主，詞賦已垂名。", "掃壁前題出，開窗舊景清。遙知賢太守，致席日邀迎。"]'),
('yuding-19','送壽昌曹明府','李頻','唐','御定全唐诗','yuding','','[]','惠人須宰邑，為政貴通經。卻用清琴理，猶嫌薄俗聽。',48,'御定全唐詩/json/589.json','["惠人須宰邑，為政貴通經。卻用清琴理，猶嫌薄俗聽。", "漲江晴漸淥，春嶠燒還青。若宿嚴陵瀨，誰當是客星。"]'),
('yuding-20','哭賈島','李頻','唐','御定全唐诗','yuding','','[]','秦樓吟苦夜，南望只悲君。一宦終遐徼，千山隔旅墳。',48,'御定全唐詩/json/589.json','["秦樓吟苦夜，南望只悲君。一宦終遐徼，千山隔旅墳。", "恨聲流蜀魄，冤氣入湘雲。無限風騷句，時來日夜聞。"]'),
('yuding-21','送薛能赴鎮徐方','李頻','唐','御定全唐诗','yuding','','[]','列土人間盛，彭門屬九州。山河天設險，禮樂牧分憂。',48,'御定全唐詩/json/589.json','["列土人間盛，彭門屬九州。山河天設險，禮樂牧分憂。", "皎日為明信，清風占早秋。雖同郤縠舉，郤縠不封侯。"]'),
('yuding-22','送鳳翔范書記','李頻','唐','御定全唐诗','yuding','','[]','西京無暑氣，夏景似清秋。天府來相辟，高人去自由。',48,'御定全唐詩/json/589.json','["西京無暑氣，夏景似清秋。天府來相辟，高人去自由。", "江山通蜀國，日月近神州。若共將軍語，河蘭地未收。"]'),
('yuding-23','岐山逢陝下故人','李頻','唐','御定全唐诗','yuding','','[]','三秦一會面，二陝久分攜。共憶黃河北，相留白日西。',48,'御定全唐詩/json/589.json','["三秦一會面，二陝久分攜。共憶黃河北，相留白日西。", "寄來書少達，別後夢多迷。早晚期於此，看花聽鳥啼。"]'),
('yuding-24','送友人陸肱往太原','李頻','唐','御定全唐诗','yuding','','[]','並州非故國，君去複尋誰。獫狁方為寇，嫖姚正用師。',48,'御定全唐詩/json/589.json','["並州非故國，君去複尋誰。獫狁方為寇，嫖姚正用師。", "戍煙來自號，邊雪下無時。更想經綿上，應逢禁火期。"]'),
('yuding-25','贈李將軍','李頻','唐','御定全唐诗','yuding','','[]','吾宗偏好武，漢代將家流。走馬辭中禁，屯軍向渭州。',48,'御定全唐詩/json/589.json','["吾宗偏好武，漢代將家流。走馬辭中禁，屯軍向渭州。", "天心待破虜，陣面許封侯。卻得河源水，方應洗國仇。"]'),
('yuding-26','送友人喻坦之歸睦州','李頻','唐','御定全唐诗','yuding','','[]','歸心常共知，歸路不相隨。彼此無依倚，東西又別離。',48,'御定全唐詩/json/589.json','["歸心常共知，歸路不相隨。彼此無依倚，東西又別離。", "山花含雨濕，江樹近潮欹。莫戀漁樵興，生涯各有為。"]'),
('yuding-27','尋華陽隱者','李頻','唐','御定全唐诗','yuding','','[]','閑卻白雲居，行蹤出去初。窗中聊取筆，架上獨留書。',48,'御定全唐詩/json/589.json','["閑卻白雲居，行蹤出去初。窗中聊取筆，架上獨留書。", "日背林光冷，潭澄嶽影虛。長聞得藥力，此說複何如。"]'),
('yuding-28','長安即事','李頻','唐','御定全唐诗','yuding','','[]','豈得有書名，徒為老帝京。關中秋氣早，雨後夜涼生。',48,'御定全唐詩/json/589.json','["豈得有書名，徒為老帝京。關中秋氣早，雨後夜涼生。", "滄海身終泛，青門夢已行。秦人縱相識，多少別離情。"]'),
('yuding-29','送友人游塞北','李頻','唐','御定全唐诗','yuding','','[]','朔野正秋風，前程見磧鴻。日西身獨遠，山轉路無窮。',48,'御定全唐詩/json/589.json','["朔野正秋風，前程見磧鴻。日西身獨遠，山轉路無窮。", "樹隔高關斷，沙連大漠空。君看河外將，早晚擬平戎。"]'),
('yuding-30','陝府上姚中丞','李頻','唐','御定全唐诗','yuding','','[]','關東領藩鎮，闕下授旌旄。覓句秋吟苦，酬恩夜坐勞。',48,'御定全唐詩/json/589.json','["關東領藩鎮，闕下授旌旄。覓句秋吟苦，酬恩夜坐勞。", "天開吹角出，木落上樓高。閒話錢塘郡，半年聽海潮。"]'),
('yuding-31','送供奉喻煉師歸天目山','李頻','唐','御定全唐诗','yuding','','[]','承恩雖內殿，得道本深山。舉世相看老，孤峰獨自還。',48,'御定全唐詩/json/589.json','["承恩雖內殿，得道本深山。舉世相看老，孤峰獨自還。", "溪來青壁裏，路在白雲間。絕頂無人住，雙峰是舊關。"]'),
('yuding-32','之任建安淥溪亭偶作二首','李頻','唐','御定全唐诗','yuding','','[]','入境當春務，農蠶事正殷。逢溪難飲馬，度嶺更勞人。',96,'御定全唐詩/json/589.json','["入境當春務，農蠶事正殷。逢溪難飲馬，度嶺更勞人。", "想取烝黎泰，無過賦斂均。不知成政後，誰是得為鄰。", "維舟綠溪岸，繞郡白雲峰。將幕連山起，人家向水重。", "短才無獨見，長策未相逢。所幸分堯理，烝民悉可封。"]'),
('yuding-33','送侯郎中任新定二首','李頻','唐','御定全唐诗','yuding','','[]','為郎非白頭，作牧授滄洲。江界乘潮入，山川值勝遊。',96,'御定全唐詩/json/589.json','["為郎非白頭，作牧授滄洲。江界乘潮入，山川值勝遊。", "暑氣隨轉扇，涼月傍開樓。便欲歸田裏，拋官逐隱侯。", "罷郎東出守，半路得浮舟。大旆行當夏，桐江到未秋。", "雲閑分島寺，濤靜見沙鷗。誰伴臨清景，吟詩上郡樓。"]'),
('yuding-34','送太學吳康仁及第南歸','李頻','唐','御定全唐诗','yuding','','[]','因為太學選，志業徹春闈。首領諸生出，先登上第歸。',72,'御定全唐詩/json/589.json','["因為太學選，志業徹春闈。首領諸生出，先登上第歸。", "一榮猶未已，具慶且應稀。縱馬行青草，臨岐脫白衣。", "家遙楚國寄，帆對漢山飛。知己盈華省，看君再發機。"]'),
('yuding-35','陝州題河上亭','李頻','唐','御定全唐诗','yuding','','[]','岸擁洪流急，亭開清興長。當軒河草晚，入坐水風涼。',72,'御定全唐詩/json/589.json','["岸擁洪流急，亭開清興長。當軒河草晚，入坐水風涼。", "獨鳥驚來客，孤雲觸去檣。秋聲和遠雨，暮色帶微陽。", "浪靜澄窗影，沙明發簟光。逍遙每盡日，誰識愛滄浪。"]'),
('yuding-36','留題姚氏山齋','李頻','唐','御定全唐诗','yuding','','[]','未厭棲林趣，猶懷濟世才。閑眠知道在，高步會時來。',72,'御定全唐詩/json/589.json','["未厭棲林趣，猶懷濟世才。閑眠知道在，高步會時來。", "露滴從添硯，蟬吟便送杯。亂書離縹帙，迸筍出苔莓。", "異果因僧摘，幽窗為燕開。春遊何處盡，欲別幾遲回。"]');
